{
  "name": "Ponto Fácil AI",
  "description": "Sistema inteligente de controle de ponto com análise de produtividade via IA."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum RecordType {
  ENTRY = 'ENTRADA',
  LUNCH_START = 'IDA_ALMOCO',
  LUNCH_END = 'VOLTA_ALMOCO',
  EXIT = 'SAIDA'
}

export interface TimeRecord {
  id: string;
  date: string; // ISO Date YYYY-MM-DD
  startTime: string | null; // ISO Timestamp
  lunchStartTime: string | null;
  lunchEndTime: string | null;
  endTime: string | null;
  totalHours: number;
  status: 'ABERTO' | 'COMPLETO' | 'INCOMPLETO';
  notes?: string;
}

export interface DailyStats {
  date: string;
  hours: number;
}

import { GoogleGenAI } from "@google/genai";
import { TimeRecord } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeTimesheet = async (records: TimeRecord[]): Promise<string> => {
  if (!process.env.API_KEY) {
    return "API Key não configurada. Por favor, configure sua chave da API Gemini.";
  }

  // Filter last 7 days for relevant context
  const recentRecords = records.slice(0, 7);

  const dataContext = JSON.stringify(recentRecords.map(r => ({
    data: r.date,
    entrada: r.startTime ? new Date(r.startTime).toLocaleTimeString('pt-BR') : 'N/A',
    saida: r.endTime ? new Date(r.endTime).toLocaleTimeString('pt-BR') : 'N/A',
    almoco_ida: r.lunchStartTime ? new Date(r.lunchStartTime).toLocaleTimeString('pt-BR') : 'N/A',
    almoco_volta: r.lunchEndTime ? new Date(r.lunchEndTime).toLocaleTimeString('pt-BR') : 'N/A',
    total_horas: r.totalHours.toFixed(2),
    status: r.status
  })));

  const prompt = `
    Atue como um gerente de RH experiente e analítico.
    Analise os seguintes registros de ponto de um colaborador (formato JSON):
    ${dataContext}

    Forneça um feedback curto, encorajador e profissional em Português do Brasil.
    1. Mencione se o colaborador está cumprindo a jornada (considere 8 horas diárias como base).
    2. Aponte inconsistências (ex: esquecer de bater o ponto, intervalos curtos demais ou longos demais).
    3. Dê uma dica de produtividade ou bem-estar baseada nos horários (ex: horas extras excessivas).

    Não use markdown complexo, apenas texto corrido e parágrafos. Seja breve.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Não foi possível gerar a análise no momento.";
  } catch (error) {
    console.error("Erro ao chamar Gemini:", error);
    return "Erro ao conectar com a IA. Tente novamente mais tarde.";
  }
};

import React, { useState, useEffect } from 'react';
import { Play, Pause, Square, Coffee } from 'lucide-react';
import { RecordType, TimeRecord } from '../types';

interface TimeClockProps {
  currentRecord: TimeRecord | null;
  onPunch: (type: RecordType) => void;
}

export const TimeClock: React.FC<TimeClockProps> = ({ currentRecord, onPunch }) => {
  const [currentTime, setCurrentTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const getButtonConfig = () => {
    if (!currentRecord) {
      return {
        label: 'Iniciar Jornada',
        icon: <Play className="w-6 h-6 mr-2" />,
        action: () => onPunch(RecordType.ENTRY),
        color: 'bg-emerald-600 hover:bg-emerald-700',
        disabled: false
      };
    }

    if (currentRecord.startTime && !currentRecord.lunchStartTime) {
      return {
        label: 'Sair para Almoço',
        icon: <Coffee className="w-6 h-6 mr-2" />,
        action: () => onPunch(RecordType.LUNCH_START),
        color: 'bg-amber-500 hover:bg-amber-600',
        disabled: false
      };
    }

    if (currentRecord.lunchStartTime && !currentRecord.lunchEndTime) {
      return {
        label: 'Voltar do Almoço',
        icon: <Play className="w-6 h-6 mr-2" />,
        action: () => onPunch(RecordType.LUNCH_END),
        color: 'bg-emerald-600 hover:bg-emerald-700',
        disabled: false
      };
    }

    if (currentRecord.lunchEndTime && !currentRecord.endTime) {
      return {
        label: 'Encerrar Dia',
        icon: <Square className="w-6 h-6 mr-2" />,
        action: () => onPunch(RecordType.EXIT),
        color: 'bg-rose-600 hover:bg-rose-700',
        disabled: false
      };
    }

    return {
      label: 'Jornada Concluída',
      icon: <Square className="w-6 h-6 mr-2" />,
      action: () => {},
      color: 'bg-slate-400 cursor-not-allowed',
      disabled: true
    };
  };

  const btn = getButtonConfig();

  return (
    <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100 flex flex-col items-center justify-center space-y-6">
      <div className="text-center">
        <h2 className="text-slate-500 font-medium text-lg uppercase tracking-wider mb-1">Hora Atual</h2>
        <div className="text-5xl font-bold text-indigo-900 tabular-nums">
          {currentTime.toLocaleTimeString('pt-BR')}
        </div>
        <p className="text-indigo-600 font-medium mt-2">
          {currentTime.toLocaleDateString('pt-BR', { weekday: 'long', day: 'numeric', month: 'long' })}
        </p>
      </div>

      <button
        onClick={btn.action}
        disabled={btn.disabled}
        className={`${btn.color} text-white font-bold py-4 px-8 rounded-full shadow-lg transform transition-all active:scale-95 flex items-center justify-center min-w-[240px]`}
      >
        {btn.icon}
        {btn.label}
      </button>

      <div className="grid grid-cols-2 gap-4 w-full mt-4 text-sm text-slate-600">
        <div className="bg-slate-50 p-3 rounded-lg text-center border border-slate-200">
          <span className="block text-xs font-bold text-slate-400 uppercase">Entrada</span>
          <span className="font-mono text-lg text-slate-900">
            {currentRecord?.startTime ? new Date(currentRecord.startTime).toLocaleTimeString('pt-BR', {hour: '2-digit', minute:'2-digit'}) : '--:--'}
          </span>
        </div>
        <div className="bg-slate-50 p-3 rounded-lg text-center border border-slate-200">
          <span className="block text-xs font-bold text-slate-400 uppercase">Saída</span>
          <span className="font-mono text-lg text-slate-900">
            {currentRecord?.endTime ? new Date(currentRecord.endTime).toLocaleTimeString('pt-BR', {hour: '2-digit', minute:'2-digit'}) : '--:--'}
          </span>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { TimeRecord } from '../types';
import { CheckCircle, AlertCircle, Clock } from 'lucide-react';

interface TimeHistoryProps {
  records: TimeRecord[];
}

export const TimeHistory: React.FC<TimeHistoryProps> = ({ records }) => {
  const formatTime = (isoString: string | null) => {
    if (!isoString) return '-';
    return new Date(isoString).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
  };

  const formatDate = (isoDate: string) => {
    const [year, month, day] = isoDate.split('-');
    return `${day}/${month}/${year}`;
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="p-6 border-b border-slate-100 flex justify-between items-center">
        <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
          <Clock className="w-5 h-5 text-indigo-600" />
          Histórico Recente
        </h3>
      </div>
      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-slate-50 text-slate-500 uppercase text-xs font-semibold">
            <tr>
              <th className="px-6 py-4">Data</th>
              <th className="px-6 py-4 text-center">Entrada</th>
              <th className="px-6 py-4 text-center">Almoço (Ida)</th>
              <th className="px-6 py-4 text-center">Almoço (Volta)</th>
              <th className="px-6 py-4 text-center">Saída</th>
              <th className="px-6 py-4 text-center">Total</th>
              <th className="px-6 py-4 text-center">Status</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {records.length === 0 ? (
              <tr>
                <td colSpan={7} className="px-6 py-8 text-center text-slate-500">
                  Nenhum registro encontrado.
                </td>
              </tr>
            ) : (
              records.map((record) => (
                <tr key={record.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 font-medium text-slate-900">
                    {formatDate(record.date)}
                  </td>
                  <td className="px-6 py-4 text-center text-slate-700">{formatTime(record.startTime)}</td>
                  <td className="px-6 py-4 text-center text-slate-600 text-sm">{formatTime(record.lunchStartTime)}</td>
                  <td className="px-6 py-4 text-center text-slate-600 text-sm">{formatTime(record.lunchEndTime)}</td>
                  <td className="px-6 py-4 text-center text-slate-700">{formatTime(record.endTime)}</td>
                  <td className="px-6 py-4 text-center font-bold text-indigo-700">
                    {record.totalHours > 0 ? `${record.totalHours.toFixed(2)}h` : '-'}
                  </td>
                  <td className="px-6 py-4 text-center">
                    {record.status === 'COMPLETO' ? (
                      <span className="inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
                        <CheckCircle className="w-3 h-3" /> Completo
                      </span>
                    ) : record.status === 'INCOMPLETO' ? (
                       <span className="inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-medium bg-red-100 text-red-800">
                        <AlertCircle className="w-3 h-3" /> Incompleto
                      </span>
                    ) : (
                       <span className="inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
                        <Clock className="w-3 h-3" /> Em andamento
                      </span>
                    )}
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React from 'react';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  ReferenceLine
} from 'recharts';
import { TimeRecord } from '../types';

interface DashboardProps {
  records: TimeRecord[];
}

export const Dashboard: React.FC<DashboardProps> = ({ records }) => {
  // Process records for chart
  const data = records
    .slice(0, 7)
    .reverse() // Show chronological order
    .map(record => ({
      name: new Date(record.date).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
      horas: Number(record.totalHours.toFixed(2)),
      meta: 8
    }));

  return (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
      <div className="mb-6">
        <h3 className="text-lg font-bold text-slate-800">Desempenho Semanal</h3>
        <p className="text-sm text-slate-500">Horas trabalhadas nos últimos 7 dias</p>
      </div>

      <div className="h-[300px] w-full">
        <ResponsiveContainer width="100%" height="100%">
          <BarChart
            data={data}
            margin={{
              top: 5,
              right: 30,
              left: 0,
              bottom: 5,
            }}
          >
            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
            <XAxis 
              dataKey="name" 
              tick={{fill: '#64748b', fontSize: 12}} 
              axisLine={false}
              tickLine={false}
              dy={10}
            />
            <YAxis 
              tick={{fill: '#64748b', fontSize: 12}} 
              axisLine={false}
              tickLine={false}
            />
            <Tooltip 
              cursor={{fill: '#f1f5f9'}}
              contentStyle={{
                backgroundColor: '#ffffff',
                border: '1px solid #e2e8f0',
                borderRadius: '8px',
                boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'
              }}
            />
            <ReferenceLine y={8} stroke="#f59e0b" strokeDasharray="3 3" label={{ position: 'right',  value: 'Meta 8h', fill: '#f59e0b', fontSize: 10 }} />
            <Bar dataKey="horas" fill="#4f46e5" radius={[4, 4, 0, 0]} barSize={40} />
          </BarChart>
