    <svg 
        xmlns="http://www.w3.org/2000/svg" 
        width="24" 
        height="24" 
        viewBox="0 0 24 24" 
        fill="none" 
        stroke="currentColor" 
        strokeWidth="2" 
        strokeLinecap="round" 
        strokeLinejoin="round" 
        className="w-5 h-5"
    >
        <circle cx="12" cy="12" r="10"/>
        <polyline points="12 6 12 12 16 14"/>
    </svg>
);

const StatCard = ({ title, value, color }: { title: string, value: string, color: string }) => (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <p className="text-sm font-medium text-slate-500 uppercase tracking-wide">{title}</p>
        <div className="mt-2 flex items-baseline gap-2">
            <span className="text-3xl font-bold text-slate-900">{value}</span>
            <div className={`w-2 h-2 rounded-full ${color}`}></div>
        </div>
    </div>
);

export default App;

export enum RecordType {
  ENTRY = 'ENTRADA',
  LUNCH_START = 'IDA_ALMOCO',
  LUNCH_END = 'VOLTA_ALMOCO',
  EXIT = 'SAIDA'
}

export interface TimeRecord {
  id: string;
  date: string; // ISO Date YYYY-MM-DD
  startTime: string | null; // ISO Timestamp
  lunchStartTime: string | null;
  lunchEndTime: string | null;
  endTime: string | null;
  totalHours: number;
  overtimeHours: number; // Horas extras calculadas
  balanceHours: number; // Saldo (Total - 8h)
  isOvertimeApproved: boolean | null; // null = pendente, true = aprovado, false = rejeitado
  status: 'ABERTO' | 'COMPLETO' | 'INCOMPLETO';
  notes?: string;
}

export interface DailyStats {
  date: string;
  hours: number;
}

import React, { useState, useEffect } from 'react';
import { TimeClock } from './components/TimeClock';
import { TimeHistory } from './components/TimeHistory';
import { Dashboard } from './components/Dashboard';
import { TimeRecord, RecordType } from './types';
import { analyzeTimesheet } from './services/geminiService';
import { Sparkles, CalendarDays, BarChart3, User, LogOut, Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [records, setRecords] = useState<TimeRecord[]>([]);
  const [activeTab, setActiveTab] = useState<'ponto' | 'historico' | 'dashboard'>('ponto');
  const [loadingAI, setLoadingAI] = useState(false);
  const [aiInsight, setAiInsight] = useState<string | null>(null);

  // Load data from localStorage on mount
  useEffect(() => {
    const savedRecords = localStorage.getItem('timeRecords');
    if (savedRecords) {
      setRecords(JSON.parse(savedRecords));
    }
  }, []);

  // Save records whenever they change
  useEffect(() => {
    localStorage.setItem('timeRecords', JSON.stringify(records));
  }, [records]);

  // Get current day's record
  const todayStr = new Date().toISOString().split('T')[0];
  const currentRecord = records.find(r => r.date === todayStr) || null;

  const handlePunch = (type: RecordType) => {
    const now = new Date().toISOString();
    let updatedRecords = [...records];
    let record = updatedRecords.find(r => r.date === todayStr);

    if (!record) {
      // Create new record for today
      record = {
        id: crypto.randomUUID(),
        date: todayStr,
        startTime: null,
        lunchStartTime: null,
        lunchEndTime: null,
        endTime: null,
        totalHours: 0,
        overtimeHours: 0,
        balanceHours: 0,
        isOvertimeApproved: null,
        status: 'ABERTO',
        notes: ''
      };
      updatedRecords = [record, ...updatedRecords];
    }

    switch (type) {
      case RecordType.ENTRY:
        record.startTime = now;
        record.status = 'ABERTO';
        break;
      case RecordType.LUNCH_START:
        record.lunchStartTime = now;
        break;
      case RecordType.LUNCH_END:
        record.lunchEndTime = now;
        break;
      case RecordType.EXIT:
        record.endTime = now;
        record.status = 'COMPLETO';
        // Calculate total hours
        if (record.startTime && record.endTime) {
            const start = new Date(record.startTime).getTime();
            const end = new Date(record.endTime).getTime();
            let totalMs = end - start;

            if (record.lunchStartTime && record.lunchEndTime) {
                const lunchStart = new Date(record.lunchStartTime).getTime();
                const lunchEnd = new Date(record.lunchEndTime).getTime();
                const lunchDuration = lunchEnd - lunchStart;
                totalMs -= lunchDuration;
            }

            const totalHours = totalMs / (1000 * 60 * 60);
            record.totalHours = totalHours;

            // Standard workday is 8 hours
            const TARGET_HOURS = 8;
            record.balanceHours = totalHours - TARGET_HOURS;
            record.overtimeHours = Math.max(0, record.balanceHours);
        }
        break;
    }

    setRecords(updatedRecords);
  };

  const handleUpdateNote = (id: string, note: string) => {
    const updatedRecords = records.map(r => 
      r.id === id ? { ...r, notes: note } : r
    );
    setRecords(updatedRecords);
  };

  const handleToggleApproval = (id: string) => {
    const updatedRecords = records.map(r => {
      if (r.id === id) {
        // Toggle: null (pending) -> true (approved) -> false (rejected) -> null
        let newStatus: boolean | null = null;
        if (r.isOvertimeApproved === null) newStatus = true;
        else if (r.isOvertimeApproved === true) newStatus = false;
        else newStatus = null;

        return { ...r, isOvertimeApproved: newStatus };
      }
      return r;
    });
    setRecords(updatedRecords);
  };

  const handleAnalyzeAI = async () => {
    setLoadingAI(true);
    setAiInsight(null);
    const feedback = await analyzeTimesheet(records);
    setAiInsight(feedback);
    setLoadingAI(false);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Sidebar Navigation */}
      <aside className="w-full md:w-64 bg-indigo-900 text-white flex-shrink-0 md:h-screen sticky top-0 md:fixed z-10 shadow-xl">
        <div className="p-6 flex items-center gap-3 border-b border-indigo-800">
            <div className="bg-white p-1.5 rounded-lg">
                <CalendarDays className="w-6 h-6 text-indigo-900" />
            </div>
          <h1 className="text-xl font-bold tracking-tight">Ponto Fácil</h1>
        </div>

        <nav className="p-4 space-y-2">
          <button
            onClick={() => setActiveTab('ponto')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${
              activeTab === 'ponto' 
                ? 'bg-indigo-700 text-white shadow-md font-semibold' 
                : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'
            }`}
          >
            <ClockIcon isActive={activeTab === 'ponto'} />
            Bater Ponto
          </button>

          <button
            onClick={() => setActiveTab('historico')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${
              activeTab === 'historico' 
                ? 'bg-indigo-700 text-white shadow-md font-semibold' 
                : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'
            }`}
          >
            <CalendarDays className="w-5 h-5" />
            Folha de Ponto
          </button>

           <button
            onClick={() => setActiveTab('dashboard')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${
              activeTab === 'dashboard' 
                ? 'bg-indigo-700 text-white shadow-md font-semibold' 
                : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'
            }`}
          >
            <BarChart3 className="w-5 h-5" />
            Relatórios
          </button>
        </nav>

        <div className="absolute bottom-0 w-full p-6 border-t border-indigo-800">
            <div className="flex items-center gap-3 mb-4">
                <div className="w-10 h-10 rounded-full bg-indigo-500 flex items-center justify-center text-white font-bold">
                    JS
                </div>
                <div>
                    <p className="text-sm font-medium text-white">João Silva</p>
                    <p className="text-xs text-indigo-300">Desenvolvedor</p>
                </div>
            </div>
            <button className="w-full flex items-center justify-center gap-2 text-sm text-indigo-300 hover:text-white transition-colors">
                <LogOut className="w-4 h-4" /> Sair do Sistema
            </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 md:ml-64 p-4 md:p-8 overflow-y-auto">
        <header className="flex justify-between items-center mb-8">
            <div>
                <h2 className="text-2xl font-bold text-slate-900">
                    {activeTab === 'ponto' && 'Registro de Ponto'}
                    {activeTab === 'historico' && 'Folha de Ponto Mensal'}
                    {activeTab === 'dashboard' && 'Painel de Indicadores'}
                </h2>
                <p className="text-slate-500 mt-1">
                    {new Date().toLocaleDateString('pt-BR', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}
                </p>
            </div>

            <button 
                onClick={handleAnalyzeAI}
                disabled={loadingAI || records.length === 0}
                className="hidden md:flex items-center gap-2 bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-700 hover:to-indigo-700 text-white px-5 py-2.5 rounded-full shadow-md transition-all active:scale-95 disabled:opacity-70 disabled:cursor-not-allowed"
            >
                {loadingAI ? <Loader2 className="w-5 h-5 animate-spin" /> : <Sparkles className="w-5 h-5" />}
                {loadingAI ? 'Analisando...' : 'Análise com IA'}
            </button>
        </header>

        {/* AI Insight Box */}
        {aiInsight && (
            <div className="mb-8 bg-gradient-to-br from-indigo-50 to-purple-50 border border-indigo-100 p-6 rounded-2xl shadow-sm relative animate-fadeIn">
                <button 
                    onClick={() => setAiInsight(null)}
                    className="absolute top-4 right-4 text-slate-400 hover:text-slate-600"
                >
                    ✕
                </button>
                <div className="flex items-start gap-4">
                    <div className="bg-white p-2 rounded-lg shadow-sm">
                        <Sparkles className="w-6 h-6 text-purple-600" />
                    </div>
                    <div>
                        <h4 className="font-bold text-indigo-900 mb-2">Insight do Gemini AI</h4>
                        <p className="text-slate-700 leading-relaxed text-sm whitespace-pre-line">{aiInsight}</p>
                    </div>
                </div>
            </div>
        )}

        <div className="max-w-6xl mx-auto space-y-6">
            {activeTab === 'ponto' && (
                <>
                    <TimeClock currentRecord={currentRecord} onPunch={handlePunch} />

                    {/* Compact recent history for 'ponto' tab */}
                    <div className="mt-8">
                        <h3 className="text-lg font-semibold text-slate-800 mb-4">Últimos Registros</h3>
                        <TimeHistory 
                          records={records.slice(0, 3)} 
                          onUpdateNote={handleUpdateNote}
                          onToggleApproval={handleToggleApproval}
                          compact
                        />
                    </div>
                </>
            )}

            {activeTab === 'historico' && (
                <TimeHistory 
                  records={records} 
                  onUpdateNote={handleUpdateNote}
                  onToggleApproval={handleToggleApproval}
                />
            )}

            {activeTab === 'dashboard' && (
                <div className="grid grid-cols-1 gap-6">
                    <Dashboard records={records} />
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                         <StatCard 
                            title="Total Horas (Geral)" 
                            value={`${records.reduce((acc, curr) => acc + curr.totalHours, 0).toFixed(1)}h`} 
                            color="bg-blue-500"
                         />
                          <StatCard 
                            title="Total Horas Extras" 
                            value={`${records.reduce((acc, curr) => acc + (curr.overtimeHours || 0), 0).toFixed(1)}h`} 
                            color="bg-emerald-500"
                         />
                         <StatCard 
                            title="Saldo de Horas" 
                            value={`${records.reduce((acc, curr) => acc + (curr.balanceHours || 0), 0).toFixed(1)}h`} 
                            color="bg-purple-500"
