  if (totalBalance >= 0) doc.setTextColor(29, 78, 216); // Blue
  else doc.setTextColor(185, 28, 28); // Red
  doc.text(`${totalBalance > 0 ? '+' : ''}${totalBalance.toFixed(2)}h`, 150, 53);

  // Table
  const tableColumn = ["Data", "Entrada", "Saída", "Total", "Extras", "Saldo", "Obs"];
  const tableRows = records.map(r => [
    formatDate(r.date),
    formatTime(r.startTime),
    formatTime(r.endTime),
    `${r.totalHours.toFixed(2)}h`,
    r.overtimeHours > 0 ? `+${r.overtimeHours.toFixed(2)}h` : '-',
    `${r.balanceHours > 0 ? '+' : ''}${r.balanceHours.toFixed(2)}h`,
    r.notes || ''
  ]);

  autoTable(doc, {
    head: [tableColumn],
    body: tableRows,
    startY: 70,
    theme: 'grid',
    headStyles: { fillColor: [79, 70, 229] }, // Indigo 600
    styles: { fontSize: 9, cellPadding: 3 },
    columnStyles: {
      0: { cellWidth: 25 },
      6: { cellWidth: 'auto' } // Auto width for notes
    }
  });

  doc.save(`folha_ponto_${new Date().toISOString().split('T')[0]}.pdf`);
};

