            onClick={onClose}
            className="text-indigo-200 hover:text-white transition-colors p-1 rounded-full hover:bg-indigo-800"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Nome Completo</label>
            <div className="relative">
              <User className="absolute top-2.5 left-3 w-5 h-5 text-slate-400 pointer-events-none" />
              <input
                type="text"
                required
                placeholder="Ex: Maria Oliveira"
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full pl-10 pr-3 py-2 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-slate-900"
              />
