export enum RecordType {
  ENTRY = 'ENTRADA',
  LUNCH_START = 'IDA_ALMOCO',
  LUNCH_END = 'VOLTA_ALMOCO',
  EXIT = 'SAIDA'
}

export interface WorkSchedule {
  startTime: string; // "09:00"
  endTime: string;   // "18:00"
  lunchDuration: number; // minutes, e.g., 60
}

export interface Employee {
  id: string;
  name: string;
  role: string;
  avatarInitials: string;
  workSchedule?: WorkSchedule; // Optional for backward compatibility
}

export interface TimeRecord {
  id: string;
  employeeId: string; // Link record to specific employee
  date: string; // ISO Date YYYY-MM-DD
  startTime: string | null; // ISO Timestamp
  lunchStartTime: string | null;
  lunchEndTime: string | null;
  endTime: string | null;
  totalHours: number;
  overtimeHours: number; // Horas extras calculadas
  balanceHours: number; // Saldo (Total - Meta)
  isOvertimeApproved: boolean | null; // null = pendente, true = aprovado, false = rejeitado
  status: 'ABERTO' | 'COMPLETO' | 'INCOMPLETO';
  notes?: string;
}

export interface DailyStats {
  date: string;
  hours: number;
}

