  const [name, setName] = useState('');
  const [role, setRole] = useState('');

  // Schedule State
  const [startTime, setStartTime] = useState('09:00');
  const [endTime, setEndTime] = useState('18:00');
  const [lunchDuration, setLunchDuration] = useState('60');

  useEffect(() => {
    if (isOpen) {
      if (initialData) {
        setName(initialData.name);
        setRole(initialData.role);
        if (initialData.workSchedule) {
          setStartTime(initialData.workSchedule.startTime);
          setEndTime(initialData.workSchedule.endTime);
          setLunchDuration(initialData.workSchedule.lunchDuration.toString());
        } else {
            // Default values if editing legacy user
            setStartTime('09:00');
            setEndTime('18:00');
            setLunchDuration('60');
        }
      } else {
        // Defaults for new user
        setName('');
        setRole('');
        setStartTime('09:00');
        setEndTime('18:00');
