import React, { useState, useEffect, useMemo, useRef } from 'react';
import { TimeClock } from './components/TimeClock';
import { TimeHistory } from './components/TimeHistory';
import { Dashboard } from './components/Dashboard';
import { OvertimeModal } from './components/OvertimeModal';
import { EmployeeModal } from './components/EmployeeModal';
import { Logo } from './components/Logo';
import { TimeRecord, RecordType, Employee, WorkSchedule } from './types';
import { analyzeTimesheet } from './services/geminiService';
import { exportToCSV, exportToPDF } from './services/exportService';
import { requestNotificationPermission, sendNotification } from './services/notificationService';
import { Sparkles, CalendarDays, BarChart3, LogOut, Loader2, FileSpreadsheet, FileText, PlusCircle, Users, ChevronDown, Check, Pencil, Trash2, Download, Upload, Database, Filter, XCircle, Bell, Menu, X, Clock } from 'lucide-react';

const App: React.FC = () => {
  const [records, setRecords] = useState<TimeRecord[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [currentEmployeeId, setCurrentEmployeeId] = useState<string>('');

  const [activeTab, setActiveTab] = useState<'ponto' | 'historico' | 'dashboard'>('ponto');
  const [loadingAI, setLoadingAI] = useState(false);
  const [aiInsight, setAiInsight] = useState<string | null>(null);

  // Date Filter State
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  const [isOvertimeModalOpen, setIsOvertimeModalOpen] = useState(false);
  const [isEmployeeModalOpen, setIsEmployeeModalOpen] = useState(false);
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false); // Mobile Sidebar State

  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Notification References to avoid stale closures in setInterval
  const currentRecordRef = useRef<TimeRecord | null>(null);
  const lastNotificationTimeRef = useRef<string | null>(null);

  // Initialization Logic (Migration and Defaults)
  useEffect(() => {
    const savedRecords = localStorage.getItem('timeRecords');
    const savedEmployees = localStorage.getItem('employees');

    let parsedEmployees: Employee[] = [];
    let parsedRecords: TimeRecord[] = [];

    // 1. Load or Initialize Employees
    if (savedEmployees) {
      parsedEmployees = JSON.parse(savedEmployees);
    } else {
      // Default initial employee with default schedule
      const defaultEmployee: Employee = {
        id: 'user-1',
        name: 'João Silva',
        role: 'Desenvolvedor',
        avatarInitials: 'JS',
        workSchedule: {
            startTime: '09:00',
            endTime: '18:00',
            lunchDuration: 60
        }
      };
      parsedEmployees = [defaultEmployee];
      localStorage.setItem('employees', JSON.stringify(parsedEmployees));
    }
    setEmployees(parsedEmployees);

    // Ensure valid currentEmployeeId
    if (parsedEmployees.length > 0) {
        setCurrentEmployeeId(parsedEmployees[0].id);
    }

    // 2. Load and Migrate Records
    if (savedRecords) {
      parsedRecords = JSON.parse(savedRecords);
      // Migration: If record has no employeeId, assign to first employee
      const hasMigration = parsedRecords.some(r => !r.employeeId);
      if (hasMigration && parsedEmployees.length > 0) {
        parsedRecords = parsedRecords.map(r => ({
          ...r,
          employeeId: r.employeeId || parsedEmployees[0].id
        }));
        localStorage.setItem('timeRecords', JSON.stringify(parsedRecords));
      }
    }
    setRecords(parsedRecords);

    // 3. Set Default Date Filter (Current Month)
    const now = new Date();
    const firstDay = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
    const lastDay = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().split('T')[0];
    setStartDate(firstDay);
    setEndDate(lastDay);

    // 4. Request Notification Permission on load
    requestNotificationPermission();

  }, []);

  // Persistence Effects
  useEffect(() => {
    if (records.length > 0) {
      localStorage.setItem('timeRecords', JSON.stringify(records));
    }
  }, [records]);

  useEffect(() => {
    if (employees.length > 0) {
      localStorage.setItem('employees', JSON.stringify(employees));
    }
  }, [employees]);

  // Derived State
  const currentEmployee = employees.find(e => e.id === currentEmployeeId) || employees[0];

  const currentUserRecords = useMemo(() => {
    return records.filter(r => r.employeeId === currentEmployeeId);
  }, [records, currentEmployeeId]);

  const filteredRecords = useMemo(() => {
    return currentUserRecords.filter(r => {
      if (!startDate && !endDate) return true;
      if (startDate && r.date < startDate) return false;
      if (endDate && r.date > endDate) return false;
      return true;
    });
  }, [currentUserRecords, startDate, endDate]);

  const todayStr = new Date().toISOString().split('T')[0];
  const currentDayRecord = currentUserRecords.find(r => r.date === todayStr) || null;

  // Update Ref for Scheduler
  useEffect(() => {
    currentRecordRef.current = currentDayRecord;
  }, [currentDayRecord]);

  // Helper: Calculate Expected Hours for Current Employee
  const calculateExpectedHours = (employee: Employee): number => {
    if (!employee.workSchedule) return 8; // Default fallback

    const { startTime, endTime, lunchDuration } = employee.workSchedule;

    const [startH, startM] = startTime.split(':').map(Number);
    const [endH, endM] = endTime.split(':').map(Number);

    const startMinutes = startH * 60 + startM;
    const endMinutes = endH * 60 + endM;

    let totalWorkMinutes = endMinutes - startMinutes;
    // Handle overnight shifts if needed (simple version assumes same day)
    if (totalWorkMinutes < 0) totalWorkMinutes += 24 * 60;

    // Subtract lunch
    totalWorkMinutes -= lunchDuration;

    return totalWorkMinutes / 60;
  };

  // Notification Scheduler
  useEffect(() => {
    const checkReminders = () => {
      const now = new Date();
      const timeString = now.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });

      // Prevent double firing in the same minute
      if (lastNotificationTimeRef.current === timeString) return;

      const record = currentRecordRef.current;

      // Use current employee schedule or defaults
      const schedule = currentEmployee?.workSchedule || {
        startTime: '09:00',
        endTime: '18:00',
        lunchDuration: 60
      };

      // Calculate approximate lunch start (e.g., 4h after start) - Simplified logic
      // In a real app, this might be configurable too
      const [startH] = schedule.startTime.split(':').map(Number);
      const lunchStartH = (startH + 4) % 24;
      const LUNCH_START_GUESS = `${lunchStartH.toString().padStart(2, '0')}:00`;

      // Calculate lunch end guess (1h after lunch start)
      const lunchEndH = (lunchStartH + 1) % 24;
      const LUNCH_END_GUESS = `${lunchEndH.toString().padStart(2, '0')}:00`;

      let shouldNotify = false;
      let title = '';
      let body = '';

      if (timeString === schedule.startTime) {
        if (!record || !record.startTime) {
          shouldNotify = true;
          title = 'Hora de Entrar! ☀️';
          body = `Bom dia! Seu horário é ${schedule.startTime}.`;
        }
      } else if (timeString === LUNCH_START_GUESS) {
        if (record && record.startTime && !record.lunchStartTime) {
          shouldNotify = true;
          title = 'Hora do Almoço! 🍽️';
          body = 'Bom apetite! Registre sua saída para o intervalo.';
        }
      } else if (timeString === LUNCH_END_GUESS) {
        if (record && record.lunchStartTime && !record.lunchEndTime) {
          shouldNotify = true;
          title = 'Fim do Intervalo 🕐';
          body = 'Hora de voltar. Registre sua volta do almoço.';
        }
      } else if (timeString === schedule.endTime) {
        if (record && record.lunchEndTime && !record.endTime) {
          shouldNotify = true;
          title = 'Fim do Expediente! 🎉';
          body = `Seu horário (${schedule.endTime}) chegou. Registre sua saída.`;
        }
      }

      if (shouldNotify) {
        sendNotification(title, body);
        lastNotificationTimeRef.current = timeString;
      }
    };

    const interval = setInterval(checkReminders, 30000); // Check every 30s
    return () => clearInterval(interval);
  }, [currentEmployee]); // Re-run effect if current employee changes (for schedule update)

  // Handlers
  const handleEnableNotifications = async () => {
    const granted = await requestNotificationPermission();
    if (granted) {
      sendNotification("Notificações Ativadas", "Você receberá lembretes de ponto.");
    } else {
      alert("É necessário permitir notificações no navegador.");
    }
  };

  const handleSetCurrentMonth = () => {
    const now = new Date();
    const firstDay = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
    const lastDay = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().split('T')[0];
    setStartDate(firstDay);
    setEndDate(lastDay);
  };

  const handleClearFilter = () => {
    setStartDate('');
    setEndDate('');
  };

  const handleSaveEmployee = (name: string, role: string, schedule: WorkSchedule) => {
    const initials = name.split(' ').map(n => n[0]).join('').substring(0, 2).toUpperCase();

    if (editingEmployee) {
      // Edit mode
      const updatedEmployees = employees.map(emp => 
        emp.id === editingEmployee.id 
          ? { ...emp, name, role, avatarInitials: initials, workSchedule: schedule }
          : emp
      );
      setEmployees(updatedEmployees);
      setEditingEmployee(null);
    } else {
      // Create mode
      const newEmployee: Employee = {
        id: crypto.randomUUID(),
        name,
        role,
        avatarInitials: initials,
        workSchedule: schedule
      };
      const updatedEmployees = [...employees, newEmployee];
      setEmployees(updatedEmployees);
      setCurrentEmployeeId(newEmployee.id);
      setAiInsight(null);
    }
    setIsEmployeeModalOpen(false);
  };

  const handleEditEmployee = (e: React.MouseEvent, emp: Employee) => {
    e.stopPropagation();
    setEditingEmployee(emp);
    setIsEmployeeModalOpen(true);
    setIsUserMenuOpen(false);
  };

  const handleDeleteEmployee = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (employees.length <= 1) {
      alert("Você não pode excluir o último colaborador.");
      return;
    }

    if (window.confirm("Tem certeza? Todos os registros de ponto deste colaborador serão excluídos permanentemente.")) {
      const updatedEmployees = employees.filter(emp => emp.id !== id);
      setEmployees(updatedEmployees);

      // Remove associated records
      const updatedRecords = records.filter(r => r.employeeId !== id);
      setRecords(updatedRecords);
      localStorage.setItem('timeRecords', JSON.stringify(updatedRecords));

      // If deleted user was active, switch to first available
      if (currentEmployeeId === id) {
        setCurrentEmployeeId(updatedEmployees[0].id);
        setAiInsight(null);
      }
    }
  };

  const handlePunch = (type: RecordType) => {
    if (!currentEmployeeId) return;

    const now = new Date().toISOString();
    let updatedRecords = [...records];

    // Find existing record within the FULL list (not filtered) to update it properly
    let recordIndex = updatedRecords.findIndex(r => r.employeeId === currentEmployeeId && r.date === todayStr);
    let record = recordIndex >= 0 ? updatedRecords[recordIndex] : null;

    if (!record) {
      record = {
        id: crypto.randomUUID(),
        employeeId: currentEmployeeId,
        date: todayStr,
        startTime: null,
        lunchStartTime: null,
        lunchEndTime: null,
        endTime: null,
        totalHours: 0,
        overtimeHours: 0,
        balanceHours: 0,
        isOvertimeApproved: null,
        status: 'ABERTO',
        notes: ''
      };
      // Push new record
      updatedRecords.unshift(record);
      recordIndex = 0; // New record is at top
    } else {
      // We are editing a record, create a copy
      record = { ...record };
      updatedRecords[recordIndex] = record;
    }

    switch (type) {
      case RecordType.ENTRY:
        record.startTime = now;
        record.status = 'ABERTO';
        break;
      case RecordType.LUNCH_START:
        record.lunchStartTime = now;
        break;
      case RecordType.LUNCH_END:
        record.lunchEndTime = now;
        break;
      case RecordType.EXIT:
        record.endTime = now;
        record.status = 'COMPLETO';
        // Calculate total hours
        if (record.startTime && record.endTime) {
            const start = new Date(record.startTime).getTime();
            const end = new Date(record.endTime).getTime();
            let totalMs = end - start;

            if (record.lunchStartTime && record.lunchEndTime) {
                const lunchStart = new Date(record.lunchStartTime).getTime();
                const lunchEnd = new Date(record.lunchEndTime).getTime();
                const lunchDuration = lunchEnd - lunchStart;
                totalMs -= lunchDuration;
            }

            const totalHours = totalMs / (1000 * 60 * 60);
            record.totalHours = totalHours;

            // Calculate Target based on Employee Schedule
            const targetHours = calculateExpectedHours(currentEmployee);

            record.balanceHours = totalHours - targetHours;
            // Overtime is specifically the positive balance
            record.overtimeHours = Math.max(0, record.balanceHours);
        }
        break;
    }

    setRecords(updatedRecords);
  };

  const handleUpdateNote = (id: string, note: string) => {
    const updatedRecords = records.map(r => 
      r.id === id ? { ...r, notes: note } : r
    );
    setRecords(updatedRecords);
  };

  const handleToggleApproval = (id: string) => {
    const updatedRecords = records.map(r => {
      if (r.id === id) {
        let newStatus: boolean | null = null;
        if (r.isOvertimeApproved === null) newStatus = true;
        else if (r.isOvertimeApproved === true) newStatus = false;
        else newStatus = null;
        return { ...r, isOvertimeApproved: newStatus };
      }
      return r;
    });
    setRecords(updatedRecords);
  };

  const handleManualOvertime = (date: string, hours: number, reason: string) => {
    if (!currentEmployeeId) return;

    let updatedRecords = [...records];
    const recordIndex = updatedRecords.findIndex(r => r.employeeId === currentEmployeeId && r.date === date);
    let record = recordIndex >= 0 ? updatedRecords[recordIndex] : null;

    const noteEntry = `[Manual]: ${reason}`;

    if (record) {
      const newOvertime = (record.overtimeHours || 0) + hours;
      const newBalance = (record.balanceHours || 0) + hours;
      const newTotal = record.totalHours + hours;
      const existingNotes = record.notes ? record.notes + '\n' : '';

      updatedRecords[recordIndex] = {
        ...record,
        totalHours: newTotal,
        overtimeHours: newOvertime,
        balanceHours: newBalance,
        notes: existingNotes + noteEntry,
        isOvertimeApproved: null
      };
    } else {
      record = {
        id: crypto.randomUUID(),
        employeeId: currentEmployeeId,
        date: date,
        startTime: null,
        lunchStartTime: null,
        lunchEndTime: null,
        endTime: null,
        totalHours: hours,
        overtimeHours: hours,
        balanceHours: hours,
        isOvertimeApproved: null,
        status: 'COMPLETO',
        notes: noteEntry
      };
      updatedRecords = [record, ...updatedRecords];
    }

    // Sort all records by date
    updatedRecords.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    setRecords(updatedRecords);
  };

  const handleAnalyzeAI = async () => {
    setLoadingAI(true);
    setAiInsight(null);
    // Analyze the currently filtered records
    const feedback = await analyzeTimesheet(filteredRecords.slice(0, 10)); // Limit to last 10 for analysis
    setAiInsight(feedback);
    setLoadingAI(false);
  };

  const switchUser = (id: string) => {
    setCurrentEmployeeId(id);
    setAiInsight(null);
    setIsUserMenuOpen(false);
    setActiveTab('ponto');
  };

  const handleBackup = () => {
    const backupData = {
      version: 1,
      date: new Date().toISOString(),
      employees,
      records
    };
    const blob = new Blob([JSON.stringify(backupData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `ponto_facil_backup_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleRestore = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const content = e.target?.result as string;
        const data = JSON.parse(content);

        if (data.employees && Array.isArray(data.employees) && data.records && Array.isArray(data.records)) {
          if (window.confirm("Isso substituirá todos os dados atuais pelos dados do backup. Deseja continuar?")) {
            setEmployees(data.employees);
            setRecords(data.records);
            setCurrentEmployeeId(data.employees[0]?.id || '');
            alert("Backup restaurado com sucesso!");
          }
        } else {
          alert("Arquivo de backup inválido.");
        }
      } catch (error) {
        console.error("Erro ao ler backup:", error);
        alert("Erro ao processar o arquivo.");
      }
      // Reset input
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  if (!currentEmployee) return <div className="min-h-screen flex items-center justify-center"><Loader2 className="animate-spin w-8 h-8 text-indigo-600"/></div>;

