  const handleBackup = () => {
    const backupData = { version: 1, date: new Date().toISOString(), employees, records };
    const blob = new Blob([JSON.stringify(backupData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `ponto_facil_backup_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleRestore = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const content = e.target?.result as string;
        const data = JSON.parse(content);
        if (data.employees && Array.isArray(data.employees) && data.records && Array.isArray(data.records)) {
          if (window.confirm("Isso substituirá todos os dados atuais. Deseja continuar?")) {
            setEmployees(data.employees);
            setRecords(data.records);
            setCurrentEmployeeId(data.employees[0]?.id || '');
            alert("Backup restaurado!");
          }
        } else {
          alert("Backup inválido.");
        }
      } catch (error) {
        alert("Erro ao processar arquivo.");
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

