/**
 * Calculates the difference in hours between two ISO date strings.
 */
export const getHoursDifference = (startIso: string | null, endIso: string | null): number => {
  if (!startIso || !endIso) return 0;
  const start = new Date(startIso).getTime();
  const end = new Date(endIso).getTime();
  const diffMs = end - start;
  return diffMs / (1000 * 60 * 60);
};

/**
 * Calculates the total worked hours based on punches (Entry, Exit, Lunch).
 */
export const calculateWorkedHours = (record: TimeRecord): number => {
  if (!record.startTime || !record.endTime) return 0;

  // Gross duration (Exit - Entry)
  let totalHours = getHoursDifference(record.startTime, record.endTime);

  // Subtract Lunch if both punches exist
  if (record.lunchStartTime && record.lunchEndTime) {
    const lunchHours = getHoursDifference(record.lunchStartTime, record.lunchEndTime);
    totalHours -= lunchHours;
  }

  // Sanity check: prevent negative hours (e.g., if punches are out of order)
  return Math.max(0, totalHours);
};

/**
 * Calculates the expected work hours based on the employee's schedule.
 * Handles overnight shifts (e.g., 22:00 to 06:00).
 */
export const calculateExpectedHours = (schedule?: WorkSchedule): number => {
  if (!schedule) return 8; // Default fallback

  const { startTime, endTime, lunchDuration } = schedule;

  const [startH, startM] = startTime.split(':').map(Number);
  const [endH, endM] = endTime.split(':').map(Number);

  const startMinutes = startH * 60 + startM;
  const endMinutes = endH * 60 + endM;

  let totalWorkMinutes = endMinutes - startMinutes;

  // Handle overnight shifts (e.g., end time is smaller than start time)
  if (totalWorkMinutes < 0) {
    totalWorkMinutes += 24 * 60;
  }

  // Subtract expected lunch duration
  totalWorkMinutes -= lunchDuration;

  return totalWorkMinutes / 60;
};

/**
 * Updates a record with calculated totals, balances, and overtime.
 */
export const calculateRecordTotals = (record: TimeRecord, schedule?: WorkSchedule): TimeRecord => {
  const totalHours = calculateWorkedHours(record);
  const targetHours = calculateExpectedHours(schedule);

  const balanceHours = totalHours - targetHours;
  // Overtime is only the positive part of the balance
  const overtimeHours = Math.max(0, balanceHours);

  return {
    ...record,
    totalHours,
    balanceHours,
    overtimeHours
  };
};

