      if (lastNotificationTimeRef.current === timeString) return;

      const record = currentRecordRef.current;
      const schedule = currentEmployee?.workSchedule || { startTime: '09:00', endTime: '18:00', lunchDuration: 60 };

      const [startH] = schedule.startTime.split(':').map(Number);
      const lunchStartH = (startH + 4) % 24;
      const LUNCH_START_GUESS = `${lunchStartH.toString().padStart(2, '0')}:00`;
      const lunchEndH = (lunchStartH + 1) % 24;
      const LUNCH_END_GUESS = `${lunchEndH.toString().padStart(2, '0')}:00`;

      let shouldNotify = false;
      let title = '';
      let body = '';

      if (timeString === schedule.startTime && (!record || !record.startTime)) {
          shouldNotify = true;
          title = 'Hora de Entrar! ☀️';
          body = `Bom dia ${currentEmployee.name.split(' ')[0]}! Seu horário é ${schedule.startTime}.`;
      } else if (timeString === LUNCH_START_GUESS && (record && record.startTime && !record.lunchStartTime)) {
          shouldNotify = true;
          title = 'Hora do Almoço! 🍽️';
          body = 'Bom apetite! Registre sua saída para o intervalo.';
      } else if (timeString === LUNCH_END_GUESS && (record && record.lunchStartTime && !record.lunchEndTime)) {
          shouldNotify = true;
          title = 'Fim do Intervalo 🕐';
          body = 'Hora de voltar. Registre sua volta do almoço.';
      } else if (timeString === schedule.endTime && (record && record.startTime && !record.endTime)) {
          shouldNotify = true;
          title = 'Fim do Expediente! 🏠';
          body = `Olá ${currentEmployee.name.split(' ')[0]}, já são ${schedule.endTime}. Seu expediente acabou, não esqueça de registrar a saída!`;
      }

      if (shouldNotify) {
        sendNotification(title, body);
        lastNotificationTimeRef.current = timeString;
      }
    };

    const interval = setInterval(checkReminders, 30000);
    return () => clearInterval(interval);
  }, [currentEmployee, isAuthenticated]);

  const handleEnableNotifications = async () => {
    const granted = await requestNotificationPermission();
