import { TimeRecord, WorkSchedule } from "../types";

// 2025 Wage Constants
const RATES = {
  NORMAL_HOUR: 6.90,        // R$ 6,90
  OT_STANDARD: 10.35,       // R$ 10,35 (Weekdays 18-22h, Sat 12-18h)
  OT_NIGHT: 12.42,          // R$ 12,42 (Weekdays 22-05h)
  SUNDAY_NORMAL: 13.80,     // R$ 13,80 (Sunday up to 8h)
  SUNDAY_OT: 17.25          // R$ 17,25 (Sunday after 8h)
};

/**
 * Calculates the difference in hours between two ISO date strings.
 */
export const getHoursDifference = (startIso: string | null, endIso: string | null): number => {
  if (!startIso || !endIso) return 0;
  const start = new Date(startIso).getTime();
  const end = new Date(endIso).getTime();
  const diffMs = end - start;
  return diffMs / (1000 * 60 * 60);
};

/**
 * Calculates the total worked hours based on punches (Entry, Exit, Lunch).
 */
export const calculateWorkedHours = (record: TimeRecord): number => {
  if (!record.startTime || !record.endTime) return 0;

  // Gross duration (Exit - Entry)
  let totalHours = getHoursDifference(record.startTime, record.endTime);

  // Subtract Lunch if both punches exist
  if (record.lunchStartTime && record.lunchEndTime) {
    const lunchHours = getHoursDifference(record.lunchStartTime, record.lunchEndTime);
    totalHours -= lunchHours;
  }

  // Sanity check: prevent negative hours (e.g., if punches are out of order)
  return Math.max(0, totalHours);
};

/**
 * Calculates the expected work hours based on the employee's schedule.
 * Handles overnight shifts (e.g., 22:00 to 06:00).
 */
export const calculateExpectedHours = (schedule?: WorkSchedule): number => {
  if (!schedule) return 8; // Default fallback

  const { startTime, endTime, lunchDuration } = schedule;

  const [startH, startM] = startTime.split(':').map(Number);
  const [endH, endM] = endTime.split(':').map(Number);

  const startMinutes = startH * 60 + startM;
  const endMinutes = endH * 60 + endM;

  let totalWorkMinutes = endMinutes - startMinutes;

  // Handle overnight shifts (e.g., end time is smaller than start time)
  if (totalWorkMinutes < 0) {
    totalWorkMinutes += 24 * 60;
  }

  // Subtract expected lunch duration
  totalWorkMinutes -= lunchDuration;

  return totalWorkMinutes / 60;
};

/**
 * Calculates the financial value of overtime based on 2025 rules.
 * Uses a "backward fill" strategy: assuming overtime happens at the end of the shift.
 */
export const calculateOvertimeValue = (record: TimeRecord, overtimeHours: number): number => {
  if (overtimeHours <= 0 || !record.endTime) return 0;

  const date = new Date(record.date); // Use record date to check day of week
  // Adjust timezone issue by ensuring we check the local day of week from the string
  // Creating date from "YYYY-MM-DD" usually sets UTC, so getUTCDay() is safer or split
  const [y, m, d] = record.date.split('-').map(Number);
  const localDate = new Date(y, m - 1, d);
  const dayOfWeek = localDate.getDay(); // 0 = Sunday, 6 = Saturday

  const isSunday = dayOfWeek === 0;

  // If it's Sunday, calculation is different (Target is effectively 0 for 'extras' logic usually, 
  // but if system counts Sunday as a work day in schedule, we check strictly OT)
  // According to rules: Sunday work is R$ 13.80 (double) up to 8h, then R$ 17.25
  if (isSunday) {
    // For Sunday, we pay for ALL worked hours if it's considered "Extra day", 
    // or just the overtime if it's a scheduled Sunday.
    // Based on "Trabalho em domingo (até 8h): R$ 110,40", implies the whole day is payable at premium.
    // However, to stick to "Overtime" field logic:

    // Logic: 
    // If TotalHours <= 8: All OT hours * 13.80 (Assuming all Sunday hours are "Extra" relative to 44h week)
    // If TotalHours > 8: First 8h * 13.80 + (Total - 8) * 17.25

    // BUT, this function only receives `overtimeHours`.
    // We need to know if these overtime hours are "after 8h" or "within 8h".

    // Simplified assumption for the "Overtime Value" column: 
    // If the user worked Sunday, and Sunday is NOT in their regular schedule (Target=0), 
    // then Overtime = TotalHours.

    let earnings = 0;
    let remainingOT = overtimeHours;

    // How many hours were above 8h threshold?
    const hoursAbove8 = Math.max(0, record.totalHours - 8);
    const hoursWithin8 = Math.max(0, remainingOT - hoursAbove8);

    earnings += hoursAbove8 * RATES.SUNDAY_OT;
    earnings += hoursWithin8 * RATES.SUNDAY_NORMAL;

    return earnings;
  }

  // Weekdays / Saturdays logic
  // Overtime happens at the END of the shift.
  // We iterate backwards from EndTime to cover the duration of Overtime.

  const endObj = new Date(record.endTime);
  let currentHourCheck = endObj.getHours() + (endObj.getMinutes() / 60);
  // Handle crossing midnight for calculation: e.g. end 01:00 (which is 25:00 relatively)
  // If endTime < startTime roughly, we might need adjustments, but let's assume standard day shift for now
  // or simple check:
  if (record.startTime && record.endTime && record.endTime < record.startTime) {
     currentHourCheck += 24;
  }

  let earnings = 0;
  let hoursLeft = overtimeHours;

  // Resolution step: 0.5 hour (30 mins)
  const step = 0.5; 

  while (hoursLeft > 0) {
    const duration = Math.min(hoursLeft, step);
    const midPoint = currentHourCheck - (duration / 2); // Sample time in this segment

    // Check if Night Shift (22:00 - 05:00)
    // 22:00 is 22. 05:00 next day is 29.
    const effectiveHour = midPoint % 24;
    const isNight = effectiveHour >= 22 || effectiveHour < 5;

    if (isNight) {
      earnings += duration * RATES.OT_NIGHT;
    } else {
      earnings += duration * RATES.OT_STANDARD;
    }

    hoursLeft -= duration;
    currentHourCheck -= duration;
  }

  return earnings;
};

/**
 * Updates a record with calculated totals, balances, and overtime.
 */
export const calculateRecordTotals = (record: TimeRecord, schedule?: WorkSchedule): TimeRecord => {
  const totalHours = calculateWorkedHours(record);

  // Determine if today is a scheduled work day.
  // Simple check: If Sunday, assume Target = 0 (Extra Day), unless specific schedule logic says otherwise.
  // For now, we use the passed schedule. If we wanted to make Sunday "Zero Target", we'd check date here.
  const [y, m, d] = record.date.split('-').map(Number);
  const localDate = new Date(y, m - 1, d);
  const isSunday = localDate.getDay() === 0;

  // If Sunday, Target is 0 (assuming standard M-F or M-S schedule), so all hours are OT/Balance
  const targetHours = isSunday ? 0 : calculateExpectedHours(schedule);

  const balanceHours = totalHours - targetHours;
  const overtimeHours = Math.max(0, balanceHours);

  const estimatedEarnings = calculateOvertimeValue(record, overtimeHours);

  return {
    ...record,
    totalHours,
    balanceHours,
    overtimeHours,
    estimatedEarnings
  };
};

