export const requestNotificationPermission = async (): Promise<boolean> => {
  if (!("Notification" in window)) {
    console.warn("Este navegador não suporta notificações de desktop.");
    return false;
  }

  if (Notification.permission === "granted") {
    return true;
  }

  if (Notification.permission !== "denied") {
    const permission = await Notification.requestPermission();
    return permission === "granted";
  }

  return false;
};

interface NotificationOptions {
  tag?: string;
  renotify?: boolean;
}

export const sendNotification = (title: string, body: string, options?: NotificationOptions) => {
  if (Notification.permission === "granted") {
    try {
      // Check for service worker support for richer notifications (optional)
      // otherwise use standard API
      new Notification(title, {
        body,
        icon: 'https://cdn-icons-png.flaticon.com/512/109/109613.png', // Generic clock icon
        tag: options?.tag || 'ponto-facil-reminder', // Group notifications by default
        renotify: options?.renotify ?? true, // Vibrate/Alert again if tag exists
        requireInteraction: true, // Keep notification until user interacts
        silent: false
      });
    } catch (e) {
      console.error("Erro ao enviar notificação:", e);
    }
  }
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
