import { Sparkles, CalendarDays, BarChart3, LogOut, Loader2, FileSpreadsheet, FileText, PlusCircle, Users, ChevronDown, Check, Pencil, Trash2, Download, Upload, Database, Filter, XCircle, Bell, Menu, X, Clock, Cloud, CloudOff, BellOff, AlarmClock } from 'lucide-react';

// Hardcoded Admin Credentials
const ADMIN_CREDENTIALS = {
  username: 'admin',
  password: 'admin1234'
};

const App: React.FC = () => {
  // Authentication State
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [loginError, setLoginError] = useState<string | null>(null);

  const [records, setRecords] = useState<TimeRecord[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [currentEmployeeId, setCurrentEmployeeId] = useState<string>('');
  const [isLoadingData, setIsLoadingData] = useState(true);

  const [activeTab, setActiveTab] = useState<'ponto' | 'historico' | 'dashboard'>('ponto');
  const [loadingAI, setLoadingAI] = useState(false);
  const [aiInsight, setAiInsight] = useState<string | null>(null);

  // Notification / Alert State
  const [activeAlert, setActiveAlert] = useState<{title: string, message: string} | null>(null);

  // Date Filter State
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  const [isOvertimeModalOpen, setIsOvertimeModalOpen] = useState(false);
  const [isEmployeeModalOpen, setIsEmployeeModalOpen] = useState(false);
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Notification References
  const currentRecordRef = useRef<TimeRecord | null>(null);
  const lastNotificationTimeRef = useRef<string | null>(null);
  const snoozeTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  // Initialization Logic (Load from Cloud/DataService)
  useEffect(() => {
    const initData = async () => {
        setIsLoadingData(true);

        // Fetch Data
        const loadedEmployees = await dataService.getEmployees();
        const loadedRecords = await dataService.getRecords();

        setEmployees(loadedEmployees);
        setRecords(loadedRecords);

        // Set default user selection
        if (loadedEmployees.length > 0 && !currentEmployeeId) {
            setCurrentEmployeeId(loadedEmployees[0].id);
        }

        // Default Date Filter
        const now = new Date();
        const firstDay = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
        const lastDay = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().split('T')[0];
        setStartDate(firstDay);
        setEndDate(lastDay);

        setIsLoadingData(false);
    };

    initData();
  }, []);

  // Removed localStorage useEffects. Persistence is now handled in event handlers.

  // Derived State
  const currentEmployee = employees.find(e => e.id === currentEmployeeId);

  const currentUserRecords = useMemo(() => {
    return records.filter(r => r.employeeId === currentEmployeeId);
  }, [records, currentEmployeeId]);

  const filteredRecords = useMemo(() => {
    return currentUserRecords.filter(r => {
      if (!startDate && !endDate) return true;
      if (startDate && r.date < startDate) return false;
      if (endDate && r.date > endDate) return false;
      return true;
    });
  }, [currentUserRecords, startDate, endDate]);

  const todayStr = new Date().toISOString().split('T')[0];
  const currentDayRecord = currentUserRecords.find(r => r.date === todayStr) || null;

  // Update Ref for Scheduler
  useEffect(() => {
    currentRecordRef.current = currentDayRecord;
  }, [currentDayRecord]);

  // --- AUTH HANDLERS ---
  const handleLogin = (username: string, pass: string) => {
    setLoginError(null);

    // Check Admin
    if (username === ADMIN_CREDENTIALS.username && pass === ADMIN_CREDENTIALS.password) {
        setIsAuthenticated(true);
        setIsAdmin(true);
        if (employees.length > 0 && !currentEmployeeId) {
            setCurrentEmployeeId(employees[0].id);
        }
        requestNotificationPermission();
        return;
    }

    // Check Employees
    const foundEmployee = employees.find(e => e.username === username && e.password === pass);
    if (foundEmployee) {
        setIsAuthenticated(true);
        setIsAdmin(false);
        setCurrentEmployeeId(foundEmployee.id);
        requestNotificationPermission();
        return;
    }

    setLoginError("Usuário ou senha incorretos.");
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setIsAdmin(false);
    setLoginError(null);
    setAiInsight(null);
    setActiveTab('ponto');
    if (snoozeTimeoutRef.current) clearTimeout(snoozeTimeoutRef.current);
  };

  // --- APP LOGIC ---

  const triggerReminder = (title: string, message: string) => {
      // 1. Native System Notification
      sendNotification(title, message, { tag: 'time-reminder' });

      // 2. In-App Banner (for snooze control)
      setActiveAlert({ title, message });
  };

  // Notification Scheduler
  useEffect(() => {
    if (!isAuthenticated || !currentEmployee) return;

    const checkReminders = () => {
      const now = new Date();
      const timeString = now.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });

      // Prevent double firing within same minute loop if not a snooze re-trigger
      if (lastNotificationTimeRef.current === timeString) return;

      const record = currentRecordRef.current;
      const schedule = currentEmployee?.workSchedule || { startTime: '09:00', endTime: '18:00', lunchDuration: 60 };

      // START TIME REMINDER
      if (timeString === schedule.startTime && (!record || !record.startTime)) {
          triggerReminder(
              '⏰ Hora de Entrar!', 
              `Lembrete: Seu horário de entrada é às ${schedule.startTime}. Bom trabalho!`
          );
          lastNotificationTimeRef.current = timeString;
      } 
      // END TIME REMINDER
      else if (timeString === schedule.endTime && (record && record.startTime && !record.endTime)) {
          triggerReminder(
              '🏠 Fim do Expediente!', 
              `Lembrete: Seu horário de saída é às ${schedule.endTime}. Não esqueça de bater o ponto.`
          );
          lastNotificationTimeRef.current = timeString;
      }
    };

    const interval = setInterval(checkReminders, 15000); // Check every 15s for better precision
    return () => clearInterval(interval);
  }, [currentEmployee, isAuthenticated]);

  const handleSnooze = () => {
    setActiveAlert(null); // Hide UI immediately

    // Clear any existing snooze
    if (snoozeTimeoutRef.current) clearTimeout(snoozeTimeoutRef.current);

    // Set 5 minute snooze
    snoozeTimeoutRef.current = setTimeout(() => {
        const record = currentRecordRef.current;
        const schedule = currentEmployee?.workSchedule;
        if (!schedule) return;

        // Re-check conditions lazily
        // If we were snoozing an ENTRY reminder and still haven't punched in:
        if (!record || !record.startTime) {
             triggerReminder('⏰ Lembrete (Soneca)', `Você pediu para lembrar. Seu horário era ${schedule.startTime}.`);
        } 
        // If we were snoozing an EXIT reminder and still haven't punched out:
        else if (record.startTime && !record.endTime) {
             const now = new Date();
             // Simple check: is it past end time?
             const [endH, endM] = schedule.endTime.split(':').map(Number);
             if (now.getHours() > endH || (now.getHours() === endH && now.getMinutes() >= endM)) {
                 triggerReminder('🏠 Lembrete (Soneca)', `Ainda não bateu a saída? Seu horário era ${schedule.endTime}.`);
             }
        }
    }, 5 * 60 * 1000); // 5 minutes
  };

  const handleDismissAlert = () => {
      setActiveAlert(null);
      if (snoozeTimeoutRef.current) clearTimeout(snoozeTimeoutRef.current);
  };

  const handleEnableNotifications = async () => {
    const granted = await requestNotificationPermission();
    if (granted) {
      sendNotification("Notificações Ativadas", "Você receberá lembretes de ponto.");
    } else {
      alert("É necessário permitir notificações no navegador.");
    }
  };

  const handleSetCurrentMonth = () => {
    const now = new Date();
    const firstDay = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
    const lastDay = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().split('T')[0];
    setStartDate(firstDay);
    setEndDate(lastDay);
  };

  const handleClearFilter = () => {
    setStartDate('');
    setEndDate('');
  };

  const handleSaveEmployee = async (name: string, role: string, schedule: WorkSchedule, auth?: {username: string, password: string}) => {
    const initials = name.split(' ').map(n => n[0]).join('').substring(0, 2).toUpperCase();

    let newEmployeeData: Employee;

    if (editingEmployee) {
      const updatedEmployees = employees.map(emp => 
        emp.id === editingEmployee.id 
          ? { ...emp, name, role, avatarInitials: initials, workSchedule: schedule, ...auth }
          : emp
      );
      setEmployees(updatedEmployees);
      newEmployeeData = updatedEmployees.find(e => e.id === editingEmployee.id)!;
      setEditingEmployee(null);
    } else {
      const newEmployee: Employee = {
        id: crypto.randomUUID(),
        name,
        role,
        avatarInitials: initials,
        workSchedule: schedule,
        ...auth
      };
      const updatedEmployees = [...employees, newEmployee];
      setEmployees(updatedEmployees);
      if (!isAdmin) {
          setCurrentEmployeeId(newEmployee.id);
      }
      newEmployeeData = newEmployee;
    }

    // Save to Cloud
    await dataService.saveEmployee(newEmployeeData);
    setIsEmployeeModalOpen(false);
  };

  const handleEditEmployee = (e: React.MouseEvent, emp: Employee) => {
    e.stopPropagation();
    setEditingEmployee(emp);
    setIsEmployeeModalOpen(true);
    setIsUserMenuOpen(false);
  };

  const handleDeleteEmployee = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (employees.length <= 1) {
      alert("Você não pode excluir o último colaborador.");
      return;
    }

    if (window.confirm("Tem certeza? Todos os registros de ponto deste colaborador serão excluídos permanentemente.")) {
      const updatedEmployees = employees.filter(emp => emp.id !== id);
      setEmployees(updatedEmployees);

      const updatedRecords = records.filter(r => r.employeeId !== id);
      setRecords(updatedRecords);

      // Cloud Delete
      await dataService.deleteEmployee(id);
      await dataService.deleteRecordsByEmployee(id);

      if (currentEmployeeId === id) {
        setCurrentEmployeeId(updatedEmployees[0].id);
        setAiInsight(null);
      }
    }
  };

  const handlePunch = async (type: RecordType) => {
    if (!currentEmployeeId) return;

    // Clear any pending snooze reminders if user punches
    if (snoozeTimeoutRef.current) clearTimeout(snoozeTimeoutRef.current);
    setActiveAlert(null);

    const now = new Date().toISOString();
    let updatedRecords = [...records];

    let recordIndex = updatedRecords.findIndex(r => r.employeeId === currentEmployeeId && r.date === todayStr);
    let record = recordIndex >= 0 ? updatedRecords[recordIndex] : null;

    if (!record) {
      record = {
        id: crypto.randomUUID(),
        employeeId: currentEmployeeId,
        date: todayStr,
        startTime: null,
        lunchStartTime: null,
        lunchEndTime: null,
        endTime: null,
        totalHours: 0,
        overtimeHours: 0,
        balanceHours: 0,
        isOvertimeApproved: null,
        status: 'ABERTO',
        notes: ''
      };
      updatedRecords.unshift(record);
      recordIndex = 0; 
    } else {
      record = { ...record };
      updatedRecords[recordIndex] = record;
    }

    switch (type) {
      case RecordType.ENTRY:
        record.startTime = now;
        record.status = 'ABERTO';
        break;
      case RecordType.LUNCH_START:
        record.lunchStartTime = now;
        break;
      case RecordType.LUNCH_END:
        record.lunchEndTime = now;
        break;
      case RecordType.EXIT:
        record.endTime = now;
        record.status = 'COMPLETO';
        if (record.startTime && record.endTime) {
            record = calculateRecordTotals(record, currentEmployee?.workSchedule);
            updatedRecords[recordIndex] = record;
        }
        break;
    }
    setRecords(updatedRecords);

    // Save to Cloud
    await dataService.saveRecord(record);
  };

  const handleUpdateNote = async (id: string, note: string) => {
    let targetRecord: TimeRecord | undefined;
    const updatedRecords = records.map(r => {
        if (r.id === id) {
            targetRecord = { ...r, notes: note };
            return targetRecord;
        }
        return r;
    });
    setRecords(updatedRecords);
    if (targetRecord) await dataService.saveRecord(targetRecord);
  };

  const handleToggleApproval = async (id: string) => {
    if (!isAdmin) return; 

    let targetRecord: TimeRecord | undefined;
    const updatedRecords = records.map(r => {
      if (r.id === id) {
        let newStatus: boolean | null = null;
        if (r.isOvertimeApproved === null) newStatus = true;
        else if (r.isOvertimeApproved === true) newStatus = false;
        else newStatus = null;

        targetRecord = { ...r, isOvertimeApproved: newStatus };
        return targetRecord;
      }
      return r;
    });
    setRecords(updatedRecords);
    if (targetRecord) await dataService.saveRecord(targetRecord);
  };

  const handleManualOvertime = async (date: string, hours: number, reason: string) => {
    if (!currentEmployeeId) return;
    let updatedRecords = [...records];
    const recordIndex = updatedRecords.findIndex(r => r.employeeId === currentEmployeeId && r.date === date);
    let record = recordIndex >= 0 ? updatedRecords[recordIndex] : null;
    const noteEntry = `[Manual]: ${reason}`;

    if (record) {
      const newTotal = record.totalHours + hours;
      const targetHours = calculateExpectedHours(currentEmployee?.workSchedule);
      const newBalance = newTotal - targetHours;
      const newOvertime = Math.max(0, newBalance);

      const existingNotes = record.notes ? record.notes + '\n' : '';
      record = { 
          ...record, 
          totalHours: newTotal, 
          overtimeHours: newOvertime, 
          balanceHours: newBalance, 
          notes: existingNotes + noteEntry, 
          isOvertimeApproved: null 
      };
      // Recalculate earnings for manual addition
      record = calculateRecordTotals(record, currentEmployee?.workSchedule);
      updatedRecords[recordIndex] = record;
    } else {
      const targetHours = calculateExpectedHours(currentEmployee?.workSchedule);
      const balance = hours - targetHours;

      record = {
        id: crypto.randomUUID(),
        employeeId: currentEmployeeId,
        date: date,
        startTime: null,
        lunchStartTime: null,
        lunchEndTime: null,
        endTime: null,
        totalHours: hours,
        overtimeHours: Math.max(0, balance),
        balanceHours: balance,
        isOvertimeApproved: null,
        status: 'COMPLETO',
        notes: noteEntry
      };
      // Calculate earnings for manual addition
      record = calculateRecordTotals(record, currentEmployee?.workSchedule);
      updatedRecords = [record, ...updatedRecords];
    }
    updatedRecords.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    setRecords(updatedRecords);

    // Save to Cloud
    if (record) await dataService.saveRecord(record);
  };

  const handleAnalyzeAI = async () => {
    setLoadingAI(true);
    setAiInsight(null);
    const feedback = await analyzeTimesheet(filteredRecords.slice(0, 10));
    setAiInsight(feedback);
    setLoadingAI(false);
  };

  const switchUser = (id: string) => {
    if (!isAdmin) return;
    setCurrentEmployeeId(id);
    setAiInsight(null);
    setIsUserMenuOpen(false);
    setActiveTab('ponto');
  };

  // --- RENDER ---
  if (isLoadingData) {
      return (
          <div className="min-h-screen flex flex-col items-center justify-center gap-4 bg-slate-50">
              <Loader2 className="animate-spin w-10 h-10 text-indigo-600"/>
              <p className="text-slate-500 font-medium">Sincronizando com a Nuvem...</p>
          </div>
      );
  }

  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} error={loginError} />;
  }

  if (!currentEmployee) return <div className="min-h-screen flex items-center justify-center"><Loader2 className="animate-spin w-8 h-8 text-indigo-600"/></div>;

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">

      {/* Active Reminder Toast */}
      {activeAlert && (
        <div className="fixed top-4 left-1/2 transform -translate-x-1/2 z-[100] w-[90%] max-w-md animate-bounce-in">
          <div className="bg-gradient-to-r from-amber-50 to-orange-50 border border-amber-200 p-4 rounded-xl shadow-2xl flex flex-col sm:flex-row items-center gap-4">
            <div className="bg-amber-100 p-2 rounded-full shrink-0">
               <AlarmClock className="w-6 h-6 text-amber-600" />
            </div>
            <div className="flex-1 text-center sm:text-left">
               <h4 className="font-bold text-amber-900">{activeAlert.title}</h4>
               <p className="text-xs text-amber-800 leading-snug">{activeAlert.message}</p>
            </div>
            <div className="flex gap-2 shrink-0 w-full sm:w-auto">
               <button 
                 onClick={handleSnooze}
                 className="flex-1 sm:flex-none flex items-center justify-center gap-1 bg-white border border-amber-200 text-amber-700 px-3 py-1.5 rounded-lg text-xs font-bold hover:bg-amber-100 transition-colors"
               >
                 <BellOff className="w-3.5 h-3.5" />
                 Soneca (5m)
               </button>
               <button 
                 onClick={handleDismissAlert}
                 className="px-2 text-amber-400 hover:text-amber-800"
               >
                 <X className="w-5 h-5" />
               </button>
            </div>
          </div>
        </div>
      )}

      {/* Mobile Backdrop */}
      {isMobileMenuOpen && (
        <div 
          className="fixed inset-0 bg-black/50 backdrop-blur-sm z-40 md:hidden animate-fadeIn"
          onClick={() => setIsMobileMenuOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`
        fixed top-0 left-0 h-full z-50 w-72 bg-indigo-900 text-white shadow-2xl flex flex-col transition-transform duration-300 ease-in-out
        md:fixed md:w-64 md:translate-x-0
        ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-6 border-b border-indigo-800 flex justify-between items-center">
           <Logo variant="light" />
           <button 
             onClick={() => setIsMobileMenuOpen(false)}
             className="md:hidden text-indigo-300 hover:text-white"
           >
             <X className="w-6 h-6" />
           </button>
        </div>

        <nav className="p-4 space-y-2 flex-1">
          {/* Cloud Status Indicator */}
          <div className={`px-4 py-2 mb-4 rounded-lg text-xs font-semibold flex items-center gap-2 ${isFirebaseConfigured ? 'bg-indigo-800 text-green-300' : 'bg-amber-900/50 text-amber-200 border border-amber-800'}`}>
               {isFirebaseConfigured ? (
                   <>
                       <Cloud className="w-3 h-3" />
                       <span>Nuvem Conectada</span>
                   </>
               ) : (
                   <>
                       <CloudOff className="w-3 h-3" />
                       <span>Modo Offline</span>
                   </>
               )}
          </div>

          <button
            onClick={() => { setActiveTab('ponto'); setIsMobileMenuOpen(false); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${
              activeTab === 'ponto' 
                ? 'bg-indigo-700 text-white shadow-md font-semibold' 
                : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'
            }`}
          >
            <ClockIcon isActive={activeTab === 'ponto'} />
            Bater Ponto
          </button>

          <button
            onClick={() => { setActiveTab('historico'); setIsMobileMenuOpen(false); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${
              activeTab === 'historico' 
                ? 'bg-indigo-700 text-white shadow-md font-semibold' 
                : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'
            }`}
          >
            <CalendarDays className="w-5 h-5" />
            Folha de Ponto
          </button>

           <button
            onClick={() => { setActiveTab('dashboard'); setIsMobileMenuOpen(false); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${
              activeTab === 'dashboard' 
                ? 'bg-indigo-700 text-white shadow-md font-semibold' 
                : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'
            }`}
          >
            <BarChart3 className="w-5 h-5" />
            Relatórios
          </button>

          {isAdmin && (
            <div className="pt-6 mt-6 border-t border-indigo-800">
                <p className="px-4 text-xs font-semibold text-indigo-400 uppercase tracking-wider mb-2">Administração</p>
                <button
                    onClick={() => { handleEnableNotifications(); setIsMobileMenuOpen(false); }}
                    className="w-full flex items-center gap-3 px-4 py-2 text-indigo-200 hover:bg-indigo-800 hover:text-white rounded-lg transition-all text-sm"
                >
                    <Bell className="w-4 h-4" />
                    Notificações
                </button>
            </div>
          )}
        </nav>

        {/* User Profile / Switcher Section */}
        <div className="relative border-t border-indigo-800">
            {/* Dropdown only for Admins */}
            {isUserMenuOpen && isAdmin && (
                <div className="absolute bottom-full left-0 w-full bg-indigo-800 border-t border-indigo-700 shadow-xl max-h-80 overflow-y-auto animate-fadeIn">
                    <div className="p-2 space-y-1">
                         <div className="px-3 py-2 text-xs font-semibold text-indigo-300 uppercase tracking-wider">
                            Gerenciar Equipe
                        </div>
                        {employees.map(emp => (
                            <div key={emp.id} className="group relative flex items-center rounded-md hover:bg-indigo-700/50 transition-colors pr-2">
                                <button
                                    onClick={() => switchUser(emp.id)}
                                    className={`flex-1 flex items-center gap-3 px-3 py-2 rounded-md transition-colors text-left ${
                                        emp.id === currentEmployeeId ? 'text-white' : 'text-indigo-200'
                                    }`}
                                >
                                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold shrink-0 ${
                                        emp.id === currentEmployeeId ? 'bg-indigo-500 text-white' : 'bg-indigo-900 border border-indigo-600'
                                    }`}>
                                        {emp.avatarInitials}
                                    </div>
                                    <div className="truncate w-24 sm:w-32">
                                        <p className="text-sm font-medium truncate">{emp.name}</p>
                                    </div>
                                    {emp.id === currentEmployeeId && <Check className="w-4 h-4 ml-auto shrink-0" />}
                                </button>

                                <div className="hidden group-hover:flex items-center gap-1 bg-indigo-800 shadow-sm rounded ml-1">
                                    <button 
                                        onClick={(e) => handleEditEmployee(e, emp)}
                                        className="p-1.5 text-indigo-300 hover:text-white hover:bg-indigo-600 rounded"
                                        title="Editar"
                                    >
                                        <Pencil className="w-3.5 h-3.5" />
                                    </button>
                                    <button 
                                        onClick={(e) => handleDeleteEmployee(e, emp.id)}
                                        className="p-1.5 text-indigo-300 hover:text-red-400 hover:bg-indigo-600 rounded"
                                        title="Excluir"
                                    >
                                        <Trash2 className="w-3.5 h-3.5" />
                                    </button>
                                </div>
                            </div>
                        ))}
                        <button
                            onClick={() => {
                                setEditingEmployee(null);
                                setIsEmployeeModalOpen(true);
                                setIsUserMenuOpen(false);
                            }}
                            className="w-full flex items-center gap-2 px-3 py-2 mt-2 text-sm text-emerald-300 hover:bg-indigo-700/50 rounded-md transition-colors"
                        >
                            <PlusCircle className="w-4 h-4" />
                            Cadastrar Novo
                        </button>
                    </div>
                </div>
            )}

            <div className="w-full p-4 flex items-center justify-between hover:bg-indigo-800 transition-colors">
                <div 
                    className={`flex items-center gap-3 flex-1 ${isAdmin ? 'cursor-pointer' : ''}`}
                    onClick={() => isAdmin && setIsUserMenuOpen(!isUserMenuOpen)}
                >
                    <div className="w-10 h-10 rounded-full bg-indigo-500 flex items-center justify-center text-white font-bold border-2 border-indigo-400 relative">
                        {isAdmin ? 'AD' : currentEmployee.avatarInitials}
                        {isAdmin && <div className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full border-2 border-indigo-900" title="Admin"></div>}
                    </div>
                    <div className="flex-1 text-left overflow-hidden">
                        <p className="text-sm font-medium text-white truncate">
                            {isAdmin ? 'Administrador' : currentEmployee.name}
                        </p>
                        <p className="text-xs text-indigo-300 truncate">
                            {isAdmin ? 'Acesso Total' : currentEmployee.role}
                        </p>
                    </div>
                    {isAdmin && <ChevronDown className={`w-4 h-4 text-indigo-400 transition-transform ${isUserMenuOpen ? 'rotate-180' : ''}`} />}
                </div>

                <button 
                    onClick={handleLogout}
                    className="ml-2 p-2 text-indigo-300 hover:text-white hover:bg-indigo-700 rounded-lg transition-colors"
                    title="Sair"
                >
                    <LogOut className="w-5 h-5" />
                </button>
            </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 md:ml-64 p-4 md:p-8 overflow-y-auto pb-24 md:pb-8">
        {/* Mobile Header */}
        <div className="md:hidden flex justify-between items-center mb-6">
            <Logo variant="dark" />
        </div>

        <header className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
            <div>
                <h2 className="text-2xl font-bold text-slate-900">
                    {activeTab === 'ponto' && 'Registro de Ponto'}
                    {activeTab === 'historico' && 'Folha de Ponto Mensal'}
                    {activeTab === 'dashboard' && 'Painel de Indicadores'}
                </h2>
                <div className="flex flex-wrap items-center gap-x-2 text-slate-500 mt-1">
                    <span className="hidden sm:inline">
                        {new Date().toLocaleDateString('pt-BR', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}
                        <span className="mx-2">•</span>
                    </span>
                    <span className="font-medium text-indigo-600">{currentEmployee.name}</span>
                    {isAdmin && (
                        <span className="text-xs bg-red-50 text-red-600 px-2 py-0.5 rounded-full border border-red-100 ml-1 font-bold">
                            Modo Admin
                        </span>
                    )}
                </div>
            </div>

            <div className="flex flex-wrap items-center gap-3">
              <button
                onClick={() => setIsOvertimeModalOpen(true)}
                className="flex items-center gap-2 bg-indigo-50 text-indigo-700 border border-indigo-100 hover:bg-indigo-100 px-3 py-2 rounded-lg text-sm font-bold transition-colors shadow-sm"
              >
                <PlusCircle className="w-4 h-4" />
                <span className="hidden sm:inline">Add Hora Extra</span>
              </button>

              {(activeTab === 'historico' || activeTab === 'dashboard') && filteredRecords.length > 0 && (
                <div className="flex items-center gap-2 mr-2">
                  <button 
                    onClick={() => exportToCSV(filteredRecords)}
                    className="flex items-center gap-2 bg-white text-slate-600 border border-slate-200 hover:bg-slate-50 hover:text-slate-900 px-3 py-2 rounded-lg text-sm font-medium transition-colors shadow-sm"
                    title="Exportar CSV"
                  >
                    <FileSpreadsheet className="w-4 h-4" />
                    <span className="hidden sm:inline">CSV</span>
                  </button>
                  <button 
                    onClick={() => exportToPDF(filteredRecords)}
                    className="flex items-center gap-2 bg-white text-slate-600 border border-slate-200 hover:bg-slate-50 hover:text-slate-900 px-3 py-2 rounded-lg text-sm font-medium transition-colors shadow-sm"
                    title="Exportar PDF"
                  >
                    <FileText className="w-4 h-4" />
                    <span className="hidden sm:inline">PDF</span>
                  </button>
                </div>
              )}

              <button 
                  onClick={handleAnalyzeAI}
                  disabled={loadingAI || filteredRecords.length === 0}
                  className="hidden md:flex items-center gap-2 bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-700 hover:to-indigo-700 text-white px-5 py-2.5 rounded-full shadow-md transition-all active:scale-95 disabled:opacity-70 disabled:cursor-not-allowed"
              >
                  {loadingAI ? <Loader2 className="w-5 h-5 animate-spin" /> : <Sparkles className="w-5 h-5" />}
                  {loadingAI ? 'Analisando...' : 'Análise com IA'}
              </button>
            </div>
        </header>

        {/* AI Insight Box */}
        {aiInsight && (
            <div className="mb-8 bg-gradient-to-br from-indigo-50 to-purple-50 border border-indigo-100 p-6 rounded-2xl shadow-sm relative animate-fadeIn">
                <button 
                    onClick={() => setAiInsight(null)}
                    className="absolute top-4 right-4 text-slate-400 hover:text-slate-600"
                >
                    ✕
                </button>
                <div className="flex items-start gap-4">
                    <div className="bg-white p-2 rounded-lg shadow-sm">
                        <Sparkles className="w-6 h-6 text-purple-600" />
                    </div>
                    <div>
                        <h4 className="font-bold text-indigo-900 mb-2">Insight do Gemini AI ({currentEmployee.name})</h4>
                        <p className="text-slate-700 leading-relaxed text-sm whitespace-pre-line">{aiInsight}</p>
                    </div>
                </div>
            </div>
        )}

        <div className="max-w-6xl mx-auto space-y-6">
            {activeTab === 'ponto' && (
                <>
                    <TimeClock currentRecord={currentDayRecord} onPunch={handlePunch} />

                    {/* Compact recent history for 'ponto' tab */}
                    <div className="mt-8">
                        <h3 className="text-lg font-semibold text-slate-800 mb-4">Últimos Registros</h3>
                        <TimeHistory 
                          records={currentUserRecords.slice(0, 3)} 
                          onUpdateNote={handleUpdateNote}
                          onToggleApproval={handleToggleApproval}
                          compact
                        />
                    </div>
                </>
            )}

            {activeTab === 'historico' && (
                <>
                  {/* Date Filter Bar */}
                  <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col sm:flex-row gap-4 items-end sm:items-center justify-between">
                     <div className="flex flex-col sm:flex-row gap-4 items-end sm:items-center w-full sm:w-auto">
                        <div className="flex items-center gap-2 text-indigo-900 font-semibold mb-1 sm:mb-0">
                          <Filter className="w-5 h-5" />
                          <span>Filtrar Período:</span>
                        </div>

                        <div className="flex gap-2 w-full sm:w-auto">
                           <div className="flex-1 sm:w-auto">
                             <label className="block text-xs text-slate-500 mb-1">Início</label>
                             <input 
                               type="date" 
                               value={startDate}
                               onChange={(e) => setStartDate(e.target.value)}
                               className="w-full px-3 py-1.5 border border-slate-300 rounded-md text-sm focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                             />
                           </div>
                           <div className="flex-1 sm:w-auto">
                             <label className="block text-xs text-slate-500 mb-1">Fim</label>
                             <input 
                               type="date" 
                               value={endDate}
                               onChange={(e) => setEndDate(e.target.value)}
                               className="w-full px-3 py-1.5 border border-slate-300 rounded-md text-sm focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                             />
                           </div>
                        </div>
                     </div>

                     <div className="flex gap-2 w-full sm:w-auto justify-end">
                       <button
                          onClick={handleSetCurrentMonth}
                          className="px-3 py-1.5 text-xs font-medium text-indigo-600 bg-indigo-50 hover:bg-indigo-100 rounded-md transition-colors"
                       >
                         Mês Atual
                       </button>
                       {(startDate || endDate) && (
                         <button
                            onClick={handleClearFilter}
                            className="px-3 py-1.5 text-xs font-medium text-slate-500 hover:text-slate-700 hover:bg-slate-100 rounded-md transition-colors flex items-center gap-1"
                         >
                           <XCircle className="w-3.5 h-3.5" />
                           Limpar
                         </button>
                       )}
                     </div>
                  </div>

                  <TimeHistory 
                    records={filteredRecords} 
                    onUpdateNote={handleUpdateNote}
                    onToggleApproval={handleToggleApproval}
                  />
                </>
            )}

            {activeTab === 'dashboard' && (
                <div className="grid grid-cols-1 gap-6">
                    <Dashboard records={filteredRecords} />
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                         <StatCard 
                            title="Total Horas (Geral)" 
                            value={`${filteredRecords.reduce((acc, curr) => acc + curr.totalHours, 0).toFixed(1)}h`} 
                            color="bg-blue-500"
                         />
                          <StatCard 
                            title="Total Horas Extras" 
                            value={`${filteredRecords.reduce((acc, curr) => acc + (curr.overtimeHours || 0), 0).toFixed(1)}h`} 
                            color="bg-emerald-500"
                         />
                         <StatCard 
                            title="Saldo de Horas" 
                            value={`${filteredRecords.reduce((acc, curr) => acc + (curr.balanceHours || 0), 0).toFixed(1)}h`} 
                            color="bg-purple-500"
                         />
                    </div>
                </div>
            )}
        </div>
      </main>

      {/* Fixed Bottom Navigation (Mobile Only) */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 z-40 px-6 py-2 pb-safe flex justify-between items-center shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]">
        <button 
            onClick={() => setActiveTab('ponto')}
            className={`flex flex-col items-center gap-1 p-2 rounded-lg transition-colors ${activeTab === 'ponto' ? 'text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}
        >
            <Clock className="w-6 h-6" strokeWidth={activeTab === 'ponto' ? 2.5 : 2} />
            <span className="text-[10px] font-medium">Ponto</span>
        </button>

        <button 
            onClick={() => setActiveTab('historico')}
            className={`flex flex-col items-center gap-1 p-2 rounded-lg transition-colors ${activeTab === 'historico' ? 'text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}
        >
            <CalendarDays className="w-6 h-6" strokeWidth={activeTab === 'historico' ? 2.5 : 2} />
            <span className="text-[10px] font-medium">Histórico</span>
        </button>

        <button 
            onClick={() => setActiveTab('dashboard')}
            className={`flex flex-col items-center gap-1 p-2 rounded-lg transition-colors ${activeTab === 'dashboard' ? 'text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}
        >
            <BarChart3 className="w-6 h-6" strokeWidth={activeTab === 'dashboard' ? 2.5 : 2} />
            <span className="text-[10px] font-medium">Relatórios</span>
        </button>

        <button 
            onClick={() => setIsMobileMenuOpen(true)}
            className={`flex flex-col items-center gap-1 p-2 rounded-lg transition-colors ${isMobileMenuOpen ? 'text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}
        >
            <Menu className="w-6 h-6" strokeWidth={isMobileMenuOpen ? 2.5 : 2} />
            <span className="text-[10px] font-medium">Menu</span>
        </button>
      </nav>

      {/* Modals */}
      <OvertimeModal 
        isOpen={isOvertimeModalOpen}
        onClose={() => setIsOvertimeModalOpen(false)}
        onSave={handleManualOvertime}
      />

      <EmployeeModal 
        isOpen={isEmployeeModalOpen}
        onClose={() => setIsEmployeeModalOpen(false)}
        onSave={handleSaveEmployee}
        initialData={editingEmployee}
      />

      {/* Mobile Floating Action Button for AI (Adjusted position for bottom bar) */}
      <button 
            onClick={handleAnalyzeAI}
            className="md:hidden fixed bottom-20 right-6 w-12 h-12 bg-indigo-600 text-white rounded-full shadow-xl flex items-center justify-center z-30 hover:bg-indigo-700 active:scale-95"
            style={{ marginBottom: 'env(safe-area-inset-bottom)' }}
      >
           {loadingAI ? <Loader2 className="w-5 h-5 animate-spin" /> : <Sparkles className="w-5 h-5" />}
      </button>
    </div>
  );
};

// Helper Components
const ClockIcon = ({ isActive }: { isActive: boolean }) => (
    <svg 
        xmlns="http://www.w3.org/2000/svg" 
        width="24" 
        height="24" 
        viewBox="0 0 24 24" 
        fill="none" 
        stroke="currentColor" 
        strokeWidth="2" 
        strokeLinecap="round" 
        strokeLinejoin="round" 
        className="w-5 h-5"
    >
        <circle cx="12" cy="12" r="10"/>
        <polyline points="12 6 12 12 16 14"/>
    </svg>
);

const StatCard = ({ title, value, color }: { title: string, value: string, color: string }) => (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <p className="text-sm font-medium text-slate-500 uppercase tracking-wide">{title}</p>
        <div className="mt-2 flex items-baseline gap-2">
            <span className="text-3xl font-bold text-slate-900">{value}</span>
            <div className={`w-2 h-2 rounded-full ${color}`}></div>
        </div>
    </div>
);

export default App;

