                 className="px-2 text-amber-400 hover:text-amber-800"
               >
                 <X className="w-5 h-5" />
               </button>
            </div>
          </div>
        </div>
      )}

      {/* Mobile Backdrop */}
      {isMobileMenuOpen && (
