}

export const EmployeeModal: React.FC<EmployeeModalProps> = ({ isOpen, onClose, onSave, initialData }) => {
  const [name, setName] = useState('');
  const [role, setRole] = useState('');
  const [systemRole, setSystemRole] = useState<SystemRole>('COLLABORATOR');

  // Schedule State
  const [startTime, setStartTime] = useState('09:00');
  const [endTime, setEndTime] = useState('18:00');
  const [lunchDuration, setLunchDuration] = useState('60');

  // Auth State
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');

  useEffect(() => {
    if (isOpen) {
      if (initialData) {
        setName(initialData.name);
        setRole(initialData.role);
        setSystemRole(initialData.systemRole || 'COLLABORATOR');
        if (initialData.workSchedule) {
          setStartTime(initialData.workSchedule.startTime);
          setEndTime(initialData.workSchedule.endTime);
          setLunchDuration(initialData.workSchedule.lunchDuration.toString());
        }
        setUsername(initialData.username || '');
        setPassword(initialData.password || '');
      } else {
        // Defaults for new user
        setName('');
        setRole('');
        setSystemRole('COLLABORATOR');
        setStartTime('09:00');
        setEndTime('18:00');
        setLunchDuration('60');
        setUsername('');
        setPassword('');
