};

import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import { TimeRecord } from "../types";

const formatTime = (isoString: string | null) => {
  if (!isoString) return '-';
  return new Date(isoString).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
};

const formatDate = (isoDate: string) => {
  const [year, month, day] = isoDate.split('-');
  return `${day}/${month}/${year}`;
};

export const exportToCSV = (records: TimeRecord[]) => {
  const headers = [
    'Data',
    'Entrada',
    'Ida Almoço',
    'Volta Almoço',
    'Saída',
    'Total Horas',
    'Horas Extras',
    'Saldo',
    'Status',
    'Observações'
  ];

  const rows = records.map(r => [
    formatDate(r.date),
    formatTime(r.startTime),
    formatTime(r.lunchStartTime),
    formatTime(r.lunchEndTime),
    formatTime(r.endTime),
    r.totalHours.toFixed(2).replace('.', ','),
    (r.overtimeHours || 0).toFixed(2).replace('.', ','),
    (r.balanceHours || 0).toFixed(2).replace('.', ','),
    r.status,
    `"${(r.notes || '').replace(/"/g, '""')}"` // Escape quotes for CSV
  ]);

  const csvContent = [
    headers.join(';'), // Using semicolon for better Excel compatibility in BR
    ...rows.map(row => row.join(';'))
  ].join('\n');

  const blob = new Blob(["\ufeff" + csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.setAttribute('href', url);
  link.setAttribute('download', `folha_ponto_${new Date().toISOString().split('T')[0]}.csv`);
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

export const exportToPDF = (records: TimeRecord[]) => {
  const doc = new jsPDF();

  // Header
  doc.setFontSize(18);
  doc.setTextColor(40, 40, 40);
  doc.text("Folha de Ponto - Relatório Detalhado", 14, 22);

  doc.setFontSize(11);
  doc.setTextColor(100, 100, 100);
  doc.text(`Gerado em: ${new Date().toLocaleDateString('pt-BR')} às ${new Date().toLocaleTimeString('pt-BR')}`, 14, 30);

  // Summary Stats
  const totalWorked = records.reduce((acc, curr) => acc + curr.totalHours, 0);
  const totalOvertime = records.reduce((acc, curr) => acc + (curr.overtimeHours || 0), 0);
  const totalBalance = records.reduce((acc, curr) => acc + (curr.balanceHours || 0), 0);

  doc.setFillColor(248, 250, 252);
  doc.roundedRect(14, 35, 180, 25, 2, 2, 'F');

  doc.setFontSize(10);
  doc.setTextColor(70, 70, 70);
  doc.text("Total Horas Trabalhadas", 20, 45);
  doc.text("Total Horas Extras", 85, 45);
  doc.text("Saldo de Horas", 150, 45);

  doc.setFontSize(14);
  doc.setFont("helvetica", "bold");
  doc.setTextColor(30, 58, 138); // Indigo
  doc.text(`${totalWorked.toFixed(2)}h`, 20, 53);

  doc.setTextColor(21, 128, 61); // Green
  doc.text(`${totalOvertime.toFixed(2)}h`, 85, 53);

  if (totalBalance >= 0) doc.setTextColor(29, 78, 216); // Blue
  else doc.setTextColor(185, 28, 28); // Red
  doc.text(`${totalBalance > 0 ? '+' : ''}${totalBalance.toFixed(2)}h`, 150, 53);

  // Table
  const tableColumn = ["Data", "Entrada", "Saída", "Total", "Extras", "Saldo", "Obs"];
  const tableRows = records.map(r => [
    formatDate(r.date),
    formatTime(r.startTime),
    formatTime(r.endTime),
    `${r.totalHours.toFixed(2)}h`,
    r.overtimeHours > 0 ? `+${r.overtimeHours.toFixed(2)}h` : '-',
    `${r.balanceHours > 0 ? '+' : ''}${r.balanceHours.toFixed(2)}h`,
    r.notes || ''
  ]);

  autoTable(doc, {
    head: [tableColumn],
    body: tableRows,
    startY: 70,
    theme: 'grid',
    headStyles: { fillColor: [79, 70, 229] }, // Indigo 600
    styles: { fontSize: 9, cellPadding: 3 },
    columnStyles: {
      0: { cellWidth: 25 },
      6: { cellWidth: 'auto' } // Auto width for notes
    }
  });

  doc.save(`folha_ponto_${new Date().toISOString().split('T')[0]}.pdf`);
};

export const downloadJSONBackup = (data: any) => {
  const jsonString = JSON.stringify(data, null, 2);
  const blob = new Blob([jsonString], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.setAttribute('href', url);
  link.setAttribute('download', `backup_sistema_${new Date().toISOString().split('T')[0]}.json`);
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { TimeClock } from './components/TimeClock';
