        const snapshot = await getDocs(q);
        const events = snapshot.docs.map(doc => doc.data() as LoginEvent);

        setLocal('loginHistory', events); // Sync Cache
        return events;

      } catch (e) {
        // Fallback for missing index or error, tries simple fetch
        try {
            const snapshot = await getDocs(collection(db, LOGINS_COL));
            const data = snapshot.docs.map(doc => doc.data() as LoginEvent);
            const sorted = data.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

            setLocal('loginHistory', sorted); // Sync Cache
            return sorted;
        } catch(err) {
            console.error(err);
            // Deep fallback to existing local storage
            return getLocal('loginHistory').sort((a: LoginEvent, b: LoginEvent) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
        }
      }
    }
    const events = getLocal('loginHistory') as LoginEvent[];
    return events.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  },

  /**
   * Get Holidays
   */
  async getHolidays(): Promise<Holiday[]> {
