import { TimeRecord, WorkSchedule, Holiday } from "../types";

// 2025 Wage Constants
const RATES = {
  NORMAL_HOUR: 6.90,        // R$ 6,90
  OT_STANDARD: 10.35,       // R$ 10,35 (Weekdays 18-22h, Sat 12-18h)
  OT_NIGHT: 12.42,          // R$ 12,42 (Weekdays 22-05h, Sat 22-05h)
  SUNDAY_NORMAL: 13.80,     // R$ 13,80 (Sunday up to 8h)
  SUNDAY_OT: 17.25          // R$ 17,25 (Sunday after 8h)
};

/**
 * Calculates the difference in hours between two ISO date strings.
 */
export const getHoursDifference = (startIso: string | null, endIso: string | null): number => {
  if (!startIso || !endIso) return 0;
  const start = new Date(startIso).getTime();
  const end = new Date(endIso).getTime();
  const diffMs = end - start;
  return diffMs / (1000 * 60 * 60);
};

/**
 * Calculates the total worked hours based on punches (Entry, Exit, Lunch).
 */
export const calculateWorkedHours = (record: TimeRecord): number => {
  if (!record.startTime || !record.endTime) return 0;

  // Gross duration (Exit - Entry)
  let totalHours = getHoursDifference(record.startTime, record.endTime);

  // Subtract Lunch if both punches exist
  if (record.lunchStartTime && record.lunchEndTime) {
    const lunchHours = getHoursDifference(record.lunchStartTime, record.lunchEndTime);
    totalHours -= lunchHours;
  }

  // Sanity check: prevent negative hours (e.g., if punches are out of order)
  return Math.max(0, totalHours);
};

/**
 * Calculates the expected work hours based on the employee's schedule.
 * Handles overnight shifts (e.g., 22:00 to 06:00).
 * If isHoliday is true, expected hours are 0.
 */
export const calculateExpectedHours = (schedule?: WorkSchedule, isHoliday: boolean = false): number => {
  if (isHoliday) return 0; // Holidays are legally "Time Off", so target is 0.

  if (!schedule) return 8; // Default fallback

  const { startTime, endTime, lunchDuration } = schedule;

  const [startH, startM] = startTime.split(':').map(Number);
  const [endH, endM] = endTime.split(':').map(Number);

  const startMinutes = startH * 60 + startM;
  const endMinutes = endH * 60 + endM;

  let totalWorkMinutes = endMinutes - startMinutes;

  // Handle overnight shifts (e.g., end time is smaller than start time)
  if (totalWorkMinutes < 0) {
    totalWorkMinutes += 24 * 60;
  }

  // Subtract expected lunch duration
  totalWorkMinutes -= lunchDuration;

  return totalWorkMinutes / 60;
};

/**
 * Calculates the financial value of overtime based on 2025 rules.
 * Uses precise timestamp intersection to determine Day vs Night shift.
 * Validates 'endTime' correctly for Saturday rules (R$ 10.35).
 * Holidays are treated with the same high rates as Sundays.
 */
export const calculateOvertimeValue = (record: TimeRecord, overtimeHours: number, isHoliday: boolean = false): number => {
  if (overtimeHours <= 0 || !record.endTime) return 0;

  const [y, m, d] = record.date.split('-').map(Number);
  const localDate = new Date(y, m - 1, d);
  const dayOfWeek = localDate.getDay(); // 0 = Sunday, 6 = Saturday

  const isSunday = dayOfWeek === 0;

  if (isSunday || isHoliday) {
    // Sunday/Holiday Logic:
    // We assume Overtime hours are the *last* hours worked in the day.
    // Interval of overtime: [totalHours - overtimeHours, totalHours]
    // Pay Rate 1 (R$ 13.80): Hours within [0, 8]
    // Pay Rate 2 (R$ 17.25): Hours within [8, Infinity]

    const otStart = record.totalHours - overtimeHours;
    const otEnd = record.totalHours;

    // Intersection with [8, Infinity]
    const highRateStart = Math.max(otStart, 8);
    const highRateEnd = otEnd;
    const highRateHours = Math.max(0, highRateEnd - highRateStart);

    // Remaining hours are low rate (but still "Sunday/Holiday Normal" rate which is higher than weekday)
    const lowRateHours = Math.max(0, overtimeHours - highRateHours);

    return (highRateHours * RATES.SUNDAY_OT) + (lowRateHours * RATES.SUNDAY_NORMAL);
  }

  // Weekdays / Saturdays Logic with Precise Timestamps
  // This correctly covers the Saturday rule: "Hora extra no sábado (12h00 às 18h00): R$ 10,35"
  // Since 12:00-18:00 falls into the Day Interval, it uses RATES.OT_STANDARD (10.35).
  let earnings = 0;
  const endMs = new Date(record.endTime).getTime();
  // Start of the overtime period (assuming OT is at the end of the shift)
  let currentMs = endMs - (overtimeHours * 60 * 60 * 1000);

  // Iterate through time intervals until we reach the end of the OT period
  while (currentMs < endMs) {
    const currentD = new Date(currentMs);
    const hour = currentD.getHours();

    let isNight = false;
    let nextBoundaryDate = new Date(currentD);
    nextBoundaryDate.setMinutes(0, 0, 0); // Reset minutes/seconds to simplify boundary calculation

    // Determine current state and next boundary
    // Night Shift: 22:00 to 05:00 (Applies to Weekdays AND Saturday nights)
    if (hour < 5) {
       // Night Interval (00:00 - 05:00)
       isNight = true;
       nextBoundaryDate.setHours(5);
    } else if (hour >= 5 && hour < 22) {
       // Day Interval (05:00 - 22:00)
       isNight = false;
       nextBoundaryDate.setHours(22);
    } else { 
       // Night Interval (22:00 - 23:59...) -> Boundary is tomorrow 05:00
       isNight = true;
       nextBoundaryDate.setDate(nextBoundaryDate.getDate() + 1);
       nextBoundaryDate.setHours(5);
    }

    const boundaryMs = nextBoundaryDate.getTime();

    // Determine the duration of this specific segment (Day or Night)
    // It is the minimum of: Time until the next boundary OR Time until the OT period ends.
    const timeUntilBoundary = boundaryMs - currentMs;
    const timeUntilEnd = endMs - currentMs;

    const segmentDurationMs = Math.min(timeUntilBoundary, timeUntilEnd);

    // Safety check to prevent infinite loops in edge cases
    if (segmentDurationMs <= 0) break;

    const segmentHours = segmentDurationMs / (1000 * 60 * 60);
    const rate = isNight ? RATES.OT_NIGHT : RATES.OT_STANDARD;

    earnings += segmentHours * rate;

    // Advance current time
    currentMs += segmentDurationMs;
  }

  return earnings;
};

/**
 * Updates a record with calculated totals, balances, and overtime.
 */
export const calculateRecordTotals = (record: TimeRecord, schedule?: WorkSchedule, holidays: Holiday[] = []): TimeRecord => {
  const totalHours = calculateWorkedHours(record);

  const [y, m, d] = record.date.split('-').map(Number);
  const localDate = new Date(y, m - 1, d);
  const dayOfWeek = localDate.getDay(); // 0 = Sunday, 6 = Saturday

  // Check if date is in holidays list
  const isHoliday = holidays.some(h => h.date === record.date);
  const isSunday = dayOfWeek === 0;

  // If Sunday or Holiday, Target is 0, so all hours are OT/Balance.
  const targetHours = (isSunday || isHoliday) ? 0 : calculateExpectedHours(schedule, false);

  const balanceHours = totalHours - targetHours;
  const overtimeHours = Math.max(0, balanceHours);

  const estimatedEarnings = calculateOvertimeValue(record, overtimeHours, isHoliday);

  return {
    ...record,
    totalHours,
    balanceHours,
    overtimeHours,
    estimatedEarnings
  };
};

