export { db };

import { db, isFirebaseConfigured } from "./firebase";
import { collection, getDocs, doc, setDoc, deleteDoc, query, where, orderBy, limit, writeBatch, onSnapshot } from "firebase/firestore";
import { Employee, TimeRecord, LoginEvent, Holiday } from "../types";

const EMPLOYEES_COL = "employees";
const RECORDS_COL = "timeRecords";
const LOGINS_COL = "loginHistory";
const HOLIDAYS_COL = "holidays";

// --- HELPERS FOR LOCAL STORAGE FALLBACK ---
const getLocal = (key: string) => JSON.parse(localStorage.getItem(key) || '[]');
const setLocal = (key: string, data: any) => localStorage.setItem(key, JSON.stringify(data));

// --- DATA SERVICE ---

export const dataService = {

  // --- REALTIME SUBSCRIPTIONS (SYNC) ---

  subscribeToEmployees(callback: (data: Employee[]) => void): () => void {
    if (isFirebaseConfigured && db) {
      // Real-time Cloud Listener
      return onSnapshot(collection(db, EMPLOYEES_COL), async (snapshot) => {
        const employees = snapshot.docs.map(doc => doc.data() as Employee);

        if (employees.length === 0 && snapshot.metadata.fromCache === false) {
           // Seed only if we are sure it's empty on server (not just empty cache)
           // A simple check is usually enough
           const local = getLocal('employees');
           if (local.length === 0) {
             await this.seedInitialEmployee();
             // Subscription will fire again after write
             return;
           }
        }

        setLocal('employees', employees); // Keep local sync
        callback(employees);
      }, (error) => {
        console.error("Erro na subscrição de funcionários:", error);
        callback(getLocal('employees'));
      });
    } else {
      // Offline fallback
      const local = getLocal('employees');
      if (local.length === 0) {
          this.seedInitialEmployee().then(seeded => callback(seeded));
      } else {
          callback(local);
      }
      return () => {};
    }
  },

  subscribeToRecords(callback: (data: TimeRecord[]) => void): () => void {
    if (isFirebaseConfigured && db) {
      return onSnapshot(collection(db, RECORDS_COL), (snapshot) => {
        const records = snapshot.docs.map(doc => doc.data() as TimeRecord);
        setLocal('timeRecords', records);
        callback(records);
      }, (error) => {
        console.error("Erro na subscrição de registros:", error);
        callback(getLocal('timeRecords'));
      });
    } else {
      callback(getLocal('timeRecords'));
      return () => {};
    }
  },

  subscribeToHolidays(callback: (data: Holiday[]) => void): () => void {
    if (isFirebaseConfigured && db) {
      return onSnapshot(collection(db, HOLIDAYS_COL), (snapshot) => {
        const holidays = snapshot.docs.map(doc => doc.data() as Holiday);
        setLocal('holidays', holidays);
        callback(holidays);
      }, (error) => {
         console.error("Erro na subscrição de feriados:", error);
         callback(getLocal('holidays'));
      });
    } else {
      callback(getLocal('holidays'));
      return () => {};
    }
  },

  // --- TRADITIONAL METHODS ---

  async getEmployees(): Promise<Employee[]> {
    // Keep for one-off needs or seeding checks
    return getLocal('employees');
  },

  async seedInitialEmployee(): Promise<Employee[]> {
     const defaultEmployee: Employee = {
        id: 'user-1',
        name: 'João Silva',
        role: 'Desenvolvedor',
        systemRole: 'COLLABORATOR',
        avatarInitials: 'JS',
        workSchedule: {
            startTime: '09:00',
            endTime: '18:00',
            lunchDuration: 60
        }
      };
      await this.saveEmployee(defaultEmployee);
      return [defaultEmployee];
  },

  async getRecords(): Promise<TimeRecord[]> {
    return getLocal('timeRecords');
  },

  async saveEmployee(employee: Employee): Promise<void> {
    if (isFirebaseConfigured && db) {
      try {
        await setDoc(doc(db, EMPLOYEES_COL, employee.id), employee);
      } catch (e) {
        console.error("Erro ao salvar funcionário na nuvem:", e);
      }
    }
    const employees = getLocal('employees') as Employee[];
    const index = employees.findIndex(e => e.id === employee.id);
    if (index >= 0) employees[index] = employee;
    else employees.push(employee);
    setLocal('employees', employees);
  },

  async deleteEmployee(id: string): Promise<void> {
    if (isFirebaseConfigured && db) {
      try {
        await deleteDoc(doc(db, EMPLOYEES_COL, id));
      } catch (e) {
        console.error("Erro ao deletar da nuvem:", e);
      }
    }
    const employees = getLocal('employees') as Employee[];
    setLocal('employees', employees.filter(e => e.id !== id));
  },

  async saveRecord(record: TimeRecord): Promise<void> {
    if (isFirebaseConfigured && db) {
      try {
        await setDoc(doc(db, RECORDS_COL, record.id), record);
      } catch (e) {
        console.error("Erro ao salvar ponto na nuvem:", e);
      }
    }
    const records = getLocal('timeRecords') as TimeRecord[];
    const index = records.findIndex(r => r.id === record.id);
    if (index >= 0) records[index] = record;
    else records.push(record);
    setLocal('timeRecords', records);
  },

  async deleteRecordsByEmployee(employeeId: string): Promise<void> {
      if (isFirebaseConfigured && db) {
          try {
              const q = query(collection(db, RECORDS_COL), where("employeeId", "==", employeeId));
              const snapshot = await getDocs(q);
              const batch = writeBatch(db);
              snapshot.docs.forEach((doc) => {
                  batch.delete(doc.ref);
              });
              await batch.commit();
          } catch(e) {
              console.error("Erro ao deletar registros em lote:", e);
          }
      }
      const records = getLocal('timeRecords') as TimeRecord[];
      setLocal('timeRecords', records.filter(r => r.employeeId !== employeeId));
  },

  async saveLoginEvent(event: LoginEvent): Promise<void> {
    if (isFirebaseConfigured && db) {
      try {
        await setDoc(doc(db, LOGINS_COL, event.id), event);
      } catch (e) {
        console.error("Erro ao salvar login na nuvem:", e);
      }
    }
    const events = getLocal('loginHistory') as LoginEvent[];
    events.push(event);
    setLocal('loginHistory', events);
  },

  async getLoginEvents(): Promise<LoginEvent[]> {
    if (isFirebaseConfigured && db) {
      try {
        const q = query(collection(db, LOGINS_COL), orderBy("timestamp", "desc"), limit(100));
        const snapshot = await getDocs(q);
        const events = snapshot.docs.map(doc => doc.data() as LoginEvent);
        setLocal('loginHistory', events);
        return events;
      } catch (e) {
        console.error(e);
      }
    }
    const events = getLocal('loginHistory') as LoginEvent[];
    return events.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  },

  async getHolidays(): Promise<Holiday[]> {
    return getLocal('holidays');
  },

  async saveHoliday(holiday: Holiday): Promise<void> {
    if (isFirebaseConfigured && db) {
      try {
        await setDoc(doc(db, HOLIDAYS_COL, holiday.id), holiday);
      } catch (e) {
        console.error("Erro ao salvar feriado na nuvem:", e);
      }
    }
    const holidays = getLocal('holidays') as Holiday[];
    const index = holidays.findIndex(h => h.id === holiday.id);
    if (index >= 0) holidays[index] = holiday;
    else holidays.push(holiday);
    setLocal('holidays', holidays);
  },

  async deleteHoliday(id: string): Promise<void> {
    if (isFirebaseConfigured && db) {
      try {
        await deleteDoc(doc(db, HOLIDAYS_COL, id));
      } catch (e) {
        console.error("Erro ao deletar feriado da nuvem:", e);
      }
    }
    const holidays = getLocal('holidays') as Holiday[];
    setLocal('holidays', holidays.filter(h => h.id !== id));
  },

  async getFullBackupData(): Promise<any> {
    // For backup, we might want fresh data from getDocs or just use local cache
    const employees = getLocal('employees');
    const records = getLocal('timeRecords');
    const logins = await this.getLoginEvents(); // this one fetches if online
    const holidays = getLocal('holidays');

    return {
      metadata: {
        exportedAt: new Date().toISOString(),
        appName: "Ponto Facil AI",
        version: "1.1"
      },
      data: {
        employees,
        records,
        logins,
        holidays
      }
    }
  }
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { TimeClock } from './components/TimeClock';
import { TimeHistory } from './components/TimeHistory';
import { Dashboard } from './components/Dashboard';
import { OvertimeModal } from './components/OvertimeModal';
import { EmployeeModal } from './components/EmployeeModal';
import { HolidaysModal } from './components/HolidaysModal'; // Importado
import { Login } from './components/Login'; 
import { LoginHistory } from './components/LoginHistory';
import { Logo } from './components/Logo';
import { TimeRecord, RecordType, Employee, WorkSchedule, LoginEvent, SystemRole, Holiday } from './types';
import { analyzeTimesheet } from './services/geminiService';
import { exportToCSV, exportToPDF, downloadJSONBackup } from './services/exportService';
import { requestNotificationPermission, sendNotification } from './services/notificationService';
import { calculateRecordTotals, calculateExpectedHours } from './services/calculationService';
import { dataService } from './services/dataService';
import { isFirebaseConfigured } from './services/firebase';
import { Sparkles, CalendarDays, BarChart3, LogOut, Loader2, FileSpreadsheet, FileText, PlusCircle, Users, ChevronDown, Check, Pencil, Trash2, Download, Upload, Database, Filter, XCircle, Bell, Menu, X, Clock, Cloud, CloudOff, BellOff, AlarmClock, Shield, Flag } from 'lucide-react';

// Hardcoded Admin Credentials
const ADMIN_CREDENTIALS = {
  username: 'admin',
  password: 'admin1234'
};

const App: React.FC = () => {
  // Authentication State
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [userRole, setUserRole] = useState<SystemRole>('COLLABORATOR'); // Default role
  const [loginError, setLoginError] = useState<string | null>(null);

  const [records, setRecords] = useState<TimeRecord[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [loginEvents, setLoginEvents] = useState<LoginEvent[]>([]);
  const [holidays, setHolidays] = useState<Holiday[]>([]);

  const [currentEmployeeId, setCurrentEmployeeId] = useState<string>('');
  const [isLoadingData, setIsLoadingData] = useState(true);

  const [activeTab, setActiveTab] = useState<'ponto' | 'historico' | 'dashboard' | 'logins'>('ponto');
  const [loadingAI, setLoadingAI] = useState(false);
  const [aiInsight, setAiInsight] = useState<string | null>(null);

  // Notification / Alert State
  const [activeAlert, setActiveAlert] = useState<{title: string, message: string} | null>(null);

  // Date Filter State
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  const [isOvertimeModalOpen, setIsOvertimeModalOpen] = useState(false);
  const [isEmployeeModalOpen, setIsEmployeeModalOpen] = useState(false);
  const [isHolidaysModalOpen, setIsHolidaysModalOpen] = useState(false);
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Notification References
  const currentRecordRef = useRef<TimeRecord | null>(null);
  const lastNotificationTimeRef = useRef<string | null>(null);
  const snoozeTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Derived Access Levels
  const isAdmin = userRole === 'ADMIN';
  const isManager = userRole === 'ADMIN' || userRole === 'MANAGER';

  // Initialization Logic (Subscriptions)
  useEffect(() => {
    setIsLoadingData(true);

    // Setup Realtime Listeners
    const unsubEmployees = dataService.subscribeToEmployees((data) => {
        setEmployees(data);
        // Default selection logic: if no current user, select first available
        if (data.length > 0) {
            setCurrentEmployeeId(prev => prev || data[0].id);
        }
    });

    const unsubRecords = dataService.subscribeToRecords((data) => {
        setRecords(data);
    });

    const unsubHolidays = dataService.subscribeToHolidays((data) => {
        setHolidays(data);
    });

    // Remove loading state shortly
    const timer = setTimeout(() => setIsLoadingData(false), 800);

    return () => {
        unsubEmployees();
        unsubRecords();
        unsubHolidays();
        clearTimeout(timer);
    };
  }, []);

  // Fetch login history when admin tab is active
  useEffect(() => {
    if (isAdmin && activeTab === 'logins') {
        const fetchLogins = async () => {
            const events = await dataService.getLoginEvents();
            setLoginEvents(events);
        };
        fetchLogins();
    }
  }, [isAdmin, activeTab]);

  // Derived State
  const currentEmployee = employees.find(e => e.id === currentEmployeeId);

  const currentUserRecords = useMemo(() => {
    return records.filter(r => r.employeeId === currentEmployeeId);
  }, [records, currentEmployeeId]);

  const filteredRecords = useMemo(() => {
    return currentUserRecords.filter(r => {
      if (!startDate && !endDate) return true;
      if (startDate && r.date < startDate) return false;
      if (endDate && r.date > endDate) return false;
      return true;
    });
  }, [currentUserRecords, startDate, endDate]);

  const todayStr = new Date().toISOString().split('T')[0];
  const currentDayRecord = currentUserRecords.find(r => r.date === todayStr) || null;

  // Update Ref for Scheduler
  useEffect(() => {
    currentRecordRef.current = currentDayRecord;
  }, [currentDayRecord]);

  // --- AUTH HANDLERS ---
  const handleLogin = async (username: string, pass: string) => {
    setLoginError(null);

    const timestamp = new Date().toISOString();

    // Check Hardcoded Super Admin
    if (username === ADMIN_CREDENTIALS.username && pass === ADMIN_CREDENTIALS.password) {
        setIsAuthenticated(true);
        setUserRole('ADMIN');
        if (employees.length > 0 && !currentEmployeeId) {
            setCurrentEmployeeId(employees[0].id);
        }

        // Log Admin Login
        const loginEvent: LoginEvent = {
            id: crypto.randomUUID(),
            employeeId: 'admin',
            employeeName: 'Super Administrador',
            timestamp
        };
        await dataService.saveLoginEvent(loginEvent);

        requestNotificationPermission();
        return;
    }

    // Check Employees
    const foundEmployee = employees.find(e => e.username === username && e.password === pass);
    if (foundEmployee) {
        setIsAuthenticated(true);
        setUserRole(foundEmployee.systemRole || 'COLLABORATOR');
        setCurrentEmployeeId(foundEmployee.id);

        // Log User Login
        const loginEvent: LoginEvent = {
            id: crypto.randomUUID(),
            employeeId: foundEmployee.id,
            employeeName: foundEmployee.name,
            timestamp
        };
        await dataService.saveLoginEvent(loginEvent);

        requestNotificationPermission();
        return;
    }

    setLoginError("Usuário ou senha incorretos.");
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setUserRole('COLLABORATOR');
    setLoginError(null);
    setAiInsight(null);
    setActiveTab('ponto');
    if (snoozeTimeoutRef.current) clearTimeout(snoozeTimeoutRef.current);
  };

  // --- APP LOGIC ---

  const triggerReminder = (title: string, message: string) => {
      // 1. Native System Notification
      sendNotification(title, message, { tag: 'time-reminder' });

      // 2. In-App Banner (for snooze control)
      setActiveAlert({ title, message });
  };

  // Notification Scheduler
  useEffect(() => {
    if (!isAuthenticated || !currentEmployee) return;

    const checkReminders = () => {
      const now = new Date();
      // Format: "HH:MM"
      const timeString = now.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });

      // Prevent double firing within same minute loop if not a snooze re-trigger
      if (lastNotificationTimeRef.current === timeString) return;

      const record = currentRecordRef.current;
      const schedule = currentEmployee?.workSchedule || { startTime: '09:00', endTime: '18:00', lunchDuration: 60 };

      // START TIME REMINDER: Only if haven't started yet
      if (timeString === schedule.startTime && (!record || !record.startTime)) {
          triggerReminder(
              `Lembrete de Entrada: ${schedule.startTime}`, 
              `Olá ${currentEmployee.name}, já são ${schedule.startTime}. Hora de registrar sua entrada!`
          );
          lastNotificationTimeRef.current = timeString;
      } 
      // END TIME REMINDER: Only if started but not finished
      else if (timeString === schedule.endTime && (record && record.startTime && !record.endTime)) {
          triggerReminder(
              `Lembrete de Saída: ${schedule.endTime}`, 
              `Atenção ${currentEmployee.name}, seu expediente encerra às ${schedule.endTime}. Não esqueça de bater o ponto.`
          );
          lastNotificationTimeRef.current = timeString;
      }
    };

    // Check every 10 seconds to ensure we hit the minute change
    const interval = setInterval(checkReminders, 10000);
    return () => clearInterval(interval);
  }, [currentEmployee, isAuthenticated]);

  const handleSnooze = (minutes: number) => {
    setActiveAlert(null); // Hide UI immediately

    // Clear any existing snooze
    if (snoozeTimeoutRef.current) clearTimeout(snoozeTimeoutRef.current);

    // Set snooze timeout based on user selection
    snoozeTimeoutRef.current = setTimeout(() => {
        const record = currentRecordRef.current;
        const schedule = currentEmployee?.workSchedule;
        if (!schedule) return;

        // Re-check conditions lazily
        // If we were snoozing an ENTRY reminder and still haven't punched in:
        if (!record || !record.startTime) {
             triggerReminder(`Lembrete de Entrada (Soneca)`, `Lembrete adiado: Você ainda não registrou sua entrada de ${schedule.startTime}.`);
        } 
        // If we were snoozing an EXIT reminder and still haven't punched out:
        else if (record.startTime && !record.endTime) {
             const now = new Date();
             // Simple check: is it past end time?
             const [endH, endM] = schedule.endTime.split(':').map(Number);
             if (now.getHours() > endH || (now.getHours() === endH && now.getMinutes() >= endM)) {
                 triggerReminder(`Lembrete de Saída (Soneca)`, `Lembrete adiado: Já passou do seu horário (${schedule.endTime}).`);
             }
        }
    }, minutes * 60 * 1000);
  };

  const handleDismissAlert = () => {
      setActiveAlert(null);
      if (snoozeTimeoutRef.current) clearTimeout(snoozeTimeoutRef.current);
  };

  const handleEnableNotifications = async () => {
    const granted = await requestNotificationPermission();
    if (granted) {
      sendNotification("Notificações Ativadas", "Você receberá lembretes de ponto.");
    } else {
      alert("É necessário permitir notificações no navegador. Verifique as configurações do site.");
    }
  };

  const handleFullBackup = async () => {
    if (!isAdmin) return;
    try {
        const backupData = await dataService.getFullBackupData();
        downloadJSONBackup(backupData);
    } catch (e) {
        console.error(e);
        alert("Erro ao gerar backup. Tente novamente.");
    }
  };

  const handleSetCurrentMonth = () => {
    const now = new Date();
    const firstDay = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
    const lastDay = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().split('T')[0];
    setStartDate(firstDay);
    setEndDate(lastDay);
  };

  const handleClearFilter = () => {
    setStartDate('');
    setEndDate('');
  };

  const handleSaveEmployee = async (name: string, role: string, systemRole: SystemRole, schedule: WorkSchedule, auth?: {username: string, password: string}) => {
    const initials = name.split(' ').map(n => n[0]).join('').substring(0, 2).toUpperCase();

    let newEmployeeData: Employee;

    if (editingEmployee) {
      const updatedEmployees = employees.map(emp => 
        emp.id === editingEmployee.id 
          ? { ...emp, name, role, systemRole, avatarInitials: initials, workSchedule: schedule, ...auth }
          : emp
      );
      setEmployees(updatedEmployees);
      newEmployeeData = updatedEmployees.find(e => e.id === editingEmployee.id)!;
      setEditingEmployee(null);
    } else {
      const newEmployee: Employee = {
        id: crypto.randomUUID(),
        name,
        role,
        systemRole,
        avatarInitials: initials,
        workSchedule: schedule,
        ...auth
      };
      const updatedEmployees = [...employees, newEmployee];
      setEmployees(updatedEmployees);
      if (!isManager) {
          // If a non-manager adds someone (shouldn't happen due to UI checks), don't auto-switch
          setCurrentEmployeeId(newEmployee.id);
      }
      newEmployeeData = newEmployee;
    }

    // Save to Cloud
    await dataService.saveEmployee(newEmployeeData);
    setIsEmployeeModalOpen(false);
  };

  const handleEditEmployee = (e: React.MouseEvent, emp: Employee) => {
    e.stopPropagation();
    setEditingEmployee(emp);
    setIsEmployeeModalOpen(true);
    setIsUserMenuOpen(false);
  };

  const handleDeleteEmployee = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    // Only ADMIN can delete
    if (!isAdmin) {
        alert("Apenas administradores podem excluir colaboradores.");
        return;
    }

    if (employees.length <= 1) {
      alert("Você não pode excluir o último colaborador.");
      return;
    }

    if (window.confirm("Tem certeza? Todos os registros de ponto deste colaborador serão excluídos permanentemente.")) {
      const updatedEmployees = employees.filter(emp => emp.id !== id);
      setEmployees(updatedEmployees);

      const updatedRecords = records.filter(r => r.employeeId !== id);
      setRecords(updatedRecords);

      // Cloud Delete
      await dataService.deleteEmployee(id);
      await dataService.deleteRecordsByEmployee(id);

      if (currentEmployeeId === id) {
        setCurrentEmployeeId(updatedEmployees[0].id);
        setAiInsight(null);
      }
    }
  };

  // Holiday Handlers
  const handleSaveHoliday = async (date: string, name: string) => {
    const newHoliday: Holiday = {
        id: crypto.randomUUID(),
        date,
        name
    };
    const updatedHolidays = [...holidays, newHoliday];
    setHolidays(updatedHolidays);
    await dataService.saveHoliday(newHoliday);
  };

  const handleDeleteHoliday = async (id: string) => {
    if(window.confirm("Remover este feriado?")) {
        setHolidays(prev => prev.filter(h => h.id !== id));
        await dataService.deleteHoliday(id);
    }
  };

  const handlePunch = async (type: RecordType) => {
    if (!currentEmployeeId) return;

    // Clear any pending snooze reminders if user punches
    if (snoozeTimeoutRef.current) clearTimeout(snoozeTimeoutRef.current);
    setActiveAlert(null);

    const now = new Date().toISOString();
    let updatedRecords = [...records];

    let recordIndex = updatedRecords.findIndex(r => r.employeeId === currentEmployeeId && r.date === todayStr);
    let record = recordIndex >= 0 ? updatedRecords[recordIndex] : null;

    if (!record) {
      record = {
        id: crypto.randomUUID(),
        employeeId: currentEmployeeId,
        date: todayStr,
        startTime: null,
        lunchStartTime: null,
        lunchEndTime: null,
        endTime: null,
        totalHours: 0,
        overtimeHours: 0,
        balanceHours: 0,
        isOvertimeApproved: null,
        status: 'ABERTO',
        notes: ''
      };
      updatedRecords.unshift(record);
      recordIndex = 0; 
    } else {
      record = { ...record };
      updatedRecords[recordIndex] = record;
    }

    switch (type) {
      case RecordType.ENTRY:
        record.startTime = now;
        record.status = 'ABERTO';
        break;
      case RecordType.LUNCH_START:
        record.lunchStartTime = now;
        break;
      case RecordType.LUNCH_END:
        record.lunchEndTime = now;
        break;
      case RecordType.EXIT:
        record.endTime = now;
        record.status = 'COMPLETO';
        if (record.startTime && record.endTime) {
            // Pass holidays to calculation
            record = calculateRecordTotals(record, currentEmployee?.workSchedule, holidays);
            updatedRecords[recordIndex] = record;
        }
        break;
    }
    setRecords(updatedRecords);

    // Save to Cloud
    await dataService.saveRecord(record);
  };

  const handleUpdateNote = async (id: string, note: string) => {
    let targetRecord: TimeRecord | undefined;
    const updatedRecords = records.map(r => {
        if (r.id === id) {
            targetRecord = { ...r, notes: note };
            return targetRecord;
        }
        return r;
    });
    setRecords(updatedRecords);
    if (targetRecord) await dataService.saveRecord(targetRecord);
  };

  const handleToggleApproval = async (id: string) => {
    // Only Managers and Admins can approve
    if (!isManager) return; 

    let targetRecord: TimeRecord | undefined;
    const updatedRecords = records.map(r => {
      if (r.id === id) {
        let newStatus: boolean | null = null;
        if (r.isOvertimeApproved === null) newStatus = true;
        else if (r.isOvertimeApproved === true) newStatus = false;
        else newStatus = null;

        targetRecord = { ...r, isOvertimeApproved: newStatus };
        return targetRecord;
      }
      return r;
    });
    setRecords(updatedRecords);
    if (targetRecord) await dataService.saveRecord(targetRecord);
  };

  const handleManualOvertime = async (date: string, hours: number, reason: string) => {
    if (!currentEmployeeId) return;
    let updatedRecords = [...records];
    const recordIndex = updatedRecords.findIndex(r => r.employeeId === currentEmployeeId && r.date === date);
    let record = recordIndex >= 0 ? updatedRecords[recordIndex] : null;
    const noteEntry = `[Manual]: ${reason}`;

    if (record) {
      const newTotal = record.totalHours + hours;
      // Recalculate based on total hours directly since it's manual adjustment
      // Note: Manual overtime adjustment assumes adding to existing worked time.
      const existingNotes = record.notes ? record.notes + '\n' : '';

      // Temporary update to calculate totals
      record = { 
          ...record, 
          totalHours: newTotal, 
          notes: existingNotes + noteEntry, 
          isOvertimeApproved: null 
      };

      // Use service to recalculate everything (overtime, balance, earnings) including holidays
      record = calculateRecordTotals(record, currentEmployee?.workSchedule, holidays);
      updatedRecords[recordIndex] = record;

    } else {
      // Create new record for manual entry
      record = {
        id: crypto.randomUUID(),
        employeeId: currentEmployeeId,
        date: date,
        startTime: null,
        lunchStartTime: null,
        lunchEndTime: null,
        endTime: null,
        totalHours: hours,
        overtimeHours: 0, // Will be calc below
        balanceHours: 0, // Will be calc below
        isOvertimeApproved: null,
        status: 'COMPLETO',
        notes: noteEntry
      };
      // Calculate earnings for manual addition including holidays
      record = calculateRecordTotals(record, currentEmployee?.workSchedule, holidays);
      updatedRecords = [record, ...updatedRecords];
    }
    updatedRecords.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    setRecords(updatedRecords);

    // Save to Cloud
    if (record) await dataService.saveRecord(record);
  };

  const handleAnalyzeAI = async () => {
    setLoadingAI(true);
    setAiInsight(null);
    const feedback = await analyzeTimesheet(filteredRecords.slice(0, 10));
    setAiInsight(feedback);
    setLoadingAI(false);
  };

  const switchUser = (id: string) => {
    if (!isManager) return;
    setCurrentEmployeeId(id);
    setAiInsight(null);
    setIsUserMenuOpen(false);
    setActiveTab('ponto');
  };

  // --- RENDER ---
  if (isLoadingData) {
      return (
          <div className="min-h-screen flex flex-col items-center justify-center gap-4 bg-slate-50">
              <Loader2 className="animate-spin w-10 h-10 text-indigo-600"/>
              <p className="text-slate-500 font-medium">Sincronizando com a Nuvem...</p>
          </div>
      );
  }

  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} error={loginError} />;
  }

  if (!currentEmployee && !isAdmin) return <div className="min-h-screen flex items-center justify-center"><Loader2 className="animate-spin w-8 h-8 text-indigo-600"/></div>;

  // Fallback for Admin viewing if employee list is empty (rare)
  const displayName = currentEmployee?.name || (isAdmin ? "Super Administrador" : "Usuário");
  const displayRole = currentEmployee?.role || (isAdmin ? "Acesso Total" : "");
  const displayInitials = currentEmployee?.avatarInitials || (isAdmin ? "AD" : "US");

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">

      {/* Active Reminder Toast */}
      {activeAlert && (
        <div className="fixed top-4 left-1/2 transform -translate-x-1/2 z-[100] w-[90%] max-w-md animate-bounce-in">
          <div className="bg-gradient-to-r from-amber-50 to-orange-50 border border-amber-200 p-4 rounded-xl shadow-2xl flex flex-col items-center gap-3">
            <div className="flex items-center gap-3 w-full">
                <div className="bg-amber-100 p-2 rounded-full shrink-0">
                    <AlarmClock className="w-6 h-6 text-amber-600" />
                </div>
                <div className="flex-1">
                    <h4 className="font-bold text-amber-900 text-sm">{activeAlert.title}</h4>
                    <p className="text-xs text-amber-800 leading-snug">{activeAlert.message}</p>
                </div>
                <button 
                    onClick={handleDismissAlert}
                    className="p-1 text-amber-400 hover:text-amber-800 rounded-full hover:bg-amber-100"
                >
                    <X className="w-5 h-5" />
                </button>
            </div>

            <div className="flex gap-2 w-full pt-1 border-t border-amber-100/50">
               <span className="text-[10px] font-semibold text-amber-700 uppercase tracking-wide py-1.5 px-1">Adiar por:</span>
               <button 
                 onClick={() => handleSnooze(5)}
                 className="flex-1 flex items-center justify-center gap-1 bg-white border border-amber-200 text-amber-700 py-1 rounded-md text-xs font-bold hover:bg-amber-100 transition-colors"
               >
                 5m
               </button>
               <button 
                 onClick={() => handleSnooze(10)}
                 className="flex-1 flex items-center justify-center gap-1 bg-white border border-amber-200 text-amber-700 py-1 rounded-md text-xs font-bold hover:bg-amber-100 transition-colors"
               >
                 10m
               </button>
               <button 
                 onClick={() => handleSnooze(15)}
                 className="flex-1 flex items-center justify-center gap-1 bg-white border border-amber-200 text-amber-700 py-1 rounded-md text-xs font-bold hover:bg-amber-100 transition-colors"
               >
                 15m
               </button>
            </div>
          </div>
