interface CloudConfigModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export const CloudConfigModal: React.FC<CloudConfigModalProps> = ({ isOpen, onClose }) => {
  const [inputConfig, setInputConfig] = useState('');
  const [error, setError] = useState<string | null>(null);

  if (!isOpen) return null;

  const handleSave = () => {
    setError(null);
    try {
      // Tenta limpar o input para pegar apenas o objeto JSON se o usuário colou código JS
      let jsonStr = inputConfig;

      // Se o usuário colou "const firebaseConfig = { ... }", tentamos extrair o objeto
      if (jsonStr.includes("=")) {
          const match = jsonStr.match(/=\s*({[\s\S]*})/);
          if (match && match[1]) {
              jsonStr = match[1];
          }
      }

      // Corrige chaves sem aspas (ex: apiKey: "..." -> "apiKey": "...") para JSON válido
      // Esta regex é simplificada e pode não cobrir todos os casos, mas ajuda em configs comuns
      const fixedJson = jsonStr.replace(/(['"])?([a-zA-Z0-9_]+)(['"])?:/g, '"$2": ').replace(/'/g, '"');

      const config = JSON.parse(fixedJson);
      saveFirebaseConfig(config);
      onClose();
    } catch (e) {
      console.error(e);
      setError("Formato inválido. Certifique-se de colar o objeto de configuração do Firebase corretamente (JSON).");
    }
  };

  const handleDisconnect = () => {
      if (window.confirm("Tem certeza? Isso desconectará a nuvem e voltará ao modo offline.")) {
