// Algoritmo de Meeus/Jones/Butcher para cálculo da Páscoa
const getEasterDate = (year: number): Date => {
  const a = year % 19;
  const b = Math.floor(year / 100);
  const c = year % 100;
  const d = Math.floor(b / 4);
  const e = b % 4;
  const f = Math.floor((b + 8) / 25);
  const g = Math.floor((b - f + 1) / 3);
  const h = (19 * a + b - d - g + 15) % 30;
  const i = Math.floor(c / 4);
  const k = c % 4;
  const l = (32 + 2 * e + 2 * i - h - k) % 7;
  const m = Math.floor((a + 11 * h + 22 * l) / 451);
  const month = Math.floor((h + l - 7 * m + 114) / 31) - 1; // 0-indexed (Março=2, Abril=3)
  const day = ((h + l - 7 * m + 114) % 31) + 1;
  return new Date(year, month, day);
};

const addDays = (date: Date, days: number): Date => {
  const result = new Date(date);
  result.setDate(result.getDate() + days);
  return result;
};

const formatDate = (date: Date): string => {
  return date.toISOString().split('T')[0];
};

export const getBrazilianHolidays = (year: number): Omit<Holiday, 'id'>[] => {
  const holidays: Omit<Holiday, 'id'>[] = [];

  // --- Feriados Fixos Nacionais ---
  holidays.push({ date: `${year}-01-01`, name: 'Confraternização Universal' });
  holidays.push({ date: `${year}-04-21`, name: 'Tiradentes' });
  holidays.push({ date: `${year}-05-01`, name: 'Dia do Trabalho' });
  holidays.push({ date: `${year}-09-07`, name: 'Independência do Brasil' });
  holidays.push({ date: `${year}-10-12`, name: 'Nossa Sra. Aparecida' });
  holidays.push({ date: `${year}-11-02`, name: 'Finados' });
  holidays.push({ date: `${year}-11-15`, name: 'Proclamação da República' });
  holidays.push({ date: `${year}-11-20`, name: 'Dia da Consciência Negra' });
  holidays.push({ date: `${year}-12-25`, name: 'Natal' });

  // --- Feriados Móveis ---
  const easter = getEasterDate(year);

  // Carnaval (Terça-feira): Páscoa - 47 dias
  const carnival = addDays(easter, -47);
  holidays.push({ date: formatDate(carnival), name: 'Carnaval' });

  // Sexta-feira Santa: Páscoa - 2 dias
  const goodFriday = addDays(easter, -2);
  holidays.push({ date: formatDate(goodFriday), name: 'Sexta-feira Santa' });

  // Corpus Christi: Páscoa + 60 dias
  const corpusChristi = addDays(easter, 60);
  holidays.push({ date: formatDate(corpusChristi), name: 'Corpus Christi' });

  return holidays;
};

