export const HolidaysModal: React.FC<HolidaysModalProps> = ({ isOpen, onClose, holidays, onSave, onDelete }) => {
  const [newDate, setNewDate] = useState('');
  const [newName, setNewName] = useState('');
  const [isImporting, setIsImporting] = useState(false);

  if (!isOpen) return null;

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newDate || !newName) return;
    onSave(newDate, newName);
    setNewDate('');
    setNewName('');
  };

  const handleImportNationalHolidays = async () => {
    setIsImporting(true);
    const currentYear = new Date().getFullYear();
    const nationalHolidays = getBrazilianHolidays(currentYear);

    // Check duplicates
    let addedCount = 0;
    nationalHolidays.forEach(h => {
        const exists = holidays.some(existing => existing.date === h.date);
        if (!exists) {
            onSave(h.date, h.name);
            addedCount++;
        }
    });

    // Small delay for UX feedback
    setTimeout(() => {
        setIsImporting(false);
        if (addedCount === 0) {
            alert("Os feriados deste ano já estão cadastrados.");
        }
    }, 600);
  };

  // Sort holidays by date
  const sortedHolidays = [...holidays].sort((a, b) => a.date.localeCompare(b.date));

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-fadeIn">
