        <div className="p-6 flex-1 overflow-y-auto">
          {/* Quick Actions */}
          <div className="mb-6">
              <button 
                onClick={handleImportNationalHolidays}
                disabled={isImporting}
                className="w-full flex items-center justify-center gap-2 bg-indigo-50 hover:bg-indigo-100 text-indigo-700 font-semibold py-3 rounded-xl border border-indigo-200 border-dashed transition-all active:scale-95 disabled:opacity-70"
              >
                  {isImporting ? <CheckCircle className="w-5 h-5 animate-pulse" /> : <DownloadCloud className="w-5 h-5" />}
