interface EmployeeModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (name: string, role: string, systemRole: SystemRole, schedule: WorkSchedule, auth?: {username: string, password: string}) => void;
  initialData?: Employee | null;
}

export const EmployeeModal: React.FC<EmployeeModalProps> = ({ isOpen, onClose, onSave, initialData }) => {
  const [name, setName] = useState('');
  const [role, setRole] = useState('');
  const [systemRole, setSystemRole] = useState<SystemRole>('COLLABORATOR');

  // Schedule State
  const [startTime, setStartTime] = useState('09:00');
  const [endTime, setEndTime] = useState('18:00');
  const [lunchDuration, setLunchDuration] = useState('60');
  const [dailyLimit, setDailyLimit] = useState('10'); // Default 10h (8h + 2h extra legal limit)

  // Auth State
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');

  useEffect(() => {
    if (isOpen) {
      if (initialData) {
        setName(initialData.name);
        setRole(initialData.role);
        setSystemRole(initialData.systemRole || 'COLLABORATOR');
        if (initialData.workSchedule) {
          setStartTime(initialData.workSchedule.startTime);
          setEndTime(initialData.workSchedule.endTime);
          setLunchDuration(initialData.workSchedule.lunchDuration.toString());
          setDailyLimit(initialData.workSchedule.dailyLimit ? initialData.workSchedule.dailyLimit.toString() : '10');
        }
        setUsername(initialData.username || '');
        setPassword(initialData.password || '');
      } else {
        // Defaults for new user
        setName('');
        setRole('');
        setSystemRole('COLLABORATOR');
        setStartTime('09:00');
        setEndTime('18:00');
        setLunchDuration('60');
        setDailyLimit('10');
        setUsername('');
        setPassword('');
      }
    }
  }, [isOpen, initialData]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !role || !startTime || !endTime || !lunchDuration) return;

    const schedule: WorkSchedule = {
        startTime,
        endTime,
        lunchDuration: parseInt(lunchDuration, 10),
        dailyLimit: parseFloat(dailyLimit) || 10
    };

    const authData = (username && password) ? { username, password } : undefined;

    onSave(name, role, systemRole, schedule, authData);

    setName('');
    setRole('');
    setUsername('');
    setPassword('');
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-fadeIn">
      <div className="bg-white rounded-2xl shadow-xl w-full max-w-md overflow-hidden transform transition-all scale-100 max-h-[90vh] overflow-y-auto">
