import React, { useState } from 'react';
import { Cloud, X, Save, HelpCircle, Check, AlertTriangle, Trash2 } from 'lucide-react';
import { saveFirebaseConfig, clearFirebaseConfig, isFirebaseConfigured } from '../services/firebase';

interface CloudConfigModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export const CloudConfigModal: React.FC<CloudConfigModalProps> = ({ isOpen, onClose }) => {
  const [inputConfig, setInputConfig] = useState('');
  const [error, setError] = useState<string | null>(null);

  if (!isOpen) return null;

  const handleSave = () => {
    setError(null);
    try {
      let jsonStr = inputConfig.trim();

      // 1. Remover comentários (// ou /* */)
      jsonStr = jsonStr.replace(/\/\/.*$/gm, '').replace(/\/\*[\s\S]*?\*\//g, '');

      // 2. Extrair apenas o objeto entre chaves { ... }
      const firstBrace = jsonStr.indexOf('{');
      const lastBrace = jsonStr.lastIndexOf('}');

      if (firstBrace !== -1 && lastBrace !== -1) {
          jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
      } else {
          throw new Error("Não foi possível encontrar um objeto { ... } na configuração. Cole o trecho completo 'const firebaseConfig = { ... }'.");
      }

      // 3. Sanitização Avançada

      // A. Trocar aspas simples por duplas apenas em valores e chaves, preservando conteúdo
      // Substitui 'valor' por "valor"
      jsonStr = jsonStr.replace(/:\s*'([^']*)'/g, ': "$1"'); 

      // B. Corrigir chaves sem aspas (ex: apiKey: -> "apiKey":)
      // Regex corrigida: Só altera se estiver no início da string, ou precedido por { ou , 
      // Isso evita quebrar URLs como "http:" dentro de valores
      jsonStr = jsonStr.replace(/(^|[{,])\s*([a-zA-Z0-9_]+)\s*:/g, '$1"$2":');

      // C. Remover vírgulas sobrando antes de fechar objetos ou arrays
      jsonStr = jsonStr.replace(/,(\s*[}\]])/g, '$1');

      let config;
      try {
        config = JSON.parse(jsonStr);
      } catch (jsonError) {
        // Fallback: Se o regex falhar, tentar interpretar como JS Object (útil para formatos mistos)
        // Isso roda em sandbox isolado sem acesso ao window/document por segurança básica
        // eslint-disable-next-line no-new-func
        config = new Function(`return ${jsonStr}`)();
      }

      // Validação dos campos
      if (!config || (typeof config !== 'object')) {
         throw new Error("O código colado não resultou em um objeto válido.");
      }

      // Verificação flexível: precisa ter pelo menos apiKey e projectId ou ser um objeto muito parecido
      if (!config.apiKey || !config.projectId) {
         throw new Error("O objeto parece válido, mas faltam campos essenciais (apiKey, projectId). Verifique se copiou o 'firebaseConfig' correto.");
      }

      saveFirebaseConfig(config);
      onClose();
    } catch (e: any) {
      console.error(e);
      setError(e.message || "Formato inválido. Certifique-se de copiar apenas o objeto de configuração.");
    }
  };

  const handleDisconnect = () => {
      if (window.confirm("Tem certeza? Isso desconectará a nuvem e voltará ao modo offline.")) {
          clearFirebaseConfig();
          onClose();
      }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fadeIn">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[90vh]">
        <div className="bg-gradient-to-r from-indigo-900 to-indigo-800 p-5 flex justify-between items-center text-white shrink-0">
          <div className="flex items-center gap-3">
            <div className="bg-white/10 p-2 rounded-lg">
                <Cloud className="w-6 h-6 text-indigo-100" />
            </div>
            <div>
                <h3 className="font-bold text-lg leading-tight">Sincronização em Nuvem</h3>
                <p className="text-xs text-indigo-300">Acesse seus dados em qualquer dispositivo</p>
            </div>
          </div>
          <button 
            onClick={onClose}
            className="text-indigo-200 hover:text-white transition-colors p-1 rounded-full hover:bg-white/10"
          >
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="p-6 overflow-y-auto">
          {isFirebaseConfigured ? (
             <div className="text-center py-8">
                 <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4">
                     <Check className="w-8 h-8" />
                 </div>
                 <h4 className="text-xl font-bold text-slate-800 mb-2">Você está conectado!</h4>
                 <p className="text-slate-600 mb-6 max-w-md mx-auto">
                     Seus dados estão sendo sincronizados com o Firebase. Para acessar em outro dispositivo, clique em "Configurar Nuvem" nele e use as mesmas credenciais.
                 </p>
                 <button 
                    onClick={handleDisconnect}
                    className="flex items-center justify-center gap-2 mx-auto px-4 py-2 text-red-600 bg-red-50 hover:bg-red-100 rounded-lg border border-red-200 transition-colors font-medium text-sm"
                 >
                     <Trash2 className="w-4 h-4" />
                     Desconectar / Resetar Configuração
                 </button>
             </div>
          ) : (
             <div className="space-y-6">
                <div className="bg-blue-50 border border-blue-100 rounded-xl p-4 flex gap-3">
                    <HelpCircle className="w-6 h-6 text-blue-600 shrink-0" />
                    <div className="text-sm text-blue-800">
                        <p className="font-bold mb-1">Como configurar?</p>
                        <ol className="list-decimal pl-4 space-y-1">
                            <li>Acesse <a href="https://console.firebase.google.com" target="_blank" rel="noopener noreferrer" className="underline font-bold hover:text-blue-900">Firebase Console</a> e crie um projeto (Grátis).</li>
                            <li>Nas configurações do projeto, adicione um app "Web" (ícone <code>&lt;/&gt;</code>).</li>
                            <li>Copie o trecho de código <code className="bg-slate-100 px-1 rounded">const firebaseConfig = {'{ ... }'}</code>.</li>
                            <li>Cole no campo abaixo e clique em Salvar.</li>
                        </ol>
                    </div>
                </div>

                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-2">
                        Cole a configuração do Firebase aqui:
                    </label>
                    <textarea 
                        className="w-full h-40 bg-slate-50 border border-slate-300 rounded-lg p-3 font-mono text-xs focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-slate-800"
                        placeholder={`{
  apiKey: "AIzaSy...",
  authDomain: "...",
  projectId: "...",
  storageBucket: "...",
  messagingSenderId: "...",
  appId: "..."
}`}
                        value={inputConfig}
                        onChange={(e) => setInputConfig(e.target.value)}
                    />
                    {error && (
                        <div className="mt-2 flex items-center gap-2 text-red-600 text-sm bg-red-50 p-2 rounded border border-red-100 animate-fadeIn">
                            <AlertTriangle className="w-4 h-4 shrink-0" />
                            <span>{error}</span>
                        </div>
                    )}
                </div>

                <div className="flex gap-3 pt-2">
                    <button
                        onClick={onClose}
                        className="flex-1 px-4 py-3 border border-slate-300 text-slate-700 font-bold rounded-xl hover:bg-slate-50 transition-colors"
                    >
                        Cancelar
                    </button>
                    <button
                        onClick={handleSave}
                        disabled={!inputConfig}
                        className="flex-1 flex items-center justify-center gap-2 px-4 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 shadow-lg shadow-indigo-200 transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        <Save className="w-5 h-5" />
                        Salvar e Conectar
                    </button>
                </div>
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore";

const STORAGE_KEY = "ponto_facil_firebase_config";

// ============================================================================
// ÁREA DE CONFIGURAÇÃO GLOBAL (Preencha aqui para funcionar em todos dispositivos)
// ============================================================================
// Para não precisar configurar em cada celular, cole suas chaves abaixo.
// Se preenchido, o sistema ignorará a configuração manual do navegador.
const GLOBAL_CONFIG = {
  apiKey: "",             // Ex: "AIzaSy..."
  authDomain: "",         // Ex: "meu-projeto.firebaseapp.com"
  projectId: "",          // Ex: "meu-projeto"
  storageBucket: "",      // Ex: "meu-projeto.appspot.com"
  messagingSenderId: "",  // Ex: "123456789"
  appId: ""               // Ex: "1:123456:web:abcd..."
};

// --- LÓGICA DE INICIALIZAÇÃO ---

const getStoredConfig = () => {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    return stored ? JSON.parse(stored) : null;
  } catch (e) {
    return null;
  }
};

const storedConfig = getStoredConfig();

// Configuração via Variáveis de Ambiente (Build time)
const envConfig = {
  apiKey: process.env.REACT_APP_FIREBASE_API_KEY,
  authDomain: process.env.REACT_APP_FIREBASE_AUTH_DOMAIN,
  projectId: process.env.REACT_APP_FIREBASE_PROJECT_ID,
  storageBucket: process.env.REACT_APP_FIREBASE_STORAGE_BUCKET,
  messagingSenderId: process.env.REACT_APP_FIREBASE_MESSAGING_SENDER_ID,
  appId: process.env.REACT_APP_FIREBASE_APP_ID
};

// Verifica se existe configuração global válida preenchida no código
const hasGlobalConfig = GLOBAL_CONFIG.apiKey && GLOBAL_CONFIG.apiKey.length > 10;

// Ordem de Prioridade:
// 1. GLOBAL_CONFIG (Hardcoded no arquivo) - Garante sincronia entre dispositivos
// 2. envConfig (Variáveis de ambiente)
// 3. storedConfig (LocalStorage - Configuração manual via Modal)
const firebaseConfig = hasGlobalConfig 
  ? GLOBAL_CONFIG 
  : (envConfig.apiKey ? envConfig : (storedConfig || {}));

// Verifica se a configuração final é válida
export const isFirebaseConfigured = 
  firebaseConfig.apiKey && 
  !firebaseConfig.apiKey.includes("API_KEY") && 
  !firebaseConfig.apiKey.includes("COLE_SUA");

// Exporta flag para saber se estamos usando config global (para UI)
export const isUsingGlobalConfig = hasGlobalConfig || !!envConfig.apiKey;

let app;
let db;

if (isFirebaseConfigured) {
  try {
    app = initializeApp(firebaseConfig);
    db = getFirestore(app);
    console.log("🔥 Firebase conectado via", hasGlobalConfig ? "Configuração Global (Código)" : "Configuração Local");
  } catch (error) {
    console.error("Erro ao inicializar Firebase. Verifique suas credenciais:", error);
    if (storedConfig && !hasGlobalConfig) {
        console.warn("A configuração manual parece inválida.");
    }
  }
} else {
  console.warn("⚠️ Firebase não configurado. O app funcionará apenas localmente.");
}

// --- MÉTODOS PÚBLICOS PARA A UI DE CONFIGURAÇÃO ---

export const saveFirebaseConfig = (config: any) => {
    if (hasGlobalConfig) {
        alert("O sistema está usando a Configuração Global do arquivo. Edite o arquivo 'services/firebase.ts' para alterar.");
        return;
    }
    // Validação básica
    if (!config.apiKey || !config.projectId) {
        throw new Error("Configuração inválida: apiKey e projectId são obrigatórios.");
    }
    localStorage.setItem(STORAGE_KEY, JSON.stringify(config));
    window.location.reload();
};

export const clearFirebaseConfig = () => {
    if (hasGlobalConfig) {
        alert("Não é possível desconectar a Configuração Global via navegador. Remova as chaves do arquivo 'services/firebase.ts'.");
        return;
    }
    localStorage.removeItem(STORAGE_KEY);
    window.location.reload();
};

export { db };

