                    <div className="border-t border-slate-200 pt-6">
                        <button 
                            onClick={() => setShowManualInput(!showManualInput)}
                            className="w-full flex items-center justify-between text-sm font-medium text-slate-500 hover:text-indigo-600 transition-colors"
                        >
                            <span>Quero testar apenas neste navegador (Manual)</span>
                            <span>{showManualInput ? '▼' : '▶'}</span>
                        </button>

                        {showManualInput && (
                            <div className="mt-4 animate-fadeIn">
                                <label className="block text-sm font-bold text-slate-800 mb-2">
                                    Cole o <code>firebaseConfig</code> aqui:
                                </label>
                                <textarea 
                                    className="w-full h-32 bg-white border-2 border-slate-200 rounded-xl p-3 font-mono text-xs text-slate-900 focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all outline-none"
                                    placeholder={`const firebaseConfig = {\n  apiKey: "...",\n  projectId: "..."\n};`}
                                    value={inputConfig}
                                    onChange={(e) => setInputConfig(e.target.value)}
                                />
                                {error && <p className="text-red-500 text-xs mt-2 font-bold">{error}</p>}
                                <button
                                    onClick={handleSave}
                                    disabled={!inputConfig}
                                    className="mt-3 w-full py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 shadow-lg shadow-indigo-200 disabled:opacity-50"
                                >
                                    Conectar Agora
                                </button>
                            </div>
                        )}
                    </div>
                )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

