// Declarações globais para as bibliotecas do Google carregadas via script tag
declare const gapi: any;
declare const google: any;

// ============================================================================
// ⚙️ CONFIGURAÇÃO DO GOOGLE DRIVE
// Cole suas chaves do Google Cloud Console aqui para permitir o login direto.
// ============================================================================
const GOOGLE_CONFIG = {
  apiKey: "SUA_API_KEY_AQUI",       // Ex: AIzaSy...
  clientId: "SEU_CLIENT_ID_AQUI",   // Ex: 123456...apps.googleusercontent.com
  appId: "SEU_PROJECT_NUMBER_AQUI"  // Ex: 655579408680 (Opcional para o Picker)
};
// ============================================================================

const SCOPES = 'https://www.googleapis.com/auth/drive.readonly';
const DISCOVERY_DOC = 'https://www.googleapis.com/discovery/v1/apis/drive/v3/rest';

export const googleDriveService = {
  tokenClient: null as any,
  accessToken: null as string | null,
  pickerInited: false,
  gisInited: false,

  // Verifica se as chaves foram preenchidas no código
  isConfigured() {
    return GOOGLE_CONFIG.apiKey !== "SUA_API_KEY_AQUI" && 
           GOOGLE_CONFIG.clientId !== "SEU_CLIENT_ID_AQUI";
  },

  // Inicializa as bibliotecas GAPI e GIS
  async init(): Promise<boolean> {
    if (!this.isConfigured()) {
        console.warn("Google Drive: Chaves não configuradas no arquivo googleDriveService.ts");
        return false;
    }

    return new Promise((resolve) => {
      const checkGapi = () => {
        if (typeof gapi !== 'undefined' && typeof google !== 'undefined') {
          this.loadLibs(resolve);
        } else {
          setTimeout(checkGapi, 100);
        }
      };
      checkGapi();
    });
  },

  loadLibs(callback: (success: boolean) => void) {
    gapi.load('client:picker', async () => {
      try {
        await gapi.client.init({
          apiKey: GOOGLE_CONFIG.apiKey,
          discoveryDocs: [DISCOVERY_DOC],
        });
        this.pickerInited = true;

        this.tokenClient = google.accounts.oauth2.initTokenClient({
          client_id: GOOGLE_CONFIG.clientId,
          scope: SCOPES,
          callback: '', // Definido dinamicamente
        });
        this.gisInited = true;
        callback(true);
      } catch (e) {
        console.error("Erro ao carregar GAPI:", e);
        callback(false);
      }
    });
  },

  // Fluxo principal: Autenticar -> Abrir Picker -> Obter Conteúdo
  handleAuthClick(onFileSelected: (content: any) => void, onError: (msg: string) => void) {

    if (!this.gisInited || !this.pickerInited) {
        // Tenta inicializar se não estiver pronto
        this.init().then(success => {
            if(success) this.handleAuthClick(onFileSelected, onError);
            else onError("Erro de configuração. Verifique as chaves no código (googleDriveService.ts).");
        });
        return;
    }

    this.tokenClient.callback = async (resp: any) => {
      if (resp.error !== undefined) {
        onError(`Acesso negado ou fechado: ${resp.error}`);
        return;
      }
      this.accessToken = resp.access_token;
      this.createPicker(onFileSelected, onError);
    };

    if (this.accessToken === null) {
      // Prompt the user to select a Google Account and ask for consent to share their data
      this.tokenClient.requestAccessToken({ prompt: 'consent' });
    } else {
      // Skip display of account chooser and consent dialog for an existing session.
      this.tokenClient.requestAccessToken({ prompt: '' });
    }
  },

  createPicker(onFileSelected: (content: any) => void, onError: (msg: string) => void) {
    if (!this.accessToken) return;

    const view = new google.picker.View(google.picker.ViewId.DOCS);
    view.setMimeTypes("application/json,text/plain");

    const pickerBuilder = new google.picker.PickerBuilder()
      .enableFeature(google.picker.Feature.NAV_HIDDEN)
      .enableFeature(google.picker.Feature.MULTISELECT_ENABLED)
      .setOAuthToken(this.accessToken)
      .addView(view)
      .addView(new google.picker.DocsUploadView())
      .setCallback((data: any) => {
        if (data.action === google.picker.Action.PICKED) {
          const fileId = data.docs[0].id;
          this.downloadFile(fileId, onFileSelected, onError);
        }
      });

    if (GOOGLE_CONFIG.appId && GOOGLE_CONFIG.appId !== "SEU_PROJECT_NUMBER_AQUI") {
        pickerBuilder.setAppId(GOOGLE_CONFIG.appId);
    }

    const picker = pickerBuilder.build();
    picker.setVisible(true);
  },

  async downloadFile(fileId: string, onSuccess: (data: any) => void, onError: (msg: string) => void) {
    try {
        // Usando a API REST do Drive para baixar o conteúdo do arquivo
        const response = await fetch(`https://www.googleapis.com/drive/v3/files/${fileId}?alt=media`, {
            headers: {
                'Authorization': `Bearer ${this.accessToken}`
            }
        });

        if (!response.ok) throw new Error("Falha ao baixar arquivo");

        const json = await response.json();
        onSuccess(json);
    } catch (e: any) {
        console.error(e);
        onError("Não foi possível ler o arquivo. Certifique-se que é um JSON válido.");
    }
  }
};

