import { db } from "./firebase";
import { 
  collection, 
  onSnapshot, 
  doc, 
  setDoc, 
  deleteDoc, 
  query, 
  orderBy,
  getDocs
} from "firebase/firestore";
import { Employee, TimeRecord, LoginEvent, Holiday } from "../types";

// --- HELPERS PARA LOCAL STORAGE (Fallback & Cache) ---
const getLocal = (key: string) => {
    try {
        const item = localStorage.getItem(key);
        return item ? JSON.parse(item) : [];
    } catch (e) {
        console.error(`Erro ao ler cache local (${key}):`, e);
        return [];
    }
};

const setLocal = (key: string, data: any) => {
    try {
        localStorage.setItem(key, JSON.stringify(data));
    } catch (e) {
        console.error(`Erro ao salvar cache local (${key}):`, e);
    }
};

// Variável para controlar pausas manuais na sincronização (se houver erro de rede)
let isPaused = false;

export const dataService = {

  isBackendPaused: () => isPaused,

  resumeBackend: () => {
    isPaused = false;
    window.location.reload();
  },

  // --- SUBSCRIPTIONS (TEMPO REAL + CACHE) ---

  subscribeToEmployees(callback: (data: Employee[]) => void): () => void {
    // 1. ESTRATÉGIA CACHE-FIRST: Carrega dados locais imediatamente
    const cached = getLocal('employees');
    if (cached && cached.length > 0) {
        callback(cached);
    }

    if (db && !isPaused) {
      try {
        const q = query(collection(db, "employees"));
        return onSnapshot(q, (snapshot) => {
          const employees = snapshot.docs.map(doc => doc.data() as Employee);

          // Se não houver funcionários no banco (nem no cache), cria o padrão
          if (employees.length === 0 && (!cached || cached.length === 0)) {
             this.seedInitialEmployee();
          } else if (employees.length > 0) {
             // Atualiza UI com dados frescos da nuvem
             callback(employees);
             // Atualiza Cache
             setLocal('employees', employees); 
          }
        }, (error) => {
          console.error("Erro na sincronização de funcionários (usando cache):", error);
          // Se falhar e não tivermos carregado cache antes (ex: cache vazio), tenta agora
          if (!cached || cached.length === 0) callback(getLocal('employees'));
        });
      } catch (e) {
        console.error(e);
        return () => {};
      }
    } else {
      // Modo Offline/Local Exclusivo
      if (!cached || cached.length === 0) {
          this.seedInitialEmployee().then(seeded => callback(seeded));
      } else {
          callback(cached);
      }
      return () => {};
    }
  },

  subscribeToRecords(callback: (data: TimeRecord[]) => void): () => void {
    // 1. CACHE-FIRST
    const cached = getLocal('timeRecords');
    if (cached && cached.length > 0) {
        callback(cached);
    }

    if (db && !isPaused) {
        const q = query(collection(db, "timeRecords"), orderBy("date", "desc"));
        return onSnapshot(q, (snapshot) => {
            const records = snapshot.docs.map(doc => doc.data() as TimeRecord);
            callback(records);
            setLocal('timeRecords', records);
        }, (error) => {
            console.error("Erro na sincronização de registros:", error);
            // Fallback silencioso
        });
    } else {
        if (cached) callback(cached);
        return () => {};
    }
  },

  subscribeToHolidays(callback: (data: Holiday[]) => void): () => void {
    // 1. CACHE-FIRST
    const cached = getLocal('holidays');
    if (cached && cached.length > 0) {
        callback(cached);
    }

    if (db && !isPaused) {
        return onSnapshot(collection(db, "holidays"), (snapshot) => {
            const holidays = snapshot.docs.map(doc => doc.data() as Holiday);
            callback(holidays);
            setLocal('holidays', holidays);
        }, (error) => {
             console.error("Erro sync feriados:", error);
        });
    } else {
        if (cached) callback(cached);
        return () => {};
    }
  },

  // --- MÉTODOS DE ESCRITA ---

  async getEmployees(): Promise<Employee[]> {
    // Tenta ler do cache primeiro para velocidade
    const cached = getLocal('employees');
    if(db && !isPaused) {
        try {
            const snap = await getDocs(collection(db, "employees"));
            const data = snap.docs.map(d => d.data() as Employee);
            setLocal('employees', data); // Atualiza cache
            return data;
        } catch (e) {
            console.warn("Falha ao buscar funcionários online, retornando cache.");
            return cached;
        }
    }
    return cached;
  },

  async seedInitialEmployee(): Promise<Employee[]> {
     const defaultEmployee: Employee = {
        id: 'user-1',
        name: 'João Silva',
        role: 'Desenvolvedor',
        systemRole: 'COLLABORATOR',
        avatarInitials: 'JS',
        workSchedule: {
            startTime: '09:00',
            endTime: '18:00',
            lunchDuration: 60,
            dailyLimit: 10
        }
      };
      await this.saveEmployee(defaultEmployee);
      return [defaultEmployee];
  },

  async saveEmployee(employee: Employee): Promise<void> {
    // 1. Atualiza LocalStorage Imediatamente (Optimistic Update)
    const employees = getLocal('employees') as Employee[];
    const index = employees.findIndex(e => e.id === employee.id);
    if (index >= 0) employees[index] = employee;
    else employees.push(employee);
    setLocal('employees', employees);

    // 2. Tenta salvar na Nuvem
    if (db && !isPaused) {
        await setDoc(doc(db, "employees", employee.id), employee);
    }
  },

  async deleteEmployee(id: string): Promise<void> {
    // 1. Atualiza LocalStorage Imediatamente
    const employees = getLocal('employees') as Employee[];
    setLocal('employees', employees.filter(e => e.id !== id));

    // 2. Nuvem
    if (db && !isPaused) {
        await deleteDoc(doc(db, "employees", id));
    }
  },

  async saveRecord(record: TimeRecord): Promise<void> {
    // 1. Atualiza LocalStorage Imediatamente
    const records = getLocal('timeRecords') as TimeRecord[];
    const index = records.findIndex(r => r.id === record.id);
    if (index >= 0) records[index] = record;
    else records.push(record);
    // Ordena por data decrescente para manter consistência
    records.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    setLocal('timeRecords', records);

    // 2. Nuvem
    if (db && !isPaused) {
        await setDoc(doc(db, "timeRecords", record.id), record);
    }
  },

  async deleteRecordsByEmployee(employeeId: string): Promise<void> {
      // 1. Local
      const records = getLocal('timeRecords') as TimeRecord[];
      setLocal('timeRecords', records.filter(r => r.employeeId !== employeeId));

      // 2. Nuvem
      if (db && !isPaused) {
          const q = query(collection(db, "timeRecords")); 
          const snapshot = await getDocs(q);
          const batchDelete = snapshot.docs.filter(d => d.data().employeeId === employeeId);
          batchDelete.forEach(async (d) => {
              await deleteDoc(doc(db, "timeRecords", d.id));
          });
      }
  },

  async saveLoginEvent(event: LoginEvent): Promise<void> {
    // Logins: Cache local para histórico offline
    const events = getLocal('loginHistory') as LoginEvent[];
    events.push(event);
    setLocal('loginHistory', events);

    if (db && !isPaused) {
        await setDoc(doc(db, "loginHistory", event.id), event);
    }
  },

  async getLoginEvents(): Promise<LoginEvent[]> {
    const cached = getLocal('loginHistory') as LoginEvent[];

    if (db && !isPaused) {
        try {
            const q = query(collection(db, "loginHistory"), orderBy("timestamp", "desc"));
            const snap = await getDocs(q);
            const data = snap.docs.map(d => d.data() as LoginEvent);
            setLocal('loginHistory', data);
            return data;
        } catch(e) {
            return cached.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
        }
    }
    return cached.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  },

  async saveHoliday(holiday: Holiday): Promise<void> {
    // 1. Local
    const holidays = getLocal('holidays') as Holiday[];
    const index = holidays.findIndex(h => h.id === holiday.id);
    if (index >= 0) holidays[index] = holiday;
    else holidays.push(holiday);
    setLocal('holidays', holidays);

    // 2. Nuvem
    if (db && !isPaused) {
        await setDoc(doc(db, "holidays", holiday.id), holiday);
    }
  },

  async deleteHoliday(id: string): Promise<void> {
    // 1. Local
    const holidays = getLocal('holidays') as Holiday[];
    setLocal('holidays', holidays.filter(h => h.id !== id));

    // 2. Nuvem
    if (db && !isPaused) {
        await deleteDoc(doc(db, "holidays", id));
    }
  },

  // --- IMPORT/EXPORT (Híbrido) ---

  async getFullBackupData(): Promise<any> {
    // Para backup, tentamos pegar a versão mais recente possível
    let employees = getLocal('employees');
    let records = getLocal('timeRecords');
    let logins = getLocal('loginHistory');
    let holidays = getLocal('holidays');

    if (db && !isPaused) {
        try {
            const empSnap = await getDocs(collection(db, "employees"));
            employees = empSnap.docs.map(d => d.data());
            setLocal('employees', employees);

            const recSnap = await getDocs(collection(db, "timeRecords"));
            records = recSnap.docs.map(d => d.data());
            setLocal('timeRecords', records);

            const holSnap = await getDocs(collection(db, "holidays"));
            holidays = holSnap.docs.map(d => d.data());
            setLocal('holidays', holidays);

            // Logins geralmente são muitos, mantemos estratégia mista
        } catch (e) {
            console.warn("Backup online falhou parcialmente, usando dados locais.");
        }
    }

    return {
      metadata: {
        exportedAt: new Date().toISOString(),
        appName: "Ponto Facil AI",
        version: "1.1"
      },
      data: { employees, records, logins, holidays }
    };
  },

  async importDatabase(json: any): Promise<boolean> {
     try {
        if (!json.data || !json.data.employees) {
            throw new Error("Formato de arquivo inválido");
        }

        // Atualiza Cache Local Imediatamente
        setLocal('employees', json.data.employees || []);
        setLocal('timeRecords', json.data.records || []);
        setLocal('loginHistory', json.data.logins || []);
        setLocal('holidays', json.data.holidays || []);

        // Se estiver online, sobrescreve o banco na nuvem
        if (db && !isPaused) {
            for (const emp of json.data.employees) await this.saveEmployee(emp);
            for (const rec of json.data.records) await this.saveRecord(rec);
            for (const hol of json.data.holidays) await this.saveHoliday(hol);
        }

        return true;
     } catch (e) {
        console.error("Erro ao importar:", e);
        return false;
     }
  }
};

