import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import { TimeRecord } from "../types";

const formatTime = (isoString: string | null) => {
  if (!isoString) return '-';
  return new Date(isoString).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
};

const formatDate = (isoDate: string) => {
  const [year, month, day] = isoDate.split('-');
  return `${day}/${month}/${year}`;
};

// Helper para formatar campos CSV corretamente (RFC 4180 adaptado para Excel BR)
// Trata aspas duplas escapando-as ("") e envolve o campo em aspas se necessário
const processCSVField = (data: any): string => {
  if (data === null || data === undefined) return '';
  const stringData = String(data);

  // Se tiver aspas, ponto e vírgula ou quebra de linha, deve estar entre aspas
  if (stringData.includes('"') || stringData.includes(';') || stringData.includes('\n')) {
    return `"${stringData.replace(/"/g, '""')}"`;
  }
  return stringData;
};

export const exportToCSV = (records: TimeRecord[]) => {
  const headers = [
    'Data',
    'Dia da Semana',
    'Entrada',
    'Ida Almoço',
    'Volta Almoço',
    'Saída',
    'Total Horas',
    'Horas Extras',
    'Valor Estimado (R$)',
    'Saldo',
    'Status',
    'Observações'
  ];

  const rows = records.map(r => {
    // Garante a data correta considerando o fuso horário local ou apenas a string YYYY-MM-DD
    const [year, month, day] = r.date.split('-').map(Number);
    const dateObj = new Date(year, month - 1, day);
    const dayOfWeek = dateObj.toLocaleDateString('pt-BR', { weekday: 'long' });

    // Mapeia os dados e processa cada campo
    return [
      formatDate(r.date),
      dayOfWeek.charAt(0).toUpperCase() + dayOfWeek.slice(1), // Capitaliza dia da semana
      formatTime(r.startTime),
      formatTime(r.lunchStartTime),
      formatTime(r.lunchEndTime),
      formatTime(r.endTime),
      r.totalHours.toFixed(2).replace('.', ','),
      (r.overtimeHours || 0).toFixed(2).replace('.', ','),
      (r.estimatedEarnings || 0).toFixed(2).replace('.', ','),
      (r.balanceHours || 0).toFixed(2).replace('.', ','),
      r.status,
      r.notes || ''
    ].map(processCSVField).join(';');
  });

  const csvContent = [
    headers.join(';'), // Usando ponto e vírgula para compatibilidade Excel PT-BR
    ...rows
  ].join('\n');

  // Adiciona BOM (\ufeff) para o Excel reconhecer acentos UTF-8 corretamente
  const blob = new Blob(["\ufeff" + csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.setAttribute('href', url);
