export const exportToPDF = (records: TimeRecord[]) => {
  const doc = new jsPDF();

  // Header
  doc.setFontSize(18);
  doc.setTextColor(40, 40, 40);
  doc.text("Folha de Ponto - Relatório Detalhado", 14, 22);

  doc.setFontSize(11);
  doc.setTextColor(100, 100, 100);
  doc.text(`Gerado em: ${new Date().toLocaleDateString('pt-BR')} às ${new Date().toLocaleTimeString('pt-BR')}`, 14, 30);

  // Summary Stats
  const totalWorked = records.reduce((acc, curr) => acc + curr.totalHours, 0);
  const totalOvertime = records.reduce((acc, curr) => acc + (curr.overtimeHours || 0), 0);
  const totalBalance = records.reduce((acc, curr) => acc + (curr.balanceHours || 0), 0);
  const totalEarnings = records.reduce((acc, curr) => acc + (curr.estimatedEarnings || 0), 0);

  // Summary Box
  doc.setFillColor(248, 250, 252); // Slate-50
  doc.roundedRect(14, 35, 180, 25, 2, 2, 'F');

  // Summary Labels
  doc.setFontSize(9);
  doc.setTextColor(100, 116, 139); // Slate-500
  doc.text("Horas Trabalhadas", 20, 44);
  doc.text("Horas Extras", 62, 44);
  doc.text("Valor Estimado (R$)", 104, 44);
  doc.text("Saldo de Banco", 156, 44);

  // Summary Values
  doc.setFontSize(12);
  doc.setFont("helvetica", "bold");

  // 1. Worked
  doc.setTextColor(30, 58, 138); // Indigo-800
  doc.text(`${totalWorked.toFixed(2)}h`, 20, 52);

  // 2. Overtime
  doc.setTextColor(21, 128, 61); // Green-700
  doc.text(`${totalOvertime.toFixed(2)}h`, 62, 52);

  // 3. Earnings (New)
  doc.setTextColor(5, 150, 105); // Emerald-600
  doc.text(`R$ ${totalEarnings.toFixed(2)}`, 104, 52);

  // 4. Balance
  if (totalBalance >= 0) doc.setTextColor(37, 99, 235); // Blue-600
  else doc.setTextColor(220, 38, 38); // Red-600
  doc.text(`${totalBalance > 0 ? '+' : ''}${totalBalance.toFixed(2)}h`, 156, 52);

  // Table
  const tableColumn = ["Data", "Entrada", "Saída", "Total", "Extras", "Valor", "Saldo", "Obs"];
  const tableRows = records.map(r => [
    formatDate(r.date),
    formatTime(r.startTime),
    formatTime(r.endTime),
    `${r.totalHours.toFixed(2)}h`,
    r.overtimeHours > 0 ? `+${r.overtimeHours.toFixed(2)}h` : '-',
    (r.estimatedEarnings && r.estimatedEarnings > 0) ? `R$ ${r.estimatedEarnings.toFixed(2)}` : '-',
    `${r.balanceHours > 0 ? '+' : ''}${r.balanceHours.toFixed(2)}h`,
    r.notes || ''
  ]);

  autoTable(doc, {
    head: [tableColumn],
    body: tableRows,
    startY: 68,
    theme: 'grid',
    headStyles: { 
        fillColor: [79, 70, 229], // Indigo 600
        halign: 'center'
    },
    styles: { 
        fontSize: 8, 
        cellPadding: 2,
        halign: 'center'
    },
    columnStyles: {
      0: { cellWidth: 20 }, // Data
      7: { cellWidth: 'auto', halign: 'left' } // Obs
    }
  });

  doc.save(`folha_ponto_${new Date().toISOString().split('T')[0]}.pdf`);
};

export const downloadJSONBackup = (data: any) => {
  const jsonString = JSON.stringify(data, null, 2);
  const blob = new Blob([jsonString], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.setAttribute('href', url);
  link.setAttribute('download', `backup_sistema_${new Date().toISOString().split('T')[0]}.json`);
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

import React from 'react';
import { TimeRecord } from '../types';
import { CheckCircle, AlertCircle, Clock, Check, X, CircleDashed, FileText, DollarSign, AlertTriangle } from 'lucide-react';

interface TimeHistoryProps {
  records: TimeRecord[];
  onUpdateNote: (id: string, note: string) => void;
  onToggleApproval: (id: string) => void;
  compact?: boolean;
  dailyLimit?: number;
}

export const TimeHistory: React.FC<TimeHistoryProps> = ({ 
  records, 
  onUpdateNote, 
  onToggleApproval,
  compact = false,
  dailyLimit = 10 // Default visual limit if not provided
}) => {

  const formatTime = (isoString: string | null) => {
    if (!isoString) return '-';
    return new Date(isoString).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
  };

  const formatDate = (isoDate: string) => {
    const [year, month, day] = isoDate.split('-');
    return `${day}/${month}`;
  };

  // Calculate Totals
  const totalWorked = records.reduce((acc, curr) => acc + curr.totalHours, 0);
  const totalOvertime = records.reduce((acc, curr) => acc + (curr.overtimeHours || 0), 0);
  const totalBalance = records.reduce((acc, curr) => acc + (curr.balanceHours || 0), 0);
  const totalEarnings = records.reduce((acc, curr) => acc + (curr.estimatedEarnings || 0), 0);

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col animate-fadeInUp">
      <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-white">
        <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
          <Clock className="w-5 h-5 text-indigo-600" />
          {compact ? 'Resumo Recente' : 'Folha de Ponto Detalhada'}
        </h3>
        {!compact && (
            <div className="text-sm text-slate-500 flex gap-4">
                <span>Meta Diária: 8h</span>
                <span className="flex items-center gap-1 text-xs font-semibold text-slate-400 bg-slate-50 px-2 rounded-full border border-slate-100">
                    <AlertTriangle className="w-3 h-3" />
                    Limite Alerta: {dailyLimit}h
                </span>
            </div>
        )}
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-slate-50 text-slate-500 uppercase text-xs font-semibold">
            <tr>
              <th className="px-4 py-4 min-w-[80px]">Data</th>
              <th className="px-4 py-4 text-center">Entrada</th>
              {!compact && <th className="px-4 py-4 text-center">Intervalo</th>}
              <th className="px-4 py-4 text-center">Saída</th>
              <th className="px-4 py-4 text-center bg-indigo-50/50">Total</th>
              <th className="px-4 py-4 text-center text-emerald-700">Extras</th>
              {!compact && <th className="px-4 py-4 text-center text-emerald-700 bg-emerald-50/30">Valor (R$)</th>}
              <th className="px-4 py-4 text-center">Saldo</th>
              {!compact && (
                <>
                  <th className="px-4 py-4 min-w-[200px]">Observações</th>
                  <th className="px-4 py-4 text-center min-w-[120px]">Aprovação</th>
                </>
              )}
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {records.length === 0 ? (
              <tr>
                <td colSpan={compact ? 6 : 10} className="px-6 py-8 text-center text-slate-500 animate-fadeInUp">
                  Nenhum registro encontrado neste período.
                </td>
              </tr>
            ) : (
              records.map((record, index) => {
                const isLimitExceeded = record.totalHours > dailyLimit;

                return (
                <tr 
                    key={record.id} 
                    className="hover:bg-slate-50 transition-colors group animate-fadeInUp opacity-0"
                    style={{ animationDelay: `${index * 50}ms` }} // Staggered delay logic
                >
                  {/* Date */}
                  <td className="px-4 py-4 font-medium text-slate-900">
                    <div className="flex flex-col">
                        <span>{formatDate(record.date)}</span>
                        {!compact && <span className="text-[10px] text-slate-400 font-normal uppercase">{new Date(record.date).toLocaleDateString('pt-BR', {weekday: 'short'})}</span>}
                    </div>
                  </td>

                  {/* Times */}
                  <td className="px-4 py-4 text-center text-slate-700 font-mono text-sm">{formatTime(record.startTime)}</td>
                  {!compact && (
                    <td className="px-4 py-4 text-center text-slate-500 text-xs">
                        {record.lunchStartTime && record.lunchEndTime ? (
                            <span className="bg-slate-100 px-2 py-1 rounded-md">
                                {formatTime(record.lunchStartTime)} - {formatTime(record.lunchEndTime)}
                            </span>
                        ) : '-'}
                    </td>
                  )}
                  <td className="px-4 py-4 text-center text-slate-700 font-mono text-sm">{formatTime(record.endTime)}</td>

                  {/* Calculated Hours */}
                  <td className="px-4 py-4 text-center font-bold text-slate-800 bg-indigo-50/30 relative group/cell">
                    <div className="flex items-center justify-center gap-1">
                        {record.totalHours > 0 ? `${record.totalHours.toFixed(2)}h` : '-'}
                        {isLimitExceeded && (
                            <AlertCircle className="w-4 h-4 text-red-500 animate-pulse" />
                        )}
                    </div>
                    {isLimitExceeded && (
                        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 hidden group-hover/cell:block bg-red-600 text-white text-[10px] py-1 px-2 rounded shadow-lg whitespace-nowrap z-10">
                            Excedeu limite de {dailyLimit}h
                        </div>
                    )}
                  </td>

                  {/* Overtime */}
                  <td className="px-4 py-4 text-center font-medium">
                    {record.overtimeHours > 0 ? (
                        <div className="flex items-center justify-center">
                            <span className="text-emerald-600 bg-emerald-50 px-2 py-1 rounded border border-emerald-100 flex items-center gap-1">
                                +{record.overtimeHours.toFixed(2)}h
                                <AlertTriangle className="w-3 h-3 text-amber-500" />
                            </span>
                        </div>
                    ) : '-'}
                  </td>

                  {/* Earnings Value */}
                  {!compact && (
                      <td className="px-4 py-4 text-center font-bold text-emerald-700 bg-emerald-50/30">
                        {record.estimatedEarnings && record.estimatedEarnings > 0 
                            ? `R$ ${record.estimatedEarnings.toFixed(2)}` 
                            : '-'}
                      </td>
                  )}

                  {/* Balance */}
                  <td className="px-4 py-4 text-center font-medium">
                    {record.balanceHours !== 0 ? (
                         <span className={`${record.balanceHours > 0 ? 'text-blue-600' : 'text-red-500'}`}>
                            {record.balanceHours > 0 ? '+' : ''}{record.balanceHours.toFixed(2)}h
                         </span>
                    ) : '-'}
                  </td>

                  {/* Extended Controls */}
                  {!compact && (
                    <>
                        {/* Observations Input */}
                        <td className="px-4 py-3">
                            <div className="relative">
                                <FileText className="absolute top-2.5 left-2 w-4 h-4 text-slate-400 pointer-events-none" />
                                <textarea 
                                    className="w-full bg-white border border-slate-200 rounded-md py-2 pl-8 pr-2 text-xs text-slate-800 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all resize-none overflow-hidden placeholder:text-slate-300 min-h-[38px] hover:border-slate-300"
                                    placeholder="Adicionar nota..."
                                    rows={1}
                                    value={record.notes || ''}
                                    onChange={(e) => onUpdateNote(record.id, e.target.value)}
                                    onFocus={(e) => e.target.rows = 3}
                                    onBlur={(e) => e.target.rows = 1}
                                />
                            </div>
                        </td>

                        {/* Approval Manager */}
                        <td className="px-4 py-4 text-center">
                            {record.overtimeHours > 0 ? (
                                <button 
                                    onClick={() => onToggleApproval(record.id)}
                                    title="Clique para alterar status (Simulação Gestor)"
                                    className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold border transition-all ${
                                        record.isOvertimeApproved === true 
                                            ? 'bg-green-100 text-green-700 border-green-200 hover:bg-green-200' 
                                        : record.isOvertimeApproved === false
                                            ? 'bg-red-50 text-red-700 border-red-200 hover:bg-red-100'
                                        : 'bg-amber-50 text-amber-700 border-amber-200 hover:bg-amber-100'
                                    }`}
                                >
                                    {record.isOvertimeApproved === true && <Check className="w-3 h-3" />}
                                    {record.isOvertimeApproved === false && <X className="w-3 h-3" />}
                                    {record.isOvertimeApproved === null && <CircleDashed className="w-3 h-3" />}

                                    {record.isOvertimeApproved === true ? 'Aprovado' : 
                                     record.isOvertimeApproved === false ? 'Rejeitado' : 'Pendente'}
                                </button>
                            ) : (
                                <span className="text-slate-300 text-xs">-</span>
                            )}
                        </td>
                    </>
                  )}
                </tr>
              )})}
            )}
          </tbody>

          {/* Footer Totals */}
          {!compact && records.length > 0 && (
              <tfoot className="bg-slate-50 font-bold text-slate-700 border-t-2 border-slate-200 animate-fadeInUp opacity-0" style={{ animationDelay: '300ms' }}>
                  <tr>
                      <td colSpan={4} className="px-4 py-4 text-right text-xs uppercase tracking-wide text-slate-500">Totais do Período:</td>
                      <td className="px-4 py-4 text-center bg-indigo-100/50 text-indigo-900">{totalWorked.toFixed(2)}h</td>
                      <td className="px-4 py-4 text-center text-emerald-700">
                          <div className="flex items-center justify-center gap-1">
                            +{totalOvertime.toFixed(2)}h
                            {totalOvertime > 0 && <AlertTriangle className="w-3.5 h-3.5 text-amber-500" />}
                          </div>
                      </td>
                      <td className="px-4 py-4 text-center bg-emerald-100/50 text-emerald-800">R$ {totalEarnings.toFixed(2)}</td>
                      <td className={`px-4 py-4 text-center ${totalBalance >= 0 ? 'text-blue-700' : 'text-red-600'}`}>
                        {totalBalance > 0 ? '+' : ''}{totalBalance.toFixed(2)}h
                      </td>
                      <td colSpan={2} className="px-4 py-4 text-left text-xs text-slate-400 font-normal">
                          *Aprovação necessária apenas para Extras
                      </td>
                  </tr>
              </tfoot>
          )}
        </table>
      </div>
    </div>
  );
};

