                  <button onClick={() => setIsOvertimeModalOpen(true)} className="flex items-center gap-2 bg-indigo-50 text-indigo-700 border border-indigo-100 hover:bg-indigo-100 px-3 py-2 rounded-lg text-sm font-bold transition-colors shadow-sm">
