import React, { useState, useEffect, useMemo, useRef } from 'react';
import { TimeClock } from './components/TimeClock';
import { TimeHistory } from './components/TimeHistory';
import { Dashboard } from './components/Dashboard';
import { EmployeeModal } from './components/EmployeeModal';
import { HolidaysModal } from './components/HolidaysModal';
import { Login } from './components/Login'; 
import { LoginHistory } from './components/LoginHistory';
import { CloudConfigModal } from './components/CloudConfigModal'; 
import { Logo } from './components/Logo';
import { TimeRecord, RecordType, Employee, WorkSchedule, LoginEvent, SystemRole, Holiday } from './types';
import { analyzeTimesheet } from './services/geminiService';
import { exportToCSV, exportToPDF } from './services/exportService';
import { requestNotificationPermission, sendNotification } from './services/notificationService';
import { calculateRecordTotals } from './services/calculationService';
import { dataService } from './services/dataService';
import { Sparkles, CalendarDays, BarChart3, LogOut, Loader2, FileSpreadsheet, FileText, PlusCircle, Check, Pencil, Trash2, Database, Filter, XCircle, Bell, Menu, X, Clock, AlarmClock, Shield, Flag, Settings } from 'lucide-react';

// Hardcoded Admin Credentials
const ADMIN_CREDENTIALS = {
  username: 'admin',
  password: 'admin1234'
};

const StatCard: React.FC<{title: string, value: string, color: string, delay?: number}> = ({ title, value, color, delay = 0 }) => (
  <div className={`bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex items-center gap-4 animate-fadeInUp ${delay > 0 ? 'opacity-0' : ''}`} style={{ animationDelay: `${delay}ms` }}>
      <div className={`w-2 h-12 rounded-full ${color}`}></div>
      <div>
          <p className="text-sm font-medium text-slate-500">{title}</p>
          <p className="text-2xl font-bold text-slate-800">{value}</p>
      </div>
  </div>
);

const App: React.FC = () => {
  // Authentication State
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [userRole, setUserRole] = useState<SystemRole>('COLLABORATOR'); // Default role
  const [loginError, setLoginError] = useState<string | null>(null);

  const [records, setRecords] = useState<TimeRecord[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [loginEvents, setLoginEvents] = useState<LoginEvent[]>([]);
  const [holidays, setHolidays] = useState<Holiday[]>([]);

  const [currentEmployeeId, setCurrentEmployeeId] = useState<string>('');
  const [isLoadingData, setIsLoadingData] = useState(true);

  const [activeTab, setActiveTab] = useState<'ponto' | 'historico' | 'dashboard' | 'logins'>('ponto');
  const [loadingAI, setLoadingAI] = useState(false);
  const [aiInsight, setAiInsight] = useState<string | null>(null);

  // Notification / Alert State
  const [activeAlert, setActiveAlert] = useState<{title: string, message: string} | null>(null);

  // Date Filter State
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  const [isEmployeeModalOpen, setIsEmployeeModalOpen] = useState(false);
  const [isHolidaysModalOpen, setIsHolidaysModalOpen] = useState(false);
  const [isCloudModalOpen, setIsCloudModalOpen] = useState(false); 
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

  // Notification References
  const currentRecordRef = useRef<TimeRecord | null>(null);
  const lastNotificationTimeRef = useRef<string | null>(null);
  const snoozeTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Derived Access Levels
  const isAdmin = userRole === 'ADMIN';
  const isManager = userRole === 'ADMIN' || userRole === 'MANAGER';

  // Initialization Logic (Subscriptions)
  useEffect(() => {
    setIsLoadingData(true);

    // Setup Realtime Listeners (Local)
    const unsubEmployees = dataService.subscribeToEmployees((data) => {
        setEmployees(data);
        // Default selection logic: if no current user, select first available
        if (data.length > 0) {
            setCurrentEmployeeId(prev => prev || data[0].id);
        }
    });

    const unsubRecords = dataService.subscribeToRecords((data) => {
        setRecords(data);
    });

    const unsubHolidays = dataService.subscribeToHolidays((data) => {
        setHolidays(data);
    });

    // Remove loading state shortly
    const timer = setTimeout(() => setIsLoadingData(false), 500);

    return () => {
        unsubEmployees();
        unsubRecords();
        unsubHolidays();
        clearTimeout(timer);
    };
  }, []);

  // Fetch login history when admin tab is active
  useEffect(() => {
    if (isAdmin && activeTab === 'logins') {
        const fetchLogins = async () => {
            const events = await dataService.getLoginEvents();
            setLoginEvents(events);
        };
        fetchLogins();
    }
  }, [isAdmin, activeTab]);

  // Derived State
  const currentEmployee = employees.find(e => e.id === currentEmployeeId);

  const currentUserRecords = useMemo(() => {
    return records.filter(r => r.employeeId === currentEmployeeId);
  }, [records, currentEmployeeId]);

  const filteredRecords = useMemo(() => {
    return currentUserRecords.filter(r => {
      if (!startDate && !endDate) return true;
      if (startDate && r.date < startDate) return false;
      if (endDate && r.date > endDate) return false;
      return true;
    });
  }, [currentUserRecords, startDate, endDate]);

  const todayStr = new Date().toISOString().split('T')[0];
  const currentDayRecord = currentUserRecords.find(r => r.date === todayStr) || null;

  // Update Ref for Scheduler
  useEffect(() => {
    currentRecordRef.current = currentDayRecord;
  }, [currentDayRecord]);

  // --- AUTH HANDLERS ---
  const handleLogin = async (username: string, pass: string) => {
    setLoginError(null);

    const timestamp = new Date().toISOString();

    // Check Hardcoded Super Admin
    if (username === ADMIN_CREDENTIALS.username && pass === ADMIN_CREDENTIALS.password) {
        setIsAuthenticated(true);
        setUserRole('ADMIN');
        if (employees.length > 0 && !currentEmployeeId) {
            setCurrentEmployeeId(employees[0].id);
        }

        // Log Admin Login
        const loginEvent: LoginEvent = {
            id: crypto.randomUUID(),
            employeeId: 'admin',
            employeeName: 'Super Administrador',
            timestamp
        };
        await dataService.saveLoginEvent(loginEvent);

        requestNotificationPermission();
        return;
    }

    // Check Employees
    const foundEmployee = employees.find(e => e.username === username && e.password === pass);
    if (foundEmployee) {
        setIsAuthenticated(true);
        setUserRole(foundEmployee.systemRole || 'COLLABORATOR');
        setCurrentEmployeeId(foundEmployee.id);

        // Log User Login
        const loginEvent: LoginEvent = {
            id: crypto.randomUUID(),
            employeeId: foundEmployee.id,
            employeeName: foundEmployee.name,
            timestamp
        };
        await dataService.saveLoginEvent(loginEvent);

        requestNotificationPermission();
        return;
    }

    setLoginError("Usuário ou senha incorretos.");
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setUserRole('COLLABORATOR');
    setLoginError(null);
    setAiInsight(null);
    setActiveTab('ponto');
    if (snoozeTimeoutRef.current) clearTimeout(snoozeTimeoutRef.current);
  };

  // --- APP LOGIC ---

  const triggerReminder = (title: string, message: string) => {
      // 1. Native System Notification
      sendNotification(title, message, { tag: 'time-reminder' });

      // 2. In-App Banner (for snooze control)
      setActiveAlert({ title, message });
  };

  // Notification Scheduler (Existing code)
  useEffect(() => {
    if (!isAuthenticated || !currentEmployee) return;

    const checkReminders = () => {
      const now = new Date();
      // Format: "HH:MM"
      const timeString = now.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });

      // Prevent double firing within same minute loop if not a snooze re-trigger
      if (lastNotificationTimeRef.current === timeString) return;

      const record = currentRecordRef.current;
      const schedule = currentEmployee?.workSchedule || { startTime: '09:00', endTime: '18:00', lunchDuration: 60 };

      // START TIME REMINDER: Only if haven't started yet
      if (timeString === schedule.startTime && (!record || !record.startTime)) {
          triggerReminder(
              `Lembrete de Entrada: ${schedule.startTime}`, 
              `Olá ${currentEmployee.name}, já são ${schedule.startTime}. Hora de registrar sua entrada!`
          );
          lastNotificationTimeRef.current = timeString;
      } 
      // END TIME REMINDER: Only if started but not finished
      else if (timeString === schedule.endTime && (record && record.startTime && !record.endTime)) {
          triggerReminder(
              `Lembrete de Saída: ${schedule.endTime}`, 
              `Atenção ${currentEmployee.name}, seu expediente encerra às ${schedule.endTime}. Não esqueça de bater o ponto.`
          );
          lastNotificationTimeRef.current = timeString;
      }
    };

    // Check every 10 seconds to ensure we hit the minute change
    const interval = setInterval(checkReminders, 10000);
    return () => clearInterval(interval);
  }, [currentEmployee, isAuthenticated]);

  const handleSnooze = (minutes: number) => {
    setActiveAlert(null); // Hide UI immediately
    if (snoozeTimeoutRef.current) clearTimeout(snoozeTimeoutRef.current);
    snoozeTimeoutRef.current = setTimeout(() => {
        const record = currentRecordRef.current;
        const schedule = currentEmployee?.workSchedule;
        if (!schedule) return;
        if (!record || !record.startTime) {
             triggerReminder(`Lembrete de Entrada (Soneca)`, `Lembrete adiado: Você ainda não registrou sua entrada de ${schedule.startTime}.`);
        } 
        else if (record.startTime && !record.endTime) {
             const now = new Date();
             const [endH, endM] = schedule.endTime.split(':').map(Number);
             if (now.getHours() > endH || (now.getHours() === endH && now.getMinutes() >= endM)) {
                 triggerReminder(`Lembrete de Saída (Soneca)`, `Lembrete adiado: Já passou do seu horário (${schedule.endTime}).`);
             }
        }
    }, minutes * 60 * 1000);
  };

  const handleDismissAlert = () => {
      setActiveAlert(null);
      if (snoozeTimeoutRef.current) clearTimeout(snoozeTimeoutRef.current);
  };

  const handleEnableNotifications = async () => {
    const granted = await requestNotificationPermission();
    if (granted) {
      sendNotification("Notificações Ativadas", "Você receberá lembretes de ponto.");
    } else {
      alert("É necessário permitir notificações no navegador. Verifique as configurações do site.");
    }
  };

  const handleSetCurrentMonth = () => {
    const now = new Date();
    const firstDay = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
    const lastDay = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().split('T')[0];
    setStartDate(firstDay);
    setEndDate(lastDay);
  };

  const handleClearFilter = () => {
    setStartDate('');
    setEndDate('');
  };

  const handleSaveEmployee = async (name: string, role: string, systemRole: SystemRole, schedule: WorkSchedule, auth?: {username: string, password: string}) => {
    const initials = name.split(' ').map(n => n[0]).join('').substring(0, 2).toUpperCase();

    let newEmployeeData: Employee;

    if (editingEmployee) {
      const updatedEmployees = employees.map(emp => 
        emp.id === editingEmployee.id 
          ? { ...emp, name, role, systemRole, avatarInitials: initials, workSchedule: schedule, ...auth }
          : emp
      );
      setEmployees(updatedEmployees);
      newEmployeeData = updatedEmployees.find(e => e.id === editingEmployee.id)!;
      setEditingEmployee(null);
    } else {
      const newEmployee: Employee = {
        id: crypto.randomUUID(),
        name,
        role,
        systemRole,
        avatarInitials: initials,
        workSchedule: schedule,
        ...auth
      };
      const updatedEmployees = [...employees, newEmployee];
      setEmployees(updatedEmployees);
      if (!isManager) {
          setCurrentEmployeeId(newEmployee.id);
      }
      newEmployeeData = newEmployee;
    }
    await dataService.saveEmployee(newEmployeeData);
    setIsEmployeeModalOpen(false);
  };

  const handleEditEmployee = (e: React.MouseEvent, emp: Employee) => {
    e.stopPropagation();
    setEditingEmployee(emp);
    setIsEmployeeModalOpen(true);
    setIsUserMenuOpen(false);
  };

  const handleDeleteEmployee = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (!isAdmin) {
        alert("Apenas administradores podem excluir colaboradores.");
        return;
    }
    if (employees.length <= 1) {
      alert("Você não pode excluir o último colaborador.");
      return;
    }
    if (window.confirm("Tem certeza? Todos os registros de ponto deste colaborador serão excluídos permanentemente.")) {
      const updatedEmployees = employees.filter(emp => emp.id !== id);
      setEmployees(updatedEmployees);
      const updatedRecords = records.filter(r => r.employeeId !== id);
      setRecords(updatedRecords);
      await dataService.deleteEmployee(id);
      await dataService.deleteRecordsByEmployee(id);
      if (currentEmployeeId === id) {
        setCurrentEmployeeId(updatedEmployees[0].id);
        setAiInsight(null);
      }
    }
  };

  const handleSaveHoliday = async (date: string, name: string) => {
    const newHoliday: Holiday = {
        id: crypto.randomUUID(),
        date,
        name
    };
    const updatedHolidays = [...holidays, newHoliday];
    setHolidays(updatedHolidays);
    await dataService.saveHoliday(newHoliday);
  };

  const handleDeleteHoliday = async (id: string) => {
    if(window.confirm("Remover este feriado?")) {
        setHolidays(prev => prev.filter(h => h.id !== id));
        await dataService.deleteHoliday(id);
    }
  };

  const handlePunch = async (type: RecordType) => {
    if (!currentEmployeeId) return;
    if (snoozeTimeoutRef.current) clearTimeout(snoozeTimeoutRef.current);
    setActiveAlert(null);

    const now = new Date().toISOString();
    let updatedRecords = [...records];
    let recordIndex = updatedRecords.findIndex(r => r.employeeId === currentEmployeeId && r.date === todayStr);
    let record = recordIndex >= 0 ? updatedRecords[recordIndex] : null;

    if (!record) {
      record = {
        id: crypto.randomUUID(),
        employeeId: currentEmployeeId,
        date: todayStr,
        startTime: null,
        lunchStartTime: null,
        lunchEndTime: null,
        endTime: null,
        totalHours: 0,
        overtimeHours: 0,
        balanceHours: 0,
        isOvertimeApproved: null,
        status: 'ABERTO',
        notes: ''
      };
      updatedRecords.unshift(record);
      recordIndex = 0; 
    } else {
      record = { ...record };
      updatedRecords[recordIndex] = record;
    }

    switch (type) {
      case RecordType.ENTRY:
        record.startTime = now;
        record.status = 'ABERTO';
        break;
      case RecordType.LUNCH_START:
        record.lunchStartTime = now;
        break;
      case RecordType.LUNCH_END:
        record.lunchEndTime = now;
        break;
      case RecordType.EXIT:
        record.endTime = now;
        record.status = 'COMPLETO';
        if (record.startTime && record.endTime) {
            record = calculateRecordTotals(record, currentEmployee?.workSchedule, holidays);
            updatedRecords[recordIndex] = record;
        }
        break;
    }
    setRecords(updatedRecords);
    await dataService.saveRecord(record);
  };

  const handleUpdateNote = async (id: string, note: string) => {
    let targetRecord: TimeRecord | undefined;
    const updatedRecords = records.map(r => {
        if (r.id === id) {
            targetRecord = { ...r, notes: note };
            return targetRecord;
        }
        return r;
    });
    setRecords(updatedRecords);
    if (targetRecord) await dataService.saveRecord(targetRecord);
  };

  const handleToggleApproval = async (id: string) => {
    if (!isManager) return; 
    let targetRecord: TimeRecord | undefined;
    const updatedRecords = records.map(r => {
      if (r.id === id) {
        let newStatus: boolean | null = null;
        if (r.isOvertimeApproved === null) newStatus = true;
        else if (r.isOvertimeApproved === true) newStatus = false;
        else newStatus = null;
        targetRecord = { ...r, isOvertimeApproved: newStatus };
        return targetRecord;
      }
      return r;
    });
    setRecords(updatedRecords);
    if (targetRecord) await dataService.saveRecord(targetRecord);
  };

  const handleAnalyzeAI = async () => {
    setLoadingAI(true);
    setAiInsight(null);
    const feedback = await analyzeTimesheet(filteredRecords.slice(0, 10));
    setAiInsight(feedback);
    setLoadingAI(false);
  };

  const switchUser = (id: string) => {
    if (!isManager) return;
    setCurrentEmployeeId(id);
    setAiInsight(null);
    setIsUserMenuOpen(false);
    setActiveTab('ponto');
  };

  // --- RENDER ---
  if (isLoadingData) {
      return (
          <div className="min-h-screen flex flex-col items-center justify-center gap-4 bg-slate-50">
              <Loader2 className="animate-spin w-10 h-10 text-indigo-600"/>
              <p className="text-slate-500 font-medium">Carregando sistema...</p>
          </div>
      );
  }

  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} error={loginError} />;
  }

  if (!currentEmployee && !isAdmin) return <div className="min-h-screen flex items-center justify-center"><Loader2 className="animate-spin w-8 h-8 text-indigo-600"/></div>;

  const displayName = currentEmployee?.name || (isAdmin ? "Super Administrador" : "Usuário");
  const displayRole = currentEmployee?.role || (isAdmin ? "Acesso Total" : "");
  const displayInitials = currentEmployee?.avatarInitials || (isAdmin ? "AD" : "US");

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">

      {/* ALERTS */}
      {activeAlert && (
        <div className="fixed top-14 md:top-4 left-1/2 transform -translate-x-1/2 z-[100] w-[90%] max-w-md animate-bounce-in">
          <div className="bg-gradient-to-r from-amber-50 to-orange-50 border border-amber-200 p-4 rounded-xl shadow-2xl flex flex-col items-center gap-3">
            <div className="flex items-center gap-3 w-full">
                <div className="bg-amber-100 p-2 rounded-full shrink-0">
                    <AlarmClock className="w-6 h-6 text-amber-600" />
                </div>
                <div className="flex-1">
                    <h4 className="font-bold text-amber-900 text-sm">{activeAlert.title}</h4>
                    <p className="text-xs text-amber-800 leading-snug">{activeAlert.message}</p>
                </div>
                <button 
                    onClick={handleDismissAlert}
                    className="p-1 text-amber-400 hover:text-amber-800 rounded-full hover:bg-amber-100"
                >
                    <X className="w-5 h-5" />
                </button>
            </div>

            <div className="flex gap-2 w-full pt-1 border-t border-amber-100/50">
               <span className="text-[10px] font-semibold text-amber-700 uppercase tracking-wide py-1.5 px-1">Adiar por:</span>
               <button onClick={() => handleSnooze(5)} className="flex-1 flex items-center justify-center gap-1 bg-white border border-amber-200 text-amber-700 py-1 rounded-md text-xs font-bold hover:bg-amber-100 transition-colors">5m</button>
               <button onClick={() => handleSnooze(10)} className="flex-1 flex items-center justify-center gap-1 bg-white border border-amber-200 text-amber-700 py-1 rounded-md text-xs font-bold hover:bg-amber-100 transition-colors">10m</button>
               <button onClick={() => handleSnooze(15)} className="flex-1 flex items-center justify-center gap-1 bg-white border border-amber-200 text-amber-700 py-1 rounded-md text-xs font-bold hover:bg-amber-100 transition-colors">15m</button>
            </div>
          </div>
        </div>
      )}

      {isMobileMenuOpen && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-40 md:hidden animate-fadeIn" onClick={() => setIsMobileMenuOpen(false)} />
      )}

      {/* Sidebar */}
      <aside className={`
        fixed top-0 left-0 h-full z-50 w-72 bg-indigo-900 text-white shadow-2xl flex flex-col transition-transform duration-300 ease-in-out
        md:fixed md:w-64 md:translate-x-0
        ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-6 border-b border-indigo-800 flex justify-between items-center">
           <Logo variant="light" />
           <button onClick={() => setIsMobileMenuOpen(false)} className="md:hidden text-indigo-300 hover:text-white">
             <X className="w-6 h-6" />
           </button>
        </div>

        <nav className="p-4 space-y-2 flex-1">
          {/* Cloud Status Indicator / Trigger */}
          <button 
             onClick={() => { setIsCloudModalOpen(true); setIsMobileMenuOpen(false); }}
             className="w-full px-4 py-3 mb-4 rounded-lg text-xs font-semibold flex items-center gap-2 transition-all bg-indigo-800 text-indigo-100 hover:bg-indigo-700 hover:text-white"
          >
               <Database className="w-4 h-4" />
               <div className="flex flex-col items-start">
                   <span>Backup & Dados</span>
                   <span className="text-[10px] opacity-70 font-normal">Gerenciar localmente</span>
               </div>
          </button>

          <button
            onClick={() => { setActiveTab('ponto'); setIsMobileMenuOpen(false); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${
              activeTab === 'ponto' ? 'bg-indigo-700 text-white shadow-md font-semibold' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'
            }`}
          >
            <Clock className="w-5 h-5" />
            Bater Ponto
          </button>

          <button
            onClick={() => { setActiveTab('historico'); setIsMobileMenuOpen(false); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${
              activeTab === 'historico' ? 'bg-indigo-700 text-white shadow-md font-semibold' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'
            }`}
          >
            <CalendarDays className="w-5 h-5" />
            Folha de Ponto
          </button>

           <button
            onClick={() => { setActiveTab('dashboard'); setIsMobileMenuOpen(false); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${
              activeTab === 'dashboard' ? 'bg-indigo-700 text-white shadow-md font-semibold' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'
            }`}
          >
            <BarChart3 className="w-5 h-5" />
            Relatórios
          </button>

          {isManager && (
            <div className="pt-6 mt-6 border-t border-indigo-800">
                <p className="px-4 text-xs font-semibold text-indigo-400 uppercase tracking-wider mb-2">Administração</p>
                {isAdmin && (
                    <>
                    <button onClick={() => { setIsHolidaysModalOpen(true); setIsMobileMenuOpen(false); }} className="w-full flex items-center gap-3 px-4 py-2 text-indigo-200 hover:bg-indigo-800 hover:text-white rounded-lg transition-all text-sm">
                        <Flag className="w-4 h-4" />
                        Gerenciar Feriados
                    </button>
                    <button onClick={() => { setActiveTab('logins'); setIsMobileMenuOpen(false); }} className={`w-full flex items-center gap-3 px-4 py-2 rounded-lg transition-all text-sm ${activeTab === 'logins' ? 'bg-indigo-700 text-white shadow-md font-semibold' : 'text-indigo-200 hover:bg-indigo-800 hover:text-white'}`}>
                        <Shield className="w-4 h-4" />
                        Histórico de Acessos
                    </button>
                    </>
                )}
                <button onClick={() => { handleEnableNotifications(); setIsMobileMenuOpen(false); }} className="w-full flex items-center gap-3 px-4 py-2 mt-2 text-indigo-200 hover:bg-indigo-800 hover:text-white rounded-lg transition-all text-sm">
                    <Bell className="w-4 h-4" />
                    Notificações
                </button>
                <button onClick={() => { setIsCloudModalOpen(true); setIsMobileMenuOpen(false); }} className="w-full flex items-center gap-3 px-4 py-2 mt-2 text-indigo-200 hover:bg-indigo-800 hover:text-white rounded-lg transition-all text-sm">
                    <Settings className="w-4 h-4" />
                    Importar / Exportar
                </button>
            </div>
          )}
        </nav>

        {/* User Profile / Switcher Section */}
        <div className="relative border-t border-indigo-800">
            {isUserMenuOpen && isManager && (
                <div className="absolute bottom-full left-0 w-full bg-indigo-800 border-t border-indigo-700 shadow-xl max-h-80 overflow-y-auto animate-fadeIn">
                    <div className="p-2 space-y-1">
                         <div className="px-3 py-2 text-xs font-semibold text-indigo-300 uppercase tracking-wider">Gerenciar Equipe</div>
                        {employees.map(emp => (
                            <div key={emp.id} className="group relative flex items-center rounded-md hover:bg-indigo-700/50 transition-colors pr-2">
                                <button onClick={() => switchUser(emp.id)} className={`flex-1 flex items-center gap-3 px-3 py-2 rounded-md transition-colors text-left ${emp.id === currentEmployeeId ? 'text-white' : 'text-indigo-200'}`}>
                                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold shrink-0 ${emp.id === currentEmployeeId ? 'bg-indigo-500 text-white' : 'bg-indigo-900 border border-indigo-600'}`}>{emp.avatarInitials}</div>
                                    <div className="truncate w-24 sm:w-32"><p className="text-sm font-medium truncate">{emp.name}</p></div>
                                    {emp.id === currentEmployeeId && <Check className="w-4 h-4 ml-auto shrink-0" />}
                                </button>
                                {isAdmin && (
                                    <div className="hidden group-hover:flex items-center gap-1 bg-indigo-800 shadow-sm rounded ml-1">
                                        <button onClick={(e) => handleEditEmployee(e, emp)} className="p-1.5 text-indigo-300 hover:text-white hover:bg-indigo-600 rounded" title="Editar"><Pencil className="w-3.5 h-3.5" /></button>
                                        <button onClick={(e) => handleDeleteEmployee(e, emp.id)} className="p-1.5 text-indigo-300 hover:text-red-400 hover:bg-indigo-600 rounded" title="Excluir"><Trash2 className="w-3.5 h-3.5" /></button>
                                    </div>
                                )}
                            </div>
                        ))}
                        {isAdmin && (
                            <button onClick={() => { setEditingEmployee(null); setIsEmployeeModalOpen(true); setIsUserMenuOpen(false); }} className="w-full flex items-center gap-2 px-3 py-2 mt-2 text-sm text-emerald-300 hover:bg-indigo-700/50 rounded-md transition-colors">
                                <PlusCircle className="w-4 h-4" />
                                Cadastrar Novo
                            </button>
                        )}
                    </div>
                </div>
            )}

            <div className="w-full p-4 flex items-center justify-between hover:bg-indigo-800 transition-colors">
                <div className={`flex items-center gap-3 flex-1 ${isManager ? 'cursor-pointer' : ''}`} onClick={() => isManager && setIsUserMenuOpen(!isUserMenuOpen)}>
                    <div className="w-10 h-10 rounded-full bg-indigo-500 flex items-center justify-center text-white font-bold border-2 border-indigo-400 relative">
                        {displayInitials}
                        {isAdmin && <div className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full border-2 border-indigo-900" title="Admin"></div>}
                        {!isAdmin && isManager && <div className="absolute -top-1 -right-1 w-3 h-3 bg-amber-500 rounded-full border-2 border-indigo-900" title="Gestor"></div>}
                    </div>
                    <div className="flex-1 text-left overflow-hidden">
                        <p className="text-sm font-medium text-white truncate">{displayName}</p>
                        <p className="text-xs text-indigo-300 truncate">{displayRole}</p>
                    </div>
                    {isManager ? (
                         <div className={`w-4 h-4 text-indigo-400 transition-transform ${isUserMenuOpen ? 'rotate-180' : ''}`}>
                             <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M6 9l6 6 6-6"/></svg>
                         </div>
                    ) : null}
                </div>
                <button onClick={handleLogout} className="ml-2 p-2 text-indigo-300 hover:text-white hover:bg-indigo-700 rounded-lg transition-colors" title="Sair"><LogOut className="w-5 h-5" /></button>
            </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 md:ml-64 p-4 md:p-8 overflow-y-auto pb-24 md:pb-8 transition-all">
        <div className="md:hidden flex justify-between items-center mb-6">
            <Logo variant="dark" />
        </div>

        <header className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
            <div>
                <h2 className="text-2xl font-bold text-slate-900">
                    {activeTab === 'ponto' && 'Registro de Ponto'}
                    {activeTab === 'historico' && 'Folha de Ponto Mensal'}
                    {activeTab === 'dashboard' && 'Painel de Indicadores'}
                    {activeTab === 'logins' && 'Histórico de Acessos'}
                </h2>
                <div className="flex flex-wrap items-center gap-x-2 text-slate-500 mt-1">
                    <span className="hidden sm:inline">
                        {new Date().toLocaleDateString('pt-BR', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}
                        <span className="mx-2">•</span>
                    </span>
                    <span className="font-medium text-indigo-600">{displayName}</span>
                    {isAdmin && <span className="text-xs bg-red-50 text-red-600 px-2 py-0.5 rounded-full border border-red-100 ml-1 font-bold">Modo Admin</span>}
                    {!isAdmin && isManager && <span className="text-xs bg-amber-50 text-amber-600 px-2 py-0.5 rounded-full border border-amber-100 ml-1 font-bold">Modo Gestor</span>}
                </div>
            </div>

            <div className="flex flex-wrap items-center gap-3">
              {(activeTab === 'historico' || activeTab === 'dashboard') && filteredRecords.length > 0 && (
                <div className="flex items-center gap-2 mr-2">
                  <button onClick={() => exportToCSV(filteredRecords)} className="flex items-center gap-2 bg-white text-slate-600 border border-slate-200 hover:bg-slate-50 hover:text-slate-900 px-3 py-2 rounded-lg text-sm font-medium transition-colors shadow-sm" title="Exportar CSV"><FileSpreadsheet className="w-4 h-4" /><span className="hidden sm:inline">CSV</span></button>
                  <button onClick={() => exportToPDF(filteredRecords)} className="flex items-center gap-2 bg-white text-slate-600 border border-slate-200 hover:bg-slate-50 hover:text-slate-900 px-3 py-2 rounded-lg text-sm font-medium transition-colors shadow-sm" title="Exportar PDF"><FileText className="w-4 h-4" /><span className="hidden sm:inline">PDF</span></button>
                </div>
              )}
              {activeTab !== 'logins' && (
                  <button onClick={handleAnalyzeAI} disabled={loadingAI || filteredRecords.length === 0} className="hidden md:flex items-center gap-2 bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-700 hover:to-indigo-700 text-white px-5 py-2.5 rounded-full shadow-md transition-all active:scale-95 disabled:opacity-70 disabled:cursor-not-allowed">
                      {loadingAI ? <Loader2 className="w-5 h-5 animate-spin" /> : <Sparkles className="w-5 h-5" />}
                      {loadingAI ? 'Analisando...' : 'Análise com IA'}
                  </button>
              )}
            </div>
        </header>

        {aiInsight && (
            <div className="mb-8 bg-gradient-to-br from-indigo-50 to-purple-50 border border-indigo-100 p-6 rounded-2xl shadow-sm relative animate-fadeIn">
                <button onClick={() => setAiInsight(null)} className="absolute top-4 right-4 text-slate-400 hover:text-slate-600">✕</button>
                <div className="flex items-start gap-4">
                    <div className="bg-white p-2 rounded-lg shadow-sm"><Sparkles className="w-6 h-6 text-purple-600" /></div>
                    <div>
                        <h4 className="font-bold text-indigo-900 mb-2">Insight do Gemini AI ({displayName})</h4>
                        <p className="text-slate-700 leading-relaxed text-sm whitespace-pre-line">{aiInsight}</p>
                    </div>
                </div>
            </div>
        )}

        <div className="max-w-6xl mx-auto">
            {activeTab === 'ponto' && (
                <div className="animate-fadeInUp space-y-8">
                    <TimeClock currentRecord={currentDayRecord} onPunch={handlePunch} />
                    <div className="mt-8">
                        <h3 className="text-lg font-semibold text-slate-800 mb-4">Últimos Registros</h3>
                        <TimeHistory 
                            records={currentUserRecords.slice(0, 3)} 
                            onUpdateNote={handleUpdateNote} 
                            onToggleApproval={handleToggleApproval} 
                            compact 
                            dailyLimit={currentEmployee?.workSchedule?.dailyLimit}
                        />
                    </div>
                </div>
            )}

            {activeTab === 'historico' && (
                <div className="animate-fadeInUp space-y-6">
                  <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col sm:flex-row gap-4 items-end sm:items-center justify-between">
                     <div className="flex flex-col sm:flex-row gap-4 items-end sm:items-center w-full sm:w-auto">
                        <div className="flex items-center gap-2 text-indigo-900 font-semibold mb-1 sm:mb-0"><Filter className="w-5 h-5" /><span>Filtrar Período:</span></div>
                        <div className="flex gap-2 w-full sm:w-auto">
                           <div className="flex-1 sm:w-auto"><label className="block text-xs text-slate-500 mb-1">Início</label><input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="w-full px-3 py-1.5 border border-slate-300 rounded-md text-sm focus:ring-2 focus:ring-indigo-500 focus:outline-none" /></div>
                           <div className="flex-1 sm:w-auto"><label className="block text-xs text-slate-500 mb-1">Fim</label><input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} className="w-full px-3 py-1.5 border border-slate-300 rounded-md text-sm focus:ring-2 focus:ring-indigo-500 focus:outline-none" /></div>
                        </div>
                     </div>
                     <div className="flex gap-2 w-full sm:w-auto justify-end">
                       <button onClick={handleSetCurrentMonth} className="px-3 py-1.5 text-xs font-medium text-indigo-600 bg-indigo-50 hover:bg-indigo-100 rounded-md transition-colors">Mês Atual</button>
                       {(startDate || endDate) && <button onClick={handleClearFilter} className="px-3 py-1.5 text-xs font-medium text-slate-500 hover:text-slate-700 hover:bg-slate-100 rounded-md transition-colors flex items-center gap-1"><XCircle className="w-3.5 h-3.5" />Limpar</button>}
                     </div>
                  </div>
                  <TimeHistory 
                        records={filteredRecords} 
                        onUpdateNote={handleUpdateNote} 
                        onToggleApproval={handleToggleApproval} 
                        dailyLimit={currentEmployee?.workSchedule?.dailyLimit}
                  />
                </div>
