            {activeTab === 'dashboard' && (
                <div className="grid grid-cols-1 gap-6">
                    <Dashboard records={filteredRecords} />
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                         <StatCard title="Total Horas (Geral)" value={`${filteredRecords.reduce((acc, curr) => acc + curr.totalHours, 0).toFixed(1)}h`} color="bg-blue-500" delay={100} />
                         <StatCard title="Total Horas Extras" value={`${filteredRecords.reduce((acc, curr) => acc + (curr.overtimeHours || 0), 0).toFixed(1)}h`} color="bg-emerald-500" delay={200} />
                         <StatCard title="Saldo de Horas" value={`${filteredRecords.reduce((acc, curr) => acc + (curr.balanceHours || 0), 0).toFixed(1)}h`} color="bg-purple-500" delay={300} />
