import { TimeRecord, WorkSchedule, Holiday } from "../types";

// Constantes de Salário e Taxas (Base 2025)
const RATES = {
  NORMAL_HOUR: 6.90,        // R$ 6,90 (Hora normal base)
  OT_STANDARD: 10.35,       // R$ 10,35 (Hora Extra Diurna: Seg-Sab 05:00-22:00)
  OT_NIGHT: 12.42,          // R$ 12,42 (Hora Extra Noturna: 22:00-05:00)
  SUNDAY_NORMAL: 13.80,     // R$ 13,80 (Domingo/Feriado até 8h)
  SUNDAY_OT: 17.25          // R$ 17,25 (Domingo/Feriado após 8h)
};

/**
 * Calcula a diferença em horas entre duas strings de data ISO.
 */
export const getHoursDifference = (startIso: string | null, endIso: string | null): number => {
  if (!startIso || !endIso) return 0;
  const start = new Date(startIso).getTime();
  const end = new Date(endIso).getTime();
  const diffMs = end - start;
  return diffMs / (1000 * 60 * 60);
};

/**
 * Calcula o total de horas trabalhadas baseadas nos registros (Entrada, Saída, Almoço).
 */
export const calculateWorkedHours = (record: TimeRecord): number => {
  if (!record.startTime || !record.endTime) return 0;

  // Duração bruta (Saída - Entrada)
  let totalHours = getHoursDifference(record.startTime, record.endTime);

  // Subtrai almoço se ambos os registros existirem
  if (record.lunchStartTime && record.lunchEndTime) {
    const lunchHours = getHoursDifference(record.lunchStartTime, record.lunchEndTime);
    totalHours -= lunchHours;
  }

  // Verificação de segurança para evitar horas negativas
  return Math.max(0, totalHours);
};

/**
 * Calcula a jornada esperada baseada na escala do colaborador.
 * Lida com turnos que atravessam a meia-noite (ex: 22:00 às 06:00).
 * Se for feriado, a expectativa é 0h.
 */
export const calculateExpectedHours = (schedule?: WorkSchedule, isHoliday: boolean = false): number => {
  if (isHoliday) return 0; 

  if (!schedule) return 8; // Fallback padrão

  const { startTime, endTime, lunchDuration } = schedule;

  const [startH, startM] = startTime.split(':').map(Number);
  const [endH, endM] = endTime.split(':').map(Number);

  const startMinutes = startH * 60 + startM;
  const endMinutes = endH * 60 + endM;

  let totalWorkMinutes = endMinutes - startMinutes;

  // Ajuste para turno noturno (ex: termina no dia seguinte)
  if (totalWorkMinutes < 0) {
    totalWorkMinutes += 24 * 60;
  }

  // Subtrai duração do almoço
  totalWorkMinutes -= lunchDuration;

  return totalWorkMinutes / 60;
};

/**
 * Calcula o valor financeiro das horas extras com precisão de turno (Dia vs Noite).
 * 
 * Regras aplicadas:
 * - Horas Extras são consideradas as *últimas* horas trabalhadas do dia.
 * - Domingos/Feriados: Taxas especiais (R$ 13,80 e R$ 17,25).
 * - Dias Úteis/Sábados:
 *    - Período Diurno (05:00 às 22:00): R$ 10,35
 *    - Período Noturno (22:00 às 05:00): R$ 12,42
 */
export const calculateOvertimeValue = (record: TimeRecord, overtimeHours: number, isHoliday: boolean = false): number => {
  if (overtimeHours <= 0 || !record.endTime) return 0;

  const [y, m, d] = record.date.split('-').map(Number);
  // Cria data localmente para verificar dia da semana corretamente
  const localDate = new Date(y, m - 1, d);
  const dayOfWeek = localDate.getDay(); // 0 = Domingo, 6 = Sábado

  const isSunday = dayOfWeek === 0;

  // --- LÓGICA DOMINGO E FERIADO ---
  if (isSunday || isHoliday) {
    const otStart = record.totalHours - overtimeHours;
    const otEnd = record.totalHours;

    // Horas acima de 8h pagam taxa cheia (R$ 17.25)
    // Intersecção com [8, Infinity]
    const highRateStart = Math.max(otStart, 8);
    const highRateEnd = otEnd;
    const highRateHours = Math.max(0, highRateEnd - highRateStart);

    // O restante das horas paga taxa de domingo normal (R$ 13.80)
    const lowRateHours = Math.max(0, overtimeHours - highRateHours);

    return (highRateHours * RATES.SUNDAY_OT) + (lowRateHours * RATES.SUNDAY_NORMAL);
  }

  // --- LÓGICA DIAS ÚTEIS E SÁBADOS (DIA vs NOITE) ---
  let earnings = 0;

  // Definimos o intervalo de tempo exato que corresponde às Horas Extras.
  // Assumimos que a HE acontece no final do expediente (antes do registro de saída).
  const endMs = new Date(record.endTime).getTime();
  const startMs = endMs - (overtimeHours * 60 * 60 * 1000);

  let currentMs = startMs;

  // Itera sobre o período da hora extra saltando de fronteira em fronteira (Mudança de turno ou fim do período)
  while (currentMs < endMs) {
    const currentDate = new Date(currentMs);
    const hour = currentDate.getHours();

    // Definição de Noite: 22:00 <= hora < 05:00 (do dia seguinte) OU 00:00 <= hora < 05:00
    // Simplificando: Hora >= 22 OU Hora < 5
    const isNight = hour >= 22 || hour < 5;

    // Determina o próximo limite de horário (fronteira de taxa)
    const nextBoundary = new Date(currentDate);
    nextBoundary.setMinutes(0, 0, 0);
    nextBoundary.setSeconds(0);
    nextBoundary.setMilliseconds(0);

    if (isNight) {
      // Se é noite...
      if (hour >= 22) {
        // ... e antes da meia noite, a fronteira é amanhã às 05:00
        nextBoundary.setDate(nextBoundary.getDate() + 1);
        nextBoundary.setHours(5);
      } else {
        // ... e depois da meia noite, a fronteira é hoje às 05:00
        nextBoundary.setHours(5);
      }
    } else {
      // Se é dia (05:00 às 22:00), a fronteira é hoje às 22:00
      nextBoundary.setHours(22);
    }

    const boundaryMs = nextBoundary.getTime();

    // O segmento atual vai até a próxima fronteira OU até o fim da hora extra (o que vier primeiro)
    const segmentEndMs = Math.min(boundaryMs, endMs);

    // Calcula duração deste segmento em horas
    const durationHours = (segmentEndMs - currentMs) / (1000 * 60 * 60);

    if (durationHours > 0) {
      const rate = isNight ? RATES.OT_NIGHT : RATES.OT_STANDARD;
      earnings += durationHours * rate;
    }

    // Avança o ponteiro
    currentMs = segmentEndMs;

    // Evita loop infinito em casos extremos de precisão
    if (durationHours <= 0 && currentMs < endMs) {
        currentMs += 1000; // Avança 1 segundo forçado se travar
    }
  }

  return earnings;
};

/**
 * Atualiza um registro com totais calculados, saldos e valores estimados.
 */
export const calculateRecordTotals = (record: TimeRecord, schedule?: WorkSchedule, holidays: Holiday[] = []): TimeRecord => {
  const totalHours = calculateWorkedHours(record);

  const [y, m, d] = record.date.split('-').map(Number);
  const localDate = new Date(y, m - 1, d);
  const dayOfWeek = localDate.getDay(); // 0 = Domingo, 6 = Sábado

  // Verifica feriados
  const isHoliday = holidays.some(h => h.date === record.date);
  const isSunday = dayOfWeek === 0;

  // Se Domingo ou Feriado, a meta é 0h, então tudo é Extra/Saldo positivo.
  const targetHours = (isSunday || isHoliday) ? 0 : calculateExpectedHours(schedule, isHoliday);

  const balanceHours = totalHours - targetHours;
  const overtimeHours = Math.max(0, balanceHours);

  // Chama a função refatorada para cálculo financeiro
  const estimatedEarnings = calculateOvertimeValue(record, overtimeHours, isHoliday);

  return {
    ...record,
    totalHours,
    balanceHours,
    overtimeHours,
    estimatedEarnings
  };
};

import { db } from "./firebase";
import { 
  collection, 
  onSnapshot, 
  doc, 
  setDoc, 
  deleteDoc, 
  query, 
  orderBy,
  getDocs,
  disableNetwork
} from "firebase/firestore";
import { Employee, TimeRecord, LoginEvent, Holiday } from "../types";
import { getBrazilianHolidays } from "./holidayUtils";

// --- HELPERS PARA LOCAL STORAGE (Fallback & Cache) ---
const getLocal = (key: string) => {
    try {
        const item = localStorage.getItem(key);
        return item ? JSON.parse(item) : [];
    } catch (e) {
        console.error(`Erro ao ler cache local (${key}):`, e);
        return [];
    }
};

const setLocal = (key: string, data: any) => {
    try {
        localStorage.setItem(key, JSON.stringify(data));
    } catch (e) {
        console.error(`Erro ao salvar cache local (${key}):`, e);
    }
};

// Variável para controlar pausas manuais na sincronização (se houver erro de rede)
let isPaused = false;

// Função auxiliar para desligar a rede do Firebase silenciosamente
const goOffline = async () => {
    if (isPaused) return;
    isPaused = true;
    if (db) {
        try {
            await disableNetwork(db);
            console.log("Modo Offline ativado: Conexão com Firebase encerrada.");
        } catch (e) {
            console.warn("Não foi possível desativar a rede Firestore:", e);
        }
    }
};

export const dataService = {

  isBackendPaused: () => isPaused,

  resumeBackend: () => {
    isPaused = false;
    window.location.reload();
  },

  // --- SUBSCRIPTIONS (TEMPO REAL + CACHE) ---

  subscribeToEmployees(callback: (data: Employee[]) => void): () => void {
    // 1. ESTRATÉGIA CACHE-FIRST: Carrega dados locais imediatamente
    const cached = getLocal('employees');
    if (cached && cached.length > 0) {
        callback(cached);
    }

    if (db && !isPaused) {
      try {
        const q = query(collection(db, "employees"));
        return onSnapshot(q, (snapshot) => {
          const employees = snapshot.docs.map(doc => doc.data() as Employee);

          // Se não houver funcionários no banco (nem no cache), cria o padrão
          if (employees.length === 0 && (!cached || cached.length === 0)) {
             this.seedInitialEmployee();
          } else if (employees.length > 0) {
             // Atualiza UI com dados frescos da nuvem
             callback(employees);
             // Atualiza Cache
             setLocal('employees', employees); 
          }
        }, (error) => {
          console.warn("Firebase indisponível ou API desabilitada. Mudando para modo offline.", error.code);
          goOffline(); // Desliga rede para parar erros

          // Se falhar e não tivermos carregado cache antes (ex: cache vazio), tenta agora
          if (!cached || cached.length === 0) callback(getLocal('employees'));
        });
      } catch (e) {
        console.error(e);
        goOffline();
        if (!cached || cached.length === 0) callback(getLocal('employees'));
        return () => {};
      }
    } else {
      // Modo Offline/Local Exclusivo
      if (!cached || cached.length === 0) {
          this.seedInitialEmployee().then(seeded => callback(seeded));
      } else {
          callback(cached);
      }
      return () => {};
    }
  },

  subscribeToRecords(callback: (data: TimeRecord[]) => void): () => void {
    // 1. CACHE-FIRST
    const cached = getLocal('timeRecords');
    if (cached && cached.length > 0) {
        callback(cached);
    }

    if (db && !isPaused) {
        const q = query(collection(db, "timeRecords"), orderBy("date", "desc"));
        return onSnapshot(q, (snapshot) => {
            const records = snapshot.docs.map(doc => doc.data() as TimeRecord);
            callback(records);
            setLocal('timeRecords', records);
        }, (error) => {
            console.warn("Erro na sincronização de registros (Offline ativado):", error.message);
            goOffline();
            // Garante que o callback tenha dados locais caso o snapshot falhe
            if (!cached || cached.length === 0) callback(getLocal('timeRecords'));
        });
    } else {
        if (cached) callback(cached);
        return () => {};
    }
  },

  subscribeToHolidays(callback: (data: Holiday[]) => void): () => void {
    // 1. CACHE-FIRST
    const cached = getLocal('holidays');
    if (cached && cached.length > 0) {
        callback(cached);
    }

    if (db && !isPaused) {
        return onSnapshot(collection(db, "holidays"), (snapshot) => {
            const holidays = snapshot.docs.map(doc => doc.data() as Holiday);

            // SEED AUTOMÁTICO DE FERIADOS
            if (holidays.length === 0 && (!cached || cached.length === 0)) {
                this.seedInitialHolidays();
            } else if (holidays.length > 0) {
                callback(holidays);
                setLocal('holidays', holidays);
            }
        }, (error) => {
             console.warn("Erro sync feriados (Offline ativado):", error.message);
             goOffline();
             if (!cached || cached.length === 0) {
                 this.seedInitialHolidays().then(seeded => callback(seeded));
             } else {
                 callback(getLocal('holidays'));
             }
        });
    } else {
        if (!cached || cached.length === 0) {
            this.seedInitialHolidays().then(seeded => callback(seeded));
        } else {
            callback(cached);
        }
        return () => {};
    }
  },

  // --- MÉTODOS DE ESCRITA ---

  async getEmployees(): Promise<Employee[]> {
    // Tenta ler do cache primeiro para velocidade
    const cached = getLocal('employees');
    if(db && !isPaused) {
        try {
            const snap = await getDocs(collection(db, "employees"));
            const data = snap.docs.map(d => d.data() as Employee);
            setLocal('employees', data); // Atualiza cache
            return data;
        } catch (e) {
            console.warn("Falha ao buscar funcionários online, retornando cache.");
            goOffline();
            return cached;
        }
    }
    return cached;
