      const records = getLocal('timeRecords') as TimeRecord[];
      setLocal('timeRecords', records.filter(r => r.employeeId !== employeeId));

      // 2. Nuvem
      if (db && !isPaused) {
          try {
              const q = query(collection(db, "timeRecords")); 
              const snapshot = await getDocs(q);
              const batchDelete = snapshot.docs.filter(d => d.data().employeeId === employeeId);
              batchDelete.forEach(async (d) => {
                  await deleteDoc(doc(db, "timeRecords", d.id));
              });
          } catch (e) {
