import React, { useState, useRef } from 'react';
import { X, Calendar, FileText, Save, Upload, AlertCircle, FileCheck } from 'lucide-react';

interface JustificationModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (date: string, reason: string, file: { name: string, base64: string } | null, note: string) => void;
}

export const JustificationModal: React.FC<JustificationModalProps> = ({ isOpen, onClose, onSave }) => {
  const [date, setDate] = useState('');
  const [reason, setReason] = useState('Doença / Atestado Médico');
  const [note, setNote] = useState('');
  const [selectedFile, setSelectedFile] = useState<{ name: string, base64: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  if (!isOpen) return null;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) { // 2MB limit check logic mostly for UX
        alert("O arquivo é muito grande. Tente uma imagem menor que 2MB.");
        return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        setSelectedFile({
            name: file.name,
            base64: base64String
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!date || !reason) return;

    onSave(date, reason, selectedFile, note);

    // Reset form
    setDate('');
    setReason('Doença / Atestado Médico');
    setNote('');
    setSelectedFile(null);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-fadeIn">
      <div className="bg-white rounded-2xl shadow-xl w-full max-w-md overflow-hidden transform transition-all scale-100">
        <div className="bg-indigo-900 p-4 flex justify-between items-center text-white">
          <h3 className="font-bold text-lg flex items-center gap-2">
            <FileCheck className="w-5 h-5" />
            Justificar Ausência
          </h3>
          <button 
            onClick={onClose}
            className="text-indigo-200 hover:text-white transition-colors p-1 rounded-full hover:bg-indigo-800"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div className="bg-amber-50 border border-amber-200 rounded-lg p-3 flex gap-2 items-start text-xs text-amber-800">
             <AlertCircle className="w-4 h-4 mt-0.5 shrink-0" />
             <p>Use este formulário para enviar atestados médicos ou justificar faltas. O dia será marcado como "Justificado" e o saldo de horas será ajustado.</p>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Data da Ausência</label>
            <div className="relative">
              <Calendar className="absolute top-2.5 left-3 w-5 h-5 text-slate-400 pointer-events-none" />
              <input
                type="date"
                required
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className="w-full pl-10 pr-3 py-2 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-slate-900"
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Motivo</label>
            <div className="relative">
              <select
                value={reason}
                onChange={(e) => setReason(e.target.value)}
                className="w-full px-3 py-2 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-slate-900 appearance-none"
              >
                  <option value="Doença / Atestado Médico">Doença / Atestado Médico</option>
                  <option value="Consulta Médica">Consulta Médica</option>
                  <option value="Problemas Pessoais">Problemas Pessoais</option>
                  <option value="Transporte/Trânsito">Problemas com Transporte</option>
                  <option value="Outros">Outros</option>
              </select>
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Anexar Atestado (Foto/PDF)</label>
            <input 
                type="file" 
                accept="image/*,application/pdf"
                ref={fileInputRef}
                onChange={handleFileChange}
                className="hidden"
            />
            <button
                type="button"
                onClick={() => fileInputRef.current?.click()}
                className={`w-full py-3 px-4 border-2 border-dashed rounded-xl flex items-center justify-center gap-2 transition-colors ${
                    selectedFile 
                    ? 'border-emerald-300 bg-emerald-50 text-emerald-700' 
                    : 'border-slate-300 bg-slate-50 text-slate-500 hover:bg-slate-100 hover:border-indigo-300 hover:text-indigo-600'
