  doc.text("Horas Extras", 62, 44);
  doc.text("Valor Estimado (R$)", 104, 44);
  doc.text("Saldo de Banco", 156, 44);

  // Summary Values
  doc.setFontSize(12);
  doc.setFont("helvetica", "bold");

  // 1. Worked
  doc.setTextColor(30, 58, 138); // Indigo-800
  doc.text(`${totalWorked.toFixed(2)}h`, 20, 52);

  // 2. Overtime
  doc.setTextColor(21, 128, 61); // Green-700
  doc.text(`${totalOvertime.toFixed(2)}h`, 62, 52);

  // 3. Earnings (New)
  doc.setTextColor(5, 150, 105); // Emerald-600
  doc.text(`R$ ${totalEarnings.toFixed(2)}`, 104, 52);

  // 4. Balance
  if (totalBalance >= 0) doc.setTextColor(37, 99, 235); // Blue-600
  else doc.setTextColor(220, 38, 38); // Red-600
  doc.text(`${totalBalance > 0 ? '+' : ''}${totalBalance.toFixed(2)}h`, 156, 52);

  // Table
  const tableColumn = ["Data", "Entrada", "Saída", "Total", "Extras", "Valor", "Saldo", "Obs"];
  const tableRows = records.map(r => [
    formatDate(r.date),
    formatTime(r.startTime),
    formatTime(r.endTime),
    `${r.totalHours.toFixed(2)}h`,
    r.overtimeHours > 0 ? `+${r.overtimeHours.toFixed(2)}h` : '-',
    (r.estimatedEarnings && r.estimatedEarnings > 0) ? `R$ ${r.estimatedEarnings.toFixed(2)}` : '-',
    `${r.balanceHours > 0 ? '+' : ''}${r.balanceHours.toFixed(2)}h`,
    r.notes || ''
  ]);

  autoTable(doc, {
    head: [tableColumn],
    body: tableRows,
    startY: 68,
    theme: 'grid',
    headStyles: { 
        fillColor: [79, 70, 229], // Indigo 600
        halign: 'center'
    },
    styles: { 
        fontSize: 8, 
        cellPadding: 2,
        halign: 'center'
    },
    columnStyles: {
      0: { cellWidth: 20 }, // Data
      7: { cellWidth: 'auto', halign: 'left' } // Obs
    }
  });

  doc.save(`folha_ponto_${new Date().toISOString().split('T')[0]}.pdf`);
};

export const downloadJSONBackup = (data: any) => {
  const jsonString = JSON.stringify(data, null, 2);
  const blob = new Blob([jsonString], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.setAttribute('href', url);
  link.setAttribute('download', `backup_sistema_${new Date().toISOString().split('T')[0]}.json`);
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

export const shareBackup = async (data: any) => {
    const fileName = `backup_ponto_${new Date().toISOString().split('T')[0]}.json`;
    const jsonString = JSON.stringify(data, null, 2);
    const file = new File([jsonString], fileName, { type: 'application/json' });

    // Verifica se o navegador suporta compartilhamento de arquivos
    if (navigator.canShare && navigator.canShare({ files: [file] })) {
        try {
            await navigator.share({
                files: [file],
                title: 'Backup Ponto Fácil',
                text: 'Segue o backup do banco de dados do sistema Ponto Fácil AI.'
            });
        } catch (error) {
            // Usuário cancelou ou erro na API
            console.log('Compartilhamento cancelado ou falhou', error);
        }
    } else {
        // Fallback: Baixa o arquivo e avisa
        downloadJSONBackup(data);
        alert("Seu dispositivo não suporta compartilhamento direto de arquivos. O backup foi baixado. Por favor, anexe-o manualmente no WhatsApp.");
    }
};

