  onClose: () => void;
}

export const CloudConfigModal: React.FC<CloudConfigModalProps> = ({ isOpen, onClose }) => {
  const [importStatus, setImportStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const fileInputRef = useRef<HTMLInputElement>(null);

  if (!isOpen) return null;

  const handleDownloadBackup = async () => {
      const data = await dataService.getFullBackupData();
      downloadJSONBackup(data);
  };

  const handleShareBackup = async () => {
      const data = await dataService.getFullBackupData();
      shareBackup(data);
  };

  const handleImportBackup = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      processBackupFile(file);
  };

  const processBackupFile = (file: File) => {
      const reader = new FileReader();
      reader.onload = async (event) => {
          try {
              const json = JSON.parse(event.target?.result as string);
              const success = await dataService.importDatabase(json);
              if (success) {
                  setImportStatus('success');
                  setTimeout(() => {
                      alert("Dados importados com sucesso! O sistema será recarregado.");
                      window.location.reload();
                  }, 500);
              } else {
                  setImportStatus('error');
              }
          } catch (err) {
              setImportStatus('error');
              console.error(err);
          }
      };
      reader.readAsText(file);
  }

