import React, { useState, useEffect } from 'react';
import { Play, Pause, Square, Coffee } from 'lucide-react';
import { RecordType, TimeRecord } from '../types';

interface TimeClockProps {
  currentRecord: TimeRecord | null;
  onPunch: (type: RecordType) => void;
}

export const TimeClock: React.FC<TimeClockProps> = ({ currentRecord, onPunch }) => {
  const [currentTime, setCurrentTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const getButtonConfig = () => {
    if (!currentRecord) {
      return {
        label: 'Iniciar Jornada',
        icon: <Play className="w-5 h-5 md:w-6 md:h-6 mr-2" />,
        action: () => onPunch(RecordType.ENTRY),
        color: 'bg-emerald-600 hover:bg-emerald-700',
        disabled: false
      };
    }

    if (currentRecord.startTime && !currentRecord.lunchStartTime) {
      return {
        label: 'Sair para Almoço',
        icon: <Coffee className="w-5 h-5 md:w-6 md:h-6 mr-2" />,
        action: () => onPunch(RecordType.LUNCH_START),
        color: 'bg-amber-500 hover:bg-amber-600',
        disabled: false
      };
    }

    if (currentRecord.lunchStartTime && !currentRecord.lunchEndTime) {
      return {
        label: 'Voltar do Almoço',
        icon: <Play className="w-5 h-5 md:w-6 md:h-6 mr-2" />,
        action: () => onPunch(RecordType.LUNCH_END),
        color: 'bg-emerald-600 hover:bg-emerald-700',
        disabled: false
      };
    }

    if (currentRecord.lunchEndTime && !currentRecord.endTime) {
      return {
        label: 'Encerrar Dia',
        icon: <Square className="w-5 h-5 md:w-6 md:h-6 mr-2" />,
        action: () => onPunch(RecordType.EXIT),
        color: 'bg-rose-600 hover:bg-rose-700',
        disabled: false
      };
    }

    return {
      label: 'Jornada Concluída',
      icon: <Square className="w-5 h-5 md:w-6 md:h-6 mr-2" />,
      action: () => {},
      color: 'bg-slate-400 cursor-not-allowed',
      disabled: true
    };
  };

  const btn = getButtonConfig();

  return (
    <div className="bg-white p-5 md:p-8 rounded-2xl shadow-sm border border-slate-100 flex flex-col items-center justify-center space-y-4 md:space-y-6">
      <div className="text-center">
        <h2 className="text-slate-500 font-medium text-xs md:text-lg uppercase tracking-wider mb-1">Hora Atual</h2>
        <div className="text-4xl md:text-5xl font-bold text-indigo-900 tabular-nums">
          {currentTime.toLocaleTimeString('pt-BR')}
        </div>
        <p className="text-indigo-600 font-medium mt-1 md:mt-2 text-sm md:text-base">
          {currentTime.toLocaleDateString('pt-BR', { weekday: 'long', day: 'numeric', month: 'long' })}
        </p>
      </div>

      <button
        onClick={btn.action}
        disabled={btn.disabled}
        className={`${btn.color} text-white font-bold py-3 px-6 md:py-4 md:px-8 rounded-full shadow-lg transform transition-all active:scale-95 flex items-center justify-center min-w-[200px] md:min-w-[240px] text-sm md:text-base`}
      >
        {btn.icon}
        {btn.label}
      </button>

      <div className="grid grid-cols-2 gap-3 md:gap-4 w-full mt-2 text-sm text-slate-600">
        <div className="bg-slate-50 p-2 md:p-3 rounded-lg text-center border border-slate-200">
          <span className="block text-[10px] md:text-xs font-bold text-slate-400 uppercase">Entrada</span>
          <span className="font-mono text-base md:text-lg text-slate-900">
            {currentRecord?.startTime ? new Date(currentRecord.startTime).toLocaleTimeString('pt-BR', {hour: '2-digit', minute:'2-digit'}) : '--:--'}
          </span>
        </div>
        <div className="bg-slate-50 p-2 md:p-3 rounded-lg text-center border border-slate-200">
          <span className="block text-[10px] md:text-xs font-bold text-slate-400 uppercase">Saída</span>
          <span className="font-mono text-base md:text-lg text-slate-900">
            {currentRecord?.endTime ? new Date(currentRecord.endTime).toLocaleTimeString('pt-BR', {hour: '2-digit', minute:'2-digit'}) : '--:--'}
          </span>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
