                <span className="flex items-center gap-1 text-xs font-semibold text-slate-400 bg-slate-50 px-2 rounded-full border border-slate-100">
                    <AlertTriangle className="w-3 h-3" />
                    Limite Alerta: {dailyLimit}h
                </span>
            </div>
        )}
