              <th className="px-3 py-3 md:px-4 md:py-4 text-center bg-indigo-50/50">Total</th>
              <th className="px-3 py-3 md:px-4 md:py-4 text-center text-emerald-700">Extras</th>
              {!compact && <th className="px-3 py-3 md:px-4 md:py-4 text-center text-emerald-700 bg-emerald-50/30">Valor (R$)</th>}
              <th className="px-3 py-3 md:px-4 md:py-4 text-center">Saldo</th>
