import React, { useState, useEffect } from 'react';
import { Play, Pause, Square, Coffee } from 'lucide-react';
import { RecordType, TimeRecord } from '../types';

interface TimeClockProps {
  currentRecord: TimeRecord | null;
  onPunch: (type: RecordType) => void;
}

export const TimeClock: React.FC<TimeClockProps> = ({ currentRecord, onPunch }) => {
  const [currentTime, setCurrentTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const getButtonConfig = () => {
    if (!currentRecord) {
      return {
        label: 'Iniciar Jornada',
        icon: <Play className="w-4 h-4 md:w-6 md:h-6 mr-2" />,
        action: () => onPunch(RecordType.ENTRY),
        color: 'bg-emerald-600 hover:bg-emerald-700',
        disabled: false
      };
    }

    if (currentRecord.startTime && !currentRecord.lunchStartTime) {
      return {
        label: 'Sair p/ Almoço',
        icon: <Coffee className="w-4 h-4 md:w-6 md:h-6 mr-2" />,
        action: () => onPunch(RecordType.LUNCH_START),
        color: 'bg-amber-500 hover:bg-amber-600',
        disabled: false
      };
    }

    if (currentRecord.lunchStartTime && !currentRecord.lunchEndTime) {
      return {
        label: 'Voltar Almoço',
        icon: <Play className="w-4 h-4 md:w-6 md:h-6 mr-2" />,
        action: () => onPunch(RecordType.LUNCH_END),
        color: 'bg-emerald-600 hover:bg-emerald-700',
        disabled: false
      };
    }

    if (currentRecord.lunchEndTime && !currentRecord.endTime) {
      return {
        label: 'Encerrar Dia',
        icon: <Square className="w-4 h-4 md:w-6 md:h-6 mr-2" />,
        action: () => onPunch(RecordType.EXIT),
        color: 'bg-rose-600 hover:bg-rose-700',
        disabled: false
      };
    }

    return {
      label: 'Concluído',
      icon: <Square className="w-4 h-4 md:w-6 md:h-6 mr-2" />,
      action: () => {},
      color: 'bg-slate-400 cursor-not-allowed',
      disabled: true
    };
  };

  const btn = getButtonConfig();

  return (
    <div className="bg-white p-4 md:p-8 rounded-2xl shadow-sm border border-slate-100 flex flex-col items-center justify-center space-y-3 md:space-y-6">
      <div className="text-center">
        <h2 className="text-slate-400 font-medium text-[10px] md:text-lg uppercase tracking-wider mb-0.5 md:mb-1">Hora Atual</h2>
        <div className="text-3xl md:text-5xl font-bold text-indigo-900 tabular-nums tracking-tight">
          {currentTime.toLocaleTimeString('pt-BR')}
        </div>
        <p className="text-indigo-600 font-medium mt-1 md:mt-2 text-xs md:text-base">
          {currentTime.toLocaleDateString('pt-BR', { weekday: 'long', day: 'numeric', month: 'long' })}
        </p>
      </div>

      <button
        onClick={btn.action}
        disabled={btn.disabled}
        className={`${btn.color} text-white font-bold py-2.5 px-6 md:py-4 md:px-8 rounded-full shadow-lg transform transition-all active:scale-95 flex items-center justify-center min-w-[180px] md:min-w-[240px] text-sm md:text-base`}
      >
        {btn.icon}
        {btn.label}
      </button>

      <div className="grid grid-cols-2 gap-2 md:gap-4 w-full mt-1 text-sm text-slate-600">
        <div className="bg-slate-50 p-2 md:p-3 rounded-lg text-center border border-slate-200">
          <span className="block text-[10px] md:text-xs font-bold text-slate-400 uppercase">Entrada</span>
          <span className="font-mono text-sm md:text-lg text-slate-900">
            {currentRecord?.startTime ? new Date(currentRecord.startTime).toLocaleTimeString('pt-BR', {hour: '2-digit', minute:'2-digit'}) : '--:--'}
          </span>
        </div>
        <div className="bg-slate-50 p-2 md:p-3 rounded-lg text-center border border-slate-200">
          <span className="block text-[10px] md:text-xs font-bold text-slate-400 uppercase">Saída</span>
          <span className="font-mono text-sm md:text-lg text-slate-900">
            {currentRecord?.endTime ? new Date(currentRecord.endTime).toLocaleTimeString('pt-BR', {hour: '2-digit', minute:'2-digit'}) : '--:--'}
          </span>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { TimeRecord } from '../types';
import { CheckCircle, AlertCircle, Clock, Check, X, CircleDashed, FileText, AlertTriangle, Paperclip, Stethoscope } from 'lucide-react';

interface TimeHistoryProps {
  records: TimeRecord[];
  onUpdateNote: (id: string, note: string) => void;
  onToggleApproval: (id: string) => void;
  compact?: boolean;
  dailyLimit?: number;
}

export const TimeHistory: React.FC<TimeHistoryProps> = ({ 
  records, 
  onUpdateNote, 
  onToggleApproval,
  compact = false,
  dailyLimit = 10 // Default visual limit if not provided
}) => {

  const formatTime = (isoString: string | null) => {
    if (!isoString) return '-';
    return new Date(isoString).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
  };

  const formatDate = (isoDate: string) => {
    const [year, month, day] = isoDate.split('-');
    return `${day}/${month}`;
  };

  const openAttachment = (base64: string) => {
      const win = window.open();
      if (win) {
          win.document.write(`<iframe src="${base64}" frameborder="0" style="border:0; top:0px; left:0px; bottom:0px; right:0px; width:100%; height:100%;" allowfullscreen></iframe>`);
      }
  };

  // Calculate Totals (excluding justified absences from worked hours but handling them in context)
  const totalWorked = records.reduce((acc, curr) => acc + curr.totalHours, 0);
  const totalOvertime = records.reduce((acc, curr) => acc + (curr.overtimeHours || 0), 0);
  const totalBalance = records.reduce((acc, curr) => acc + (curr.balanceHours || 0), 0);
  const totalEarnings = records.reduce((acc, curr) => acc + (curr.estimatedEarnings || 0), 0);

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col animate-fadeInUp">
      <div className="p-3 md:p-6 border-b border-slate-100 flex justify-between items-center bg-white">
        <h3 className="text-sm md:text-lg font-bold text-slate-800 flex items-center gap-2">
          <Clock className="w-4 h-4 md:w-5 md:h-5 text-indigo-600" />
          {compact ? 'Resumo' : 'Folha de Ponto'}
        </h3>
        {!compact && (
            <div className="hidden sm:flex text-sm text-slate-500 gap-4">
                <span>Meta: 8h</span>
                <span className="flex items-center gap-1 text-xs font-semibold text-slate-400 bg-slate-50 px-2 rounded-full border border-slate-100">
                    <AlertTriangle className="w-3 h-3" />
                    Limite: {dailyLimit}h
                </span>
            </div>
        )}
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] md:text-xs font-semibold">
            <tr>
              <th className="px-2 py-2 md:px-4 md:py-4 min-w-[50px] md:min-w-[80px]">Data</th>
              <th className="px-2 py-2 md:px-4 md:py-4 text-center">Ent.</th>
              {!compact && <th className="px-2 py-2 md:px-4 md:py-4 text-center">Int.</th>}
              <th className="px-2 py-2 md:px-4 md:py-4 text-center">Sai.</th>
              <th className="px-2 py-2 md:px-4 md:py-4 text-center bg-indigo-50/50">Tot.</th>
              <th className="px-2 py-2 md:px-4 md:py-4 text-center text-emerald-700">Ext.</th>
              {!compact && <th className="px-2 py-2 md:px-4 md:py-4 text-center text-emerald-700 bg-emerald-50/30">R$</th>}
              <th className="px-2 py-2 md:px-4 md:py-4 text-center">Saldo</th>
              {!compact && (
                <>
                  <th className="px-2 py-2 md:px-4 md:py-4 min-w-[150px]">Obs.</th>
                  <th className="px-2 py-2 md:px-4 md:py-4 text-center min-w-[80px]">Apr.</th>
                </>
              )}
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {records.length === 0 ? (
              <tr>
                <td colSpan={compact ? 6 : 10} className="px-4 py-6 text-center text-slate-500 text-xs md:text-base animate-fadeInUp">
                  Sem registros.
                </td>
              </tr>
            ) : (
              records.map((record, index) => {
                const isLimitExceeded = record.totalHours > dailyLimit;
                const isJustified = record.status === 'JUSTIFICADO';

                return (
                <tr 
                    key={record.id} 
                    className={`hover:bg-slate-50 transition-colors group animate-fadeInUp opacity-0 ${isJustified ? 'bg-indigo-50/30' : ''}`}
                    style={{ animationDelay: `${index * 50}ms` }} // Staggered delay logic
                >
                  {/* Date */}
                  <td className="px-2 py-2 md:px-4 md:py-4 font-medium text-slate-900">
                    <div className="flex flex-col leading-tight">
                        <span className="text-xs md:text-base">{formatDate(record.date)}</span>
                        {!compact && <span className="text-[9px] md:text-[10px] text-slate-400 font-normal uppercase">{new Date(record.date).toLocaleDateString('pt-BR', {weekday: 'short'})}</span>}
                    </div>
                  </td>

                  {/* LOGICA DE EXIBIÇÃO: SE FOR JUSTIFICADO, MESCLA AS COLUNAS DE TEMPO */}
                  {isJustified ? (
                      <td colSpan={!compact ? 3 : 2} className="px-2 py-2 md:px-4 md:py-4 text-center">
                          <div className="flex items-center justify-center gap-1 md:gap-2 text-indigo-600 bg-indigo-50 py-1 rounded md:rounded-lg border border-indigo-100">
                              <Stethoscope className="w-3 h-3 md:w-4 md:h-4" />
                              <span className="text-[9px] md:text-xs font-bold uppercase tracking-wide truncate max-w-[60px] md:max-w-none">{record.justificationReason || 'Atestado'}</span>
                              {record.attachmentBase64 && (
                                  <button 
                                    onClick={() => openAttachment(record.attachmentBase64!)}
                                    className="ml-1 flex items-center gap-0.5 text-[9px] bg-white border border-indigo-200 px-1 py-0.5 rounded shadow-sm hover:text-indigo-800"
                                    title="Ver Atestado"
                                  >
                                      <Paperclip className="w-2.5 h-2.5 md:w-3 md:h-3" />
                                      <span className="hidden md:inline">Anexo</span>
                                  </button>
                              )}
                          </div>
                      </td>
                  ) : (
                      /* Renderização Normal de Horários */
                      <>
                        <td className="px-2 py-2 md:px-4 md:py-4 text-center text-slate-700 font-mono text-xs md:text-sm">{formatTime(record.startTime)}</td>
                        {!compact && (
                            <td className="px-2 py-2 md:px-4 md:py-4 text-center text-slate-500 text-[10px] md:text-xs">
                                {record.lunchStartTime && record.lunchEndTime ? (
                                    <span className="bg-slate-100 px-1 py-0.5 rounded">
                                        {formatTime(record.lunchStartTime)}-{formatTime(record.lunchEndTime)}
                                    </span>
                                ) : '-'}
                            </td>
                        )}
                        <td className="px-2 py-2 md:px-4 md:py-4 text-center text-slate-700 font-mono text-xs md:text-sm">{formatTime(record.endTime)}</td>
                      </>
                  )}

                  {/* Calculated Hours */}
                  <td className="px-2 py-2 md:px-4 md:py-4 text-center font-bold text-slate-800 bg-indigo-50/30 relative group/cell">
                    <div className="flex items-center justify-center gap-0.5 md:gap-1 text-xs md:text-base">
                        {isJustified ? (
                           <span className="text-slate-400 font-normal">-</span>
                        ) : (
                           record.totalHours > 0 ? `${record.totalHours.toFixed(2)}h` : '-'
                        )}

                        {!isJustified && isLimitExceeded && (
                            <AlertCircle className="w-3 h-3 md:w-4 md:h-4 text-red-500 animate-pulse" />
                        )}
                    </div>
                  </td>

                  {/* Overtime */}
                  <td className="px-2 py-2 md:px-4 md:py-4 text-center font-medium">
                    {record.overtimeHours > 0 ? (
                        <div className="flex items-center justify-center">
                            <span className="text-emerald-600 bg-emerald-50 px-1 py-0.5 md:px-2 md:py-1 rounded border border-emerald-100 flex items-center gap-0.5 text-[10px] md:text-sm">
                                +{record.overtimeHours.toFixed(2)}
                            </span>
                        </div>
                    ) : '-'}
                  </td>

                  {/* Earnings Value */}
                  {!compact && (
                      <td className="px-2 py-2 md:px-4 md:py-4 text-center font-bold text-emerald-700 bg-emerald-50/30 text-[10px] md:text-sm">
                        {record.estimatedEarnings && record.estimatedEarnings > 0 
                            ? `R$${record.estimatedEarnings.toFixed(2)}` 
                            : '-'}
                      </td>
                  )}

                  {/* Balance */}
                  <td className="px-2 py-2 md:px-4 md:py-4 text-center font-medium">
                    {isJustified ? (
                        <span className="text-slate-400 text-[9px] md:text-xs">Abon.</span>
                    ) : (
                        record.balanceHours !== 0 ? (
                            <span className={`${record.balanceHours > 0 ? 'text-blue-600' : 'text-red-500'} text-[10px] md:text-sm`}>
                                {record.balanceHours > 0 ? '+' : ''}{record.balanceHours.toFixed(2)}
                            </span>
                        ) : '-'
                    )}
                  </td>

                  {/* Extended Controls */}
                  {!compact && (
                    <>
                        {/* Observations Input */}
                        <td className="px-2 py-2 md:px-4 md:py-3">
                             <textarea 
                                className="w-full bg-white border border-slate-200 rounded py-1 px-1 text-[10px] md:text-xs text-slate-800 focus:ring-1 focus:ring-indigo-500 min-h-[28px] resize-none"
                                placeholder="..."
                                rows={1}
                                value={record.notes || ''}
                                onChange={(e) => onUpdateNote(record.id, e.target.value)}
                            />
                        </td>

                        {/* Approval Manager */}
                        <td className="px-2 py-2 md:px-4 md:py-4 text-center">
                            {record.overtimeHours > 0 ? (
                                <button 
                                    onClick={() => onToggleApproval(record.id)}
                                    className={`inline-flex items-center justify-center p-1 md:px-3 md:py-1.5 rounded-full text-[9px] md:text-xs font-semibold border transition-all ${
                                        record.isOvertimeApproved === true 
                                            ? 'bg-green-100 text-green-700 border-green-200' 
                                        : record.isOvertimeApproved === false
                                            ? 'bg-red-50 text-red-700 border-red-200'
                                        : 'bg-amber-50 text-amber-700 border-amber-200'
                                    }`}
                                >
                                    {record.isOvertimeApproved === true ? <Check className="w-3 h-3" /> : 
                                     record.isOvertimeApproved === false ? <X className="w-3 h-3" /> : <CircleDashed className="w-3 h-3" />}
                                    <span className="hidden md:inline ml-1">
                                        {record.isOvertimeApproved === true ? 'Aprovado' : 
                                         record.isOvertimeApproved === false ? 'Rejeitado' : 'Pendente'}
                                    </span>
                                </button>
                            ) : '-'}
                        </td>
                    </>
                  )}
                </tr>
              )})}
            )}
          </tbody>

          {/* Footer Totals */}
          {!compact && records.length > 0 && (
              <tfoot className="bg-slate-50 font-bold text-slate-700 border-t-2 border-slate-200 animate-fadeInUp opacity-0" style={{ animationDelay: '300ms' }}>
                  <tr>
                      <td colSpan={4} className="px-2 py-2 md:px-4 md:py-4 text-right text-[10px] md:text-xs uppercase tracking-wide text-slate-500">Totais:</td>
                      <td className="px-2 py-2 md:px-4 md:py-4 text-center bg-indigo-100/50 text-indigo-900 text-[10px] md:text-sm">{totalWorked.toFixed(2)}</td>
                      <td className="px-2 py-2 md:px-4 md:py-4 text-center text-emerald-700 text-[10px] md:text-sm">
                         +{totalOvertime.toFixed(2)}
                      </td>
                      <td className="px-2 py-2 md:px-4 md:py-4 text-center bg-emerald-100/50 text-emerald-800 text-[10px] md:text-sm">R${totalEarnings.toFixed(2)}</td>
                      <td className={`px-2 py-2 md:px-4 md:py-4 text-center ${totalBalance >= 0 ? 'text-blue-700' : 'text-red-600'} text-[10px] md:text-sm`}>
                        {totalBalance > 0 ? '+' : ''}{totalBalance.toFixed(2)}
                      </td>
                      <td colSpan={2} className="hidden md:table-cell px-4 py-4 text-left text-xs text-slate-400 font-normal">
                      </td>
                  </tr>
              </tfoot>
          )}
        </table>
      </div>
    </div>
  );
};

