interface LoginProps {
  onLogin: (username: string, pass: string) => void;
  error?: string | null;
}

export const Login: React.FC<LoginProps> = ({ onLogin, error }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');

