        <h2 className="text-lg md:text-2xl font-bold text-slate-800 mb-4 md:mb-6 text-center">Acesso ao Sistema</h2>

        <form onSubmit={handleSubmit} className="space-y-3 md:space-y-4">
          <div>
            <label className="block text-xs md:text-sm font-medium text-slate-700 mb-1">Usuário</label>
            <div className="relative">
              <User className="absolute top-2.5 left-3 w-4 h-4 md:w-5 md:h-5 text-slate-400 pointer-events-none" />
              <input
                type="text"
                required
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                className="w-full pl-9 md:pl-10 pr-3 py-2 md:py-2.5 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-colors text-sm"
                placeholder="Seu usuário"
              />
            </div>
          </div>

          <div>
            <label className="block text-xs md:text-sm font-medium text-slate-700 mb-1">Senha</label>
            <div className="relative">
              <Lock className="absolute top-2.5 left-3 w-4 h-4 md:w-5 md:h-5 text-slate-400 pointer-events-none" />
              <input
                type="password"
                required
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full pl-9 md:pl-10 pr-3 py-2 md:py-2.5 bg-slate-50 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-colors text-sm"
                placeholder="Sua senha"
              />
            </div>
          </div>

          {error && (
            <div className="text-red-500 text-xs md:text-sm text-center font-medium bg-red-50 py-2 rounded-lg">
              {error}
            </div>
          )}

          <button
            type="submit"
            className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-2.5 md:py-3 rounded-lg shadow-lg shadow-indigo-200 transition-all active:scale-95 mt-2 text-sm md:text-base"
          >
            Entrar
            <ArrowRight className="w-4 h-4 md:w-5 md:h-5" />
          </button>
        </form>

        <p className="text-center text-[10px] md:text-xs text-slate-400 mt-4 md:mt-6">
          © {new Date().getFullYear()} PontoFácil System AI
        </p>
      </div>
    </div>
  );
};

